INSERT INTO articles (subject_code, title, content_text, word_count, difficulty_level, target_exam, questions)
VALUES
  ('turkce', 'Paragrafta Yapı ve Anlam', $$Bir paragraf, tek bir ana düşünce etrafında kurulmuş cümleler topluluğudur. Paragrafın ilk cümlesi çoğunlukla konuyu tanıtan giriş cümlesidir. Ortadaki cümleler bu ana düşünceyi destekler, açıklar ya da örneklendirir. Son cümle ise genellikle sonuç veya özet niteliği taşır.

Ana fikir, paragrafın tümünü kapsayan en genel düşüncedir. Konu ise paragrafın "ne hakkında olduğu"nu kısaca belirtir. Bu ikisini birbirinden ayırt etmek, sınav sorularında sıklıkla test edilir.

Destekleyici cümleler, ana fikri kanıtlamak için somut bilgi, örnek ya da karşılaştırma sunar. İyi yazılmış bir paragrafta her cümle birbirine mantıksal bağlarla bağlıdır. "Çünkü, bu nedenle, ancak, oysa" gibi bağlaçlar bu mantıksal ilişkiyi kurar.

LGS ve TYT sınavlarında paragraf soruları, öğrencinin metnin bütününü kavrayıp kavramadığını ölçer. Bu tür sorularda dikkatli okuma ve cümlelerin birbirini nasıl desteklediğini anlamak büyük önem taşır.$$, 162, 5, '{lgs,tyt}', '[{"question":"Paragrafın ana fikri ile konusu arasındaki temel fark nedir?","options":["Ana fikir daha kısadır, konu daha uzundur","Konu paragrafın neyle ilgili olduğunu, ana fikir ise en genel düşünceyi verir","İkisi aynı anlama gelir, aralarında fark yoktur","Ana fikir yalnızca son cümlede yer alır"],"correctIndex":1},{"question":"Destekleyici cümlelerin görevi nedir?","options":["Paragrafın konusunu değiştirmek","Yeni bir ana fikir ortaya koymak","Ana fikri kanıtlamak, açıklamak veya örneklendirmek","Paragrafı sonlandırmak"],"correctIndex":2},{"question":"Bağlaçlar paragrafta ne işe yarar?","options":["Cümleleri daha uzun yapar","Cümleler arasındaki mantıksal ilişkiyi kurar","Okumayı zorlaştırır","Ana fikri gizler"],"correctIndex":1},{"question":"LGS ve TYT sınavlarında paragraf soruları neyi ölçer?","options":["Öğrencinin yazma hızını","Öğrencinin kelime sayısını bilip bilmediğini","Öğrencinin metnin bütününü kavrayıp kavramadığını","Öğrencinin bağlaç sayısını"],"correctIndex":2}]'::jsonb),
  ('turkce', 'Sözcükte Anlam: Eş, Zıt ve Mecaz Anlam', $$Türkçede her sözcüğün birden fazla anlam boyutu bulunabilir. Gerçek anlam, sözcüğün sözlükte kayıtlı olan temel anlamıdır. Mecaz anlam ise sözcüğün benzetme ya da çağrışım yoluyla kazandığı yan anlamdır. "Taş kalpli" ifadesinde "taş" sözcüğü mecaz anlamda kullanılmıştır.

Eş anlamlı sözcükler, yazılış ve söylenişleri farklı olsa da aynı ya da yakın anlamı karşılayan kelimelerdir. "Güzel" ile "hoş", "hızlı" ile "çabuk" bunlara örnek verilebilir. Zıt anlamlı sözcükler ise anlam bakımından birbirinin karşıtı olan kelimelerdir; "açık-kapalı", "iyi-kötü" gibi.

Bağlam içinde anlam da sınavlarda sıkça çıkan konular arasındadır. Aynı sözcük farklı cümlelerde farklı anlam taşıyabilir. "Ağır" sözcüğü bir cümlede "fazla kilolu", başka bir cümlede "zor" anlamında kullanılabilir.

Bu farklı anlam katmanlarını kavramak, hem okuma anlayışını geliştirir hem de sınav sorularında doğru seçeneği bulmayı kolaylaştırır.$$, 158, 5, '{lgs,tyt}', '[{"question":"\"Taş kalpli\" ifadesinde \"taş\" sözcüğü hangi anlamda kullanılmıştır?","options":["Gerçek anlam","Mecaz anlam","Eş anlam","Zıt anlam"],"correctIndex":1},{"question":"Eş anlamlı sözcüklerin temel özelliği nedir?","options":["Yazılışları aynıdır","Zıt anlamlar taşırlar","Farklı yazılıp söylenseler de aynı ya da yakın anlamı karşılarlar","Her zaman mecaz anlam taşırlar"],"correctIndex":2},{"question":"\"Açık-kapalı\" sözcükleri hangi anlam ilişkisine örnektir?","options":["Eş anlamlılık","Mecaz anlamlılık","Zıt anlamlılık","Gerçek anlamlılık"],"correctIndex":2},{"question":"\"Ağır\" sözcüğünün farklı cümlelerde farklı anlam taşıması hangi kavramı açıklar?","options":["Eş anlamlılık","Bağlam içinde anlam","Zıt anlamlılık","Gerçek anlam"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Cümle Türleri', $$Türkçede cümleler yapılarına göre üçe ayrılır: basit cümle, bileşik cümle ve sıralı cümle.

Basit cümle, içinde yalnızca bir yargı barındıran cümledir. Tek bir özne ve tek bir yüklemden oluşur. "Öğrenciler sınıfta çalışıyor." cümlesi buna iyi bir örnektir.

Bileşik cümle, bir temel cümle ile ona bağlı bir ya da birden fazla yan cümleden oluşur. "Hava soğuk olduğu için dışarı çıkmadık." cümlesinde "dışarı çıkmadık" temel cümle, "hava soğuk olduğu için" ise yan cümledir.

Sıralı cümle ise birden fazla temel yargının noktalı virgül ya da virgülle ayrılarak yan yana sıralanmasından oluşur. "Güneş battı; karanlık çöktü; yıldızlar belirdi." cümlesi buna örnektir.

Cümle türlerini doğru biçimde tanımak, özellikle yazma ve anlatım bilgisi sorularında başarıyı doğrudan etkiler. LGS ve TYT sınavlarında cümle türleriyle ilgili sorular düzenli olarak yer almaktadır.$$, 160, 5, '{lgs,tyt}', '[{"question":"\"Öğrenciler sınıfta çalışıyor.\" cümlesi hangi türdendir?","options":["Bileşik cümle","Sıralı cümle","Basit cümle","Eksiltili cümle"],"correctIndex":2},{"question":"Bileşik cümleyi basit cümleden ayıran temel özellik nedir?","options":["Daha uzun olması","Temel cümleye bağlı en az bir yan cümle içermesi","Yüklem içermemesi","Birden fazla özne içermesi"],"correctIndex":1},{"question":"\"Güneş battı; karanlık çöktü; yıldızlar belirdi.\" cümlesi hangi türdendir?","options":["Basit cümle","Bileşik cümle","Sıralı cümle","Devrik cümle"],"correctIndex":2},{"question":"Sıralı cümlede yargılar genellikle hangi işaret/bağlaçlarla ayrılır?","options":["Nokta ve soru işareti","Virgül ve noktalı virgül","Tırnak işareti","Ünlem işareti"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Ses Bilgisi: Ünlü Uyumları ve Ünsüz Yumuşaması', $$Türkçenin temel ses özelliklerinden biri ünlü uyumudur. Büyük ünlü uyumuna göre bir sözcükteki ünlüler ya hep kalın (a, ı, o, u) ya da hep ince (e, i, ö, ü) olmalıdır. "Kaplumbağa" sözcüğündeki tüm ünlüler kalındır ve bu kurala uymaktadır. Küçük ünlü uyumunda ise son hecedeki ünlüye göre ek alınır; düz ünlüden sonra düz, yuvarlak ünlüden sonra yuvarlak ek gelir.

Ünsüz yumuşaması ise sözcük sonundaki sert ünsüzlerin (ç, k, p, t) ünlüyle başlayan ek aldıklarında yumuşamasıdır. "Kitap" sözcüğü "kitabı" biçimini alır; burada "p" sesi "b"ye dönüşür.

Sınav sorularında bu kuralların istisnaları da sorulur. Tek heceli sözcükler ile yabancı kökenli sözcükler ünsüz yumuşamasına uğramayabilir. "Harp" sözcüğünde "p" yumuşamaz.

Bu kuralları kavramak, yazım yanlışlarını önler ve TYT Türkçe sorularında doğru biçim tercihini sağlar.$$, 155, 6, '{lgs,tyt}', '[{"question":"Büyük ünlü uyumuna göre bir sözcükteki ünlüler nasıl olmalıdır?","options":["Birbirinden farklı olmalıdır","Ya hep kalın ya da hep ince olmalıdır","Yalnızca kalın olmalıdır","Yalnızca ince olmalıdır"],"correctIndex":1},{"question":"\"Kitap\" sözcüğünün \"kitabı\" biçimini alması hangi ses olayını gösterir?","options":["Ünlü türemesi","Ünsüz yumuşaması","Ünlü daralması","Ünsüz benzeşmesi"],"correctIndex":1},{"question":"Ünsüz yumuşaması ne zaman gerçekleşir?","options":["Her zaman gerçekleşir","Sözcük sonundaki sert ünsüz ünlüyle başlayan ek aldığında","Sözcük başına ek getirildiğinde","Sözcük tek heceli olduğunda"],"correctIndex":1},{"question":"\"Harp\" sözcüğünde \"p\" sesi neden yumuşamaz?","options":["Sözcük kalın ünlü içerdiği için","Sözcük yabancı kökenli olduğu için","Sözcük fiil olduğu için","Sözcük çok heceli olduğu için"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Anlatım Bozuklukları', $$Anlatım bozukluğu, bir cümlede anlam karışıklığına, mantık hatasına ya da dil kurallarına aykırı kullanıma yol açan yanlışlıklar olarak tanımlanır. Bu bozukluklar yapı bakımından ya da anlam bakımından ortaya çıkabilir.

Yapı bakımından anlatım bozuklukları; eksik öge, gereksiz sözcük kullanımı, özne-yüklem uyumsuzluğu ve tamlama yanlışlıklarını kapsar. "Öğrenciler toplantıya katıldı ve konuşmalar yapıldı." cümlesinde özne belirsizliği vardır.

Anlam bakımından bozukluklar ise çelişkili ifadeler, anlam belirsizliği ve sözcüklerin yanlış anlamda kullanımı biçiminde görülür. "Herkes kendi fikirlerini birbirinden aldı." cümlesinde anlam çelişkisi bulunmaktadır.

TYT ve LGS sınavlarında anlatım bozukluğu soruları, verilen dört seçenek arasından hatalı ya da doğru cümleyi bulmayı gerektirir. Bu soruları çözebilmek için cümleyi dikkatle okuyup her ögenin görevini düşünmek gerekir.

Düzenli pratik yaparak anlatım bozukluklarını tanımak, sınavda yüksek puan almanın etkili yollarından biridir.$$, 163, 6, '{lgs,tyt}', '[{"question":"Anlatım bozukluğu hangi tür yanlışlıkları kapsar?","options":["Yalnızca yazım hatalarını","Anlam karışıklığı, mantık hatası veya dil kurallarına aykırı kullanımları","Yalnızca noktalama hatalarını","Yalnızca sözcük seçimi hatalarını"],"correctIndex":1},{"question":"\"Öğrenciler toplantıya katıldı ve konuşmalar yapıldı.\" cümlesindeki bozukluk nedir?","options":["Gereksiz sözcük kullanımı","Anlam çelişkisi","Özne belirsizliği","Yüklem eksikliği"],"correctIndex":2},{"question":"Anlam bakımından anlatım bozukluğuna hangi örnekler girer?","options":["Eksik öge ve tamlama yanlışlıkları","Çelişkili ifadeler, anlam belirsizliği ve sözcüklerin yanlış anlamda kullanımı","Özne-yüklem uyumsuzluğu","Gereksiz sözcük kullanımı"],"correctIndex":1},{"question":"Sınavlarda anlatım bozukluğu sorularında ne yapılmalıdır?","options":["En kısa cümle seçilmelidir","Cümle dikkatle okunup her ögenin görevi düşünülmelidir","Yalnızca yükleme bakılmalıdır","Sözcük sayısı hesaplanmalıdır"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Yazım Kuralları ve Noktalama', $$Türkçede doğru yazım, iletişimi kolaylaştırır ve anlamı kesinleştirir. Türk Dil Kurumu tarafından belirlenen yazım kuralları, sözcüklerin bitişik mi ayrı mı yazılacağını, büyük harf kullanımını ve noktalama işaretlerinin yerini düzenler.

Büyük harf kuralına göre cümle başları, özel isimler ve unvanlar büyük harfle başlar. "Atatürk" ve "Türkiye" gibi özel isimler her zaman büyük harfle yazılır.

Birleşik sözcüklerin yazımı ise sıkça karıştırılan konular arasındadır. "Başbakan" bitişik yazılırken "el ele" ayrı yazılır. Bu konuda kararlı bir kural yoktur; sözcük sözlükte nasıl geçiyorsa öyle yazılır.

Noktalama işaretlerinden nokta, cümle sonuna; virgül, yan cümleleri ve sıralı ögeleri birbirinden ayırmaya; soru işareti ise soru cümlelerinin sonuna gelir.

Sınav sorularında en çok karıştırılan noktalama işareti kesme işaretidir. Özel isimlere getirilen ekler kesme işaretiyle ayrılır: "Ankara'ya", "Atatürk'ün" gibi.$$, 157, 5, '{lgs,tyt}', '[{"question":"Türkçede büyük harf hangi durumlarda kullanılır?","options":["Yalnızca cümle başlarında","Cümle başları, özel isimler ve unvanlarda","Yalnızca özel isimlerde","Her sözcüğün başında"],"correctIndex":1},{"question":"\"Başbakan\" sözcüğünün doğru yazımı nedir?","options":["Baş Bakan","Baş-bakan","Başbakan","baş bakan"],"correctIndex":2},{"question":"Kesme işareti ne zaman kullanılır?","options":["Her sözcükten önce","Özel isimlere getirilen ekleri ayırmak için","Soru cümlelerinin sonunda","Yalnızca alıntılarda"],"correctIndex":1},{"question":"\"Ankara''ya\" yazımında kesme işareti hangi görevi üstlenir?","options":["Sözcüğü kısaltır","Özel isim olan \"Ankara\" ile eki ayırır","Cümleyi bitirir","Vurguyu gösterir"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Deyimler ve Atasözleri', $$Deyimler, en az iki sözcükten oluşan ve kalıplaşmış bir anlam taşıyan söz gruplarıdır. Deyimlerdeki sözcükler gerçek anlamını yitirmiş, mecaz bir anlam kazanmıştır. "Göz kulak olmak" deyimi "dikkatli biçimde bakmak ve korumak" anlamına gelir; burada göz ve kulak sözcükleri gerçek anlamda kullanılmamaktadır.

Atasözleri ise uzun deneyimlerin ürünü olan, toplumun ortak yaşam bilgeliğini yansıtan kısa ve öz kalıp sözlerdir. Atasözlerinde genellikle bir öğüt ya da evrensel bir gerçek dile getirilir. "Damlaya damlaya göl olur." atasözü, küçük şeylerin birikmesiyle büyük sonuçlara ulaşılabileceğini anlatır.

Deyim ile atasözü arasındaki temel fark şudur: Deyimler tam bir yargı bildirmez, atasözleri ise tam bir yargı içerir ve bağımsız kullanılabilir.

Sınav sorularında öğrencilerden deyim ile atasözünü birbirinden ayırt etmeleri, verilen bir ifadenin hangi anlama geldiğini bulmaları beklenir. Bu konuda pratik yapmak, söz varlığını zenginleştirmenin de etkili bir yoludur.$$, 161, 5, '{lgs,tyt}', '[{"question":"Deyimlerin temel özelliği nedir?","options":["Her zaman tek sözcükten oluşurlar","Kalıplaşmış ve mecaz anlam taşıyan söz gruplarıdır","Tam bir yargı bildirirler","Gerçek anlamda kullanılırlar"],"correctIndex":1},{"question":"\"Göz kulak olmak\" deyiminin anlamı nedir?","options":["Hem görmek hem duymak","Dikkatli biçimde bakmak ve korumak","Meraklı olmak","Gözetlemek"],"correctIndex":1},{"question":"Deyim ile atasözü arasındaki temel fark nedir?","options":["Deyimler daha uzundur","Atasözleri daha eskidir","Deyimler tam yargı bildirmez, atasözleri tam yargı içerir","Atasözleri mecaz anlam taşımaz"],"correctIndex":2},{"question":"\"Damlaya damlaya göl olur.\" atasözünün anlamı nedir?","options":["Su önemli bir kaynaktır","Küçük şeylerin birikmesiyle büyük sonuçlara ulaşılır","Göller yağmurla dolar","Sabırsız olmak gerekmez"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Şiir Türleri: Lirik, Epik ve Didaktik', $$Şiir, duygu ve düşüncelerin yoğun ve ahenkli bir biçimde dile getirildiği yazınsal türdür. Türk ve dünya edebiyatında şiirler, içeriklerine göre çeşitli türlere ayrılmaktadır.

Lirik şiir, aşk, özlem, hüzün gibi bireysel duyguları yoğun biçimde işler. Okuyucuda duygusal bir etki bırakmayı amaçlar. Ahmet Haşim'in şiirleri lirik şiire örnek gösterilebilir.

Epik şiir, savaş, kahramanlık ve destansı olayları anlatır. Okuyucuda yiğitlik ve coşku duygusu uyandırır. Köroğlu Destanı, Türk edebiyatındaki önemli epik örneklerden biridir.

Didaktik şiir ise bir öğreti ya da bilgi vermek amacıyla yazılır. Okuyucuya ahlaki, dini ya da felsefi bir ders aktarmayı hedefler. Yunus Emre'nin şiirleri didaktik özellikleriyle öne çıkar.

Sınavlarda şiir türünü belirlemek için şiirde işlenen tema ve duygu tonu dikkate alınmalıdır. Şiirin amacı ve okuyucuda yaratmak istediği etki, türü belirlemenin en güvenilir yoludur.$$, 159, 6, '{lgs,tyt}', '[{"question":"Lirik şiirin temel özelliği nedir?","options":["Savaş ve kahramanlık anlatır","Bilgi ve öğüt verir","Aşk, özlem, hüzün gibi bireysel duyguları işler","Toplumsal olayları eleştirir"],"correctIndex":2},{"question":"Epik şiirde hangi duygular ön plana çıkar?","options":["Hüzün ve özlem","Yiğitlik ve coşku","Aşk ve sevinç","Felsefi düşünceler"],"correctIndex":1},{"question":"Didaktik şiirin amacı nedir?","options":["Okuyucuyu eğlendirmek","Destan anlatmak","Ahlaki, dini ya da felsefi bir ders aktarmak","Bireysel duyguları dile getirmek"],"correctIndex":2},{"question":"Şiir türünü belirlemek için en güvenilir yöntem nedir?","options":["Şiirin uyak düzenine bakmak","Şiirin uzunluğuna bakmak","Şiirde işlenen tema, duygu tonu ve okuyucuda yaratılan etkiyi değerlendirmek","Şairin adını bilmek"],"correctIndex":2}]'::jsonb),
  ('turkce', 'Roman ve Hikâye: Olay Örgüsü, Kişi ve Zaman', $$Roman ve hikâye, anlatmaya dayalı yazınsal türlerin en önemlileridir. Her ikisinde de olay örgüsü, kişiler ve zaman unsurları temel yapı taşlarını oluşturur.

Olay örgüsü, eserdeki olayların belirli bir nedensellik çerçevesinde birbirine bağlanarak oluşturduğu zincirimsi yapıdır. Bu yapı genellikle serim, düğüm ve çözüm bölümlerinden oluşur.

Kişi unsuru, eserde yer alan karakterleri kapsar. Ana karakter, olayların merkezindeyken yan karakterler onu destekler ya da çatışmada karşısında durur. Karakterlerin psikolojik derinliği, eserin kalitesini belirleyen önemli etkenlerden biridir.

Zaman unsuru, olayların geçtiği dönem, günlük ve saatlik dilimler ile anlatının iç zamanını içerir. Romanlarda geriye dönüş (flashback) ve ileriye sıçrama (foreshadowing) teknikleri kullanılır.

Hikâye roman'dan daha kısa, tek bir olay çevresinde yoğunlaşır ve sınırlı sayıda kişi barındırır. Sınavlarda bu iki tür arasındaki farkı bilmek, soruları doğru yanıtlamak için zorunludur.$$, 164, 6, '{lgs,tyt}', '[{"question":"Olay örgüsü hangi bölümlerden oluşur?","options":["Başlangıç, orta ve son","Serim, düğüm ve çözüm","Giriş, gelişme ve sonuç","Tanıtım, çatışma ve kapanış"],"correctIndex":1},{"question":"Ana karakter ile yan karakter arasındaki fark nedir?","options":["Ana karakter daha uzun tanıtılır","Ana karakter olayların merkezindeyken yan karakterler destekleyici rol üstlenir","Yan karakterler her zaman kötü adamdır","Ana karakter her zaman kahraman olur"],"correctIndex":1},{"question":"\"Flashback\" tekniği ne anlama gelir?","options":["Olayları hızlı anlatmak","İleriye sıçramak","Anlatıda geçmiş olaylara dönmek","Karakteri detaylı tanıtmak"],"correctIndex":2},{"question":"Hikâye ile roman arasındaki temel fark nedir?","options":["Hikâye şiirsel, roman düz yazıdır","Hikâye daha kısa ve tek olay odaklıdır, roman daha uzun ve kapsamlıdır","Roman gerçek, hikâye kurgusaldır","Hikâyelerde kahraman yoktur"],"correctIndex":1}]'::jsonb),
  ('turkce', 'Gazete Haberi ve Röportaj', $$Gazete haberi, güncel olayları kısa ve yalın bir dille aktaran haber türüdür. Bir haberin temel unsurları şunlardır: ne, nerede, ne zaman, nasıl, neden ve kim. Bu altı soruya verilen yanıtlar, haberin tüm önemli bilgilerini kapsamalıdır.

Haberlerde dil tarafsız ve nesnel olmalıdır. Gazetecilik etiği gereği haber yazarı, kendi görüşünü habere katmamalıdır. Başlık dikkat çekici, ilk paragraf ise tüm önemli bilgileri içeren özet niteliğinde olmalıdır.

Röportaj ise bir kişiyle yapılan sorulu-yanıtlı konuşmanın yazıya aktarılmış halidir. Röportajlarda kişinin görüşleri, deneyimleri ve hayat hikâyesi aktarılır. Dil daha kişisel ve anlatısal olabilir.

Gazete haberi ile röportajı birbirinden ayırt etmek, Türkçe ve Edebiyat sınavlarında önemli bir konudur. Haberde bilgi aktarımı ön plandayken röportajda kişinin sesi ve bakış açısı öne çıkar.

Her iki türde de başlığa bakarak metnin içeriği hakkında ön fikir edinilebilir.$$, 160, 5, '{lgs,tyt}', '[{"question":"Bir gazete haberinin temel unsurları nelerdir?","options":["Başlık, giriş ve son paragraf","Ne, nerede, ne zaman, nasıl, neden ve kim soruları","Fotoğraf, altyazı ve metin","Yazar adı, tarih ve sayfa numarası"],"correctIndex":1},{"question":"Gazete haberinde dilin nasıl olması gerekir?","options":["Duygusal ve öznel","Tarafsız ve nesnel","Şiirsel ve mecazlı","Kişisel ve anlatısal"],"correctIndex":1},{"question":"Röportajın temel özelliği nedir?","options":["Bir olayı tarafsız aktarmak","Sorulu-yanıtlı bir konuşmanın yazıya dökülmesidir","Kısa ve öz bilgi vermek","Toplumsal sorunları eleştirmek"],"correctIndex":1},{"question":"Haber ile röportaj arasındaki temel fark nedir?","options":["Haberde resim kullanılır, röportajda kullanılmaz","Haberde bilgi aktarımı ön plandayken röportajda kişinin sesi öne çıkar","Röportaj daha kısa olur","Haber yalnızca siyasi konuları ele alır"],"correctIndex":1}]'::jsonb),
  ('ingilizce', 'Modal Fiiller: Can, Must, Should, May', $$Modal fiiller (modal verbs), İngilizce cümlelerde yardımcı fiil olarak kullanılan ve cümleye olasılık, zorunluluk, izin ya da öneri anlamı katan fiillerdir. "Can, must, should ve may" en sık kullanılan modal fiiller arasındadır.

"Can" yetenek ya da izin anlamı taşır. "She can speak three languages." cümlesi onun üç dil konuşabildiğini gösterir. İzin için ise "Can I sit here?" biçiminde kullanılır.

"Must" güçlü bir zorunluluk ifade eder. "You must wear a seatbelt." cümlesi emniyet kemeri takmanın zorunlu olduğunu belirtir. Aynı zamanda güçlü bir çıkarım yapmak için de kullanılır: "He must be tired."

"Should" öneri ve tavsiye içerir. "You should study every day." cümlesi her gün çalışmanın iyi bir fikir olduğunu önerir.

"May" olasılık ya da resmi izin anlamına gelir. "It may rain tomorrow." olasılığı ifade ederken "May I leave early?" resmi izin ister.

Bu modal fiillerin doğru kullanımı, LGS ve TYT İngilizce sınavlarında sıkça test edilir.$$, 155, 4, '{lgs,tyt}', '[{"question":"\"She can speak three languages.\" cümlesinde \"can\" hangi anlamı taşır?","options":["Zorunluluk","Öneri","Yetenek","Olasılık"],"correctIndex":2},{"question":"\"Must\" modal fiili hangi anlamları taşır?","options":["Öneri ve tavsiye","Güçlü zorunluluk ve güçlü çıkarım","Yetenek ve izin","Olasılık ve resmi izin"],"correctIndex":1},{"question":"\"You should study every day.\" cümlesinde \"should\" ne anlamına gelir?","options":["Her gün çalışmak zorunludur","Her gün çalışmak tavsiye edilir","Her gün çalışmak yasaktır","Her gün çalışmak olasıdır"],"correctIndex":1},{"question":"\"May I leave early?\" cümlesinde \"may\" ne işlev görür?","options":["Olasılık belirtir","Zorunluluk belirtir","Resmi izin ister","Öneri sunar"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Edilgen Çatı (Passive Voice)', $$İngilizce'de edilgen çatı (passive voice), eylemin kim tarafından yapıldığından çok neyin yapıldığına odaklanmak için kullanılır. Cümlenin nesnesi özne konumuna geçer ve fiil "be + past participle" (geçmiş ortaç) yapısıyla oluşturulur.

Örneğin, "The teacher corrects the homework." (etken) cümlesi edilgen çatıda "The homework is corrected by the teacher." biçimini alır. Özne olan "the teacher" edilgen cümlede "by the teacher" ifadesiyle gösterilir.

Farklı zamanlarda edilgen yapı şöyle kurulur: Geniş zaman için "is/are + past participle", geçmiş zaman için "was/were + past participle", gelecek zaman için "will be + past participle" kullanılır.

Edilgen çatı özellikle haber metinlerinde, bilimsel yazılarda ve resmi belgelerde sıklıkla görülür. Örneğin: "The new bridge was opened last week."

LGS ve TYT sınavlarında etken cümleyi edilgene ya da edilgen cümleyi etkene dönüştürmek, sık karşılaşılan soru tiplerindendir. Fiilin üçüncü halini (past participle) doğru kullanmak bu dönüşümlerde kritik öneme sahiptir.$$, 157, 5, '{lgs,tyt}', '[{"question":"Edilgen çatı hangi yapıyla oluşturulur?","options":["Have + past participle","Be + past participle","Do + past participle","Get + infinitive"],"correctIndex":1},{"question":"\"The teacher corrects the homework.\" cümlesinin edilgen biçimi hangisidir?","options":["The homework corrects the teacher.","The teacher is corrected by the homework.","The homework is corrected by the teacher.","The homework was correct."],"correctIndex":2},{"question":"Geçmiş zaman edilgen çatı hangi yapıyla kurulur?","options":["Is/are + past participle","Will be + past participle","Was/were + past participle","Has been + past participle"],"correctIndex":2},{"question":"Edilgen çatı hangi tür metinlerde sıklıkla kullanılır?","options":["Günlük diyaloglar ve şiirler","Haber metinleri, bilimsel yazılar ve resmi belgeler","Çocuk masalları ve romanlar","Yalnızca akademik tezler"],"correctIndex":1}]'::jsonb),
  ('ingilizce', 'Koşul Cümleleri (Conditional Sentences)', $$İngilizce'de koşul cümleleri (conditional sentences), bir koşul ile bu koşulun sonucunu bir arada ifade eden cümle yapılarıdır. "If" (eğer) bağlacıyla başlayan yan cümle koşulu, temel cümle ise sonucu bildirir.

Sıfır koşul (zero conditional) genel gerçekler için kullanılır. Her iki yan da geniş zamandadır: "If you heat ice, it melts."

Birinci koşul (first conditional) gerçekleşmesi mümkün olan gelecek durumlar için kullanılır. "If you study hard, you will pass the exam." cümlesinde koşul gerçekleşirse sonucun da gerçekleşeceği öngörülür.

İkinci koşul (second conditional) gerçek olmayan ya da olması çok zor olan durumları anlatır. "If I were rich, I would travel the world." Bu yapıda "if" yan cümlesinde past simple, temel cümlede "would + infinitive" kullanılır.

Üçüncü koşul (third conditional) ise geçmişte gerçekleşmemiş durumlar için pişmanlık ya da varsayım ifade eder. "If I had studied harder, I would have passed the test."

Sınavlarda koşul türleri arasındaki farkı bilmek ve doğru zaman kipini seçmek büyük önem taşır.$$, 162, 5, '{lgs,tyt}', '[{"question":"Sıfır koşul cümleleri ne için kullanılır?","options":["Gerçekleşmemiş geçmiş durumlar için","Genel gerçekler için","Olası gelecek durumlar için","Hayal kurmak için"],"correctIndex":1},{"question":"\"If you study hard, you will pass the exam.\" hangi koşul türüdür?","options":["Sıfır koşul","Birinci koşul","İkinci koşul","Üçüncü koşul"],"correctIndex":1},{"question":"İkinci koşul cümlesinde \"if\" yan cümlesinde hangi zaman kullanılır?","options":["Present simple","Future simple","Past simple","Present perfect"],"correctIndex":2},{"question":"Üçüncü koşul cümleleri hangi durumları ifade eder?","options":["Olası gelecek durumları","Genel gerçekleri","Geçmişte gerçekleşmemiş durumları","Şimdiki zamanı"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Sıfat Cümleleri (Relative Clauses)', $$Sıfat cümleleri (relative clauses), bir ismi ya da zamir ifadesini niteleyen yan cümlelerdir. Bu cümleler "who, which, that, whose, where ve when" gibi ilgi zamiriyle başlar.

"Who" insanlar için, "which" nesneler ve hayvanlar için, "that" ise her ikisi için kullanılabilir. "The boy who sits next to me is my friend." cümlesinde "who sits next to me" bölümü "the boy"u niteler.

Tanımlayıcı sıfat cümleleri (defining relative clauses), cümleye zorunlu bilgi ekler. Bu cümleler virgülle ayrılmaz. Örneğin: "The book that I read was interesting."

Tanımlamayan sıfat cümleleri (non-defining relative clauses) ise ekstra bilgi verir ve virgülle ayrılır. Örneğin: "My sister, who lives in Ankara, is a doctor." Bu yapıda "that" kullanılmaz.

"Whose" iyelik belirtir: "The student whose bag is red is absent today."

LGS ve TYT sınavlarında bu yapı, hem gramer soruları hem de okuma anlayışı testlerinde sıkça karşılaşılan konular arasındadır. Doğru ilgi zamirini seçmek ve virgül kullanımına dikkat etmek başarıyı artırır.$$, 158, 5, '{lgs,tyt}', '[{"question":"\"The boy who sits next to me is my friend.\" cümlesinde \"who\" neyi niteliyor?","options":["Arkadaşı","\"The boy\"u","Konuşmacıyı","Oturma eylemini"],"correctIndex":1},{"question":"\"Which\" ilgi zamiri ne için kullanılır?","options":["Yalnızca insanlar için","Yalnızca yerler için","Nesneler ve hayvanlar için","Zaman bildirmek için"],"correctIndex":2},{"question":"Tanımlamayan sıfat cümleleri (non-defining) nasıl ayrılır?","options":["Noktalı virgülle","Virgülle","Tire ile","Ayraçla"],"correctIndex":1},{"question":"\"Whose\" ilgi zamiri ne işlev görür?","options":["Yer bildirir","Zaman bildirir","İyelik belirtir","Eylem belirtir"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Present Perfect Tense', $$Present Perfect Tense (geniş geçmiş zaman), geçmişte başlayan ya da tamamlanan ancak şimdiki zamanla bağlantısı olan eylemleri ifade etmek için kullanılır. Bu zaman "have/has + past participle" yapısıyla kurulur.

Örneğin: "I have visited Istanbul three times." cümlesi, konuşmacının İstanbul'u kaç kez ziyaret ettiğini, bu ziyaretin ne zaman olduğundan bağımsız olarak aktarır.

Present Perfect çeşitli bağlamlarda kullanılır. "Already, yet, just, ever, never, since ve for" gibi zaman zarfları bu yapıyla sıklıkla kullanılır. "She has just arrived." (az önce geldi), "Have you ever eaten sushi?" (hiç yedim mi?) gibi.

"Since" belirli bir başlangıç noktası için, "for" ise süre belirtmek için kullanılır: "I have lived here since 2020." ve "I have lived here for five years."

Bu zaman dilimi, Simple Past ile sıkça karıştırılır. Temel fark şudur: Simple Past belirli bir geçmiş zaman dilimine atıfta bulunurken Present Perfect bugünle bağlantısı olan bir geçmiş durumu anlatır.

LGS ve TYT sınavlarında bu iki zamanın farkı düzenli olarak sorulmaktadır.$$, 160, 4, '{lgs,tyt}', '[{"question":"Present Perfect Tense hangi yapıyla oluşturulur?","options":["Did + past participle","Have/has + past participle","Was/were + past participle","Will + base form"],"correctIndex":1},{"question":"\"She has just arrived.\" cümlesindeki \"just\" ne anlama gelir?","options":["Henüz gelmedi","Az önce geldi","Yakında gelecek","Yarın geldi"],"correctIndex":1},{"question":"\"Since\" ve \"for\" kelimeleri arasındaki fark nedir?","options":["\"Since\" süre, \"for\" başlangıç noktası belirtir","\"Since\" başlangıç noktası, \"for\" süre belirtir","İkisi de aynı anlamda kullanılır","\"Since\" gelecek, \"for\" geçmiş belirtir"],"correctIndex":1},{"question":"Present Perfect ile Simple Past arasındaki temel fark nedir?","options":["Simple Past daha eski olaylar için kullanılır","Present Perfect daha uzun bir süreyi anlatır","Simple Past belirli geçmiş zamana, Present Perfect bugünle bağlantılı geçmişe atıfta bulunur","İkisi arasında fark yoktur"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Dolaylı Anlatım (Reported Speech)', $$Dolaylı anlatım (reported speech), bir kişinin söylediklerini doğrudan aktarmak yerine başkasına bildirirken kullanılan dilbilgisi yapısıdır. Bu yapıda cümle, genellikle "said that, told him/her that, asked if" gibi giriş ifadeleriyle başlar.

Fiil zamanları bir adım geriye kayar: Geniş zaman (present simple) geçmiş zamana (past simple) dönüşür. "I am tired." cümlesi dolaylı anlatımda "She said that she was tired." biçimini alır.

Soru cümlelerinde "said" yerine "asked" kullanılır. Evet-hayır soruları "asked if/whether" ile, soru sözcüklü sorular ise söz konusu soru kelimesiyle aktarılır: "Where do you live?" → "She asked where I lived."

Emir cümlelerinde ise "told + kişi + to infinitive" yapısı kullanılır: "Open the window." → "He told me to open the window."

Zaman ve yer belirteçleri de değişir: "now" yerine "then", "here" yerine "there", "today" yerine "that day" kullanılır.

Bu yapı LGS ve TYT sınavlarında hem dilbilgisi hem de okuma anlayışı sorularında karşımıza çıkmaktadır.$$, 156, 5, '{lgs,tyt}', '[{"question":"\"I am tired.\" cümlesinin dolaylı anlatım biçimi hangisidir?","options":["She said that she is tired.","She said that she was tired.","She told that she is tired.","She asked if she was tired."],"correctIndex":1},{"question":"Evet-hayır sorularını dolaylı anlatıma dönüştürürken ne kullanılır?","options":["Said that","Told to","Asked if/whether","Wanted that"],"correctIndex":2},{"question":"\"Open the window.\" emrinin dolaylı anlatım biçimi hangisidir?","options":["He said to open the window.","He asked if I opened the window.","He told me to open the window.","He told that open the window."],"correctIndex":2},{"question":"Dolaylı anlatımda \"now\" kelimesi hangi kelimeyle değiştirilir?","options":["Here","Then","That day","Today"],"correctIndex":1}]'::jsonb),
  ('ingilizce', 'Çevre (The Environment)', $$Çevre sorunları günümüzde hem bireysel hem de küresel düzeyde büyük önem taşımaktadır. İklim değişikliği (climate change), hava kirliliği (air pollution), su kirliliği (water pollution) ve orman kesimi (deforestation) bu sorunların başında gelmektedir.

İklim değişikliği, sera gazlarının atmosferde birikmesiyle oluşur. Karbondioksit (CO₂), metan ve su buharı en önemli sera gazlarıdır. Fosil yakıtların yakılması ve sanayi faaliyetleri bu gazların salınımını artırır.

Orman kesimi biyoçeşitlilik kaybına ve karbon depolanmasının azalmasına yol açar. Dünya nüfusunun artmasıyla birlikte tarım alanı açmak için her yıl milyonlarca hektar orman yok edilmektedir.

Bireyler de çevre koruma sürecine katkıda bulunabilir. Geri dönüşüm yapmak, enerji tasarrufu sağlamak, toplu taşıma kullanmak ve tek kullanımlık plastiklerden kaçınmak bu adımların en bilinenleridir.

Sürdürülebilir kalkınma (sustainable development), hem ekonomik büyümeyi hem de çevre korumayı bir arada hedefleyen bir yaklaşımdır. Gelecek nesillere yaşanabilir bir dünya bırakmak ortak sorumluluğumuzdur.$$, 163, 4, '{lgs,tyt}', '[{"question":"İklim değişikliğinin temel nedeni nedir?","options":["Okyanus sıcaklıklarının artması","Sera gazlarının atmosferde birikmesi","Güneş aktivitesinin artması","Ormanların genişlemesi"],"correctIndex":1},{"question":"Orman kesimi hangi sonuçlara yol açar?","options":["Hava kirliliğini azaltır","Biyoçeşitlilik kaybı ve karbon depolanmasının azalması","Su kirliliğini önler","İklim değişikliğini durdurur"],"correctIndex":1},{"question":"Bireylerin çevre korumaya katkısı olarak hangi davranış verilmemiştir?","options":["Geri dönüşüm yapmak","Toplu taşıma kullanmak","Tek kullanımlık plastikten kaçınmak","Daha fazla araba üretmek"],"correctIndex":3},{"question":"Sürdürülebilir kalkınma ne anlama gelir?","options":["Yalnızca ekonomik büyümeyi hedeflemek","Yalnızca çevre korumayı hedeflemek","Hem ekonomik büyümeyi hem de çevre korumayı bir arada hedeflemek","Sanayiyi durdurmak"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Günlük Yaşamda Teknoloji (Technology in Daily Life)', $$Teknoloji günümüzde hayatın her alanına girmiş, bireylerin yaşam biçimlerini köklü biçimde değiştirmiştir. Akıllı telefonlar (smartphones), tabletler ve giyilebilir teknolojiler (wearable technologies) artık gündelik yaşamın vazgeçilmez parçaları haline gelmiştir.

İnternet, bilgiye erişimi kolaylaştırmış ve iletişim alışkanlıklarını dönüştürmüştür. Sosyal medya platformları insanları dünyanın dört bir yanındaki bireylerle anlık olarak bağlamaktadır. Uzaktan çalışma (remote work) ve çevrimiçi eğitim (online education) gibi kavramlar pandemi süreciyle birlikte yaygınlaşmıştır.

Yapay zekâ (artificial intelligence) ve makine öğrenmesi (machine learning) ise teknolojinin en hızlı gelişen alanları arasındadır. Sağlık, ulaşım, finans ve eğitim sektörleri bu teknolojilerden yoğun biçimde yararlanmaktadır.

Ancak teknolojinin olumsuz etkileri de göz ardı edilmemelidir. Ekran bağımlılığı (screen addiction), mahremiyet sorunları (privacy issues) ve siber zorbalık (cyberbullying) modern dünyanın ciddi sorunları arasında yer almaktadır.

Teknolojiyi bilinçli ve dengeli kullanmak; bireylerin hem üretkenliklerini artırmasını hem de sağlıklarını korumasını sağlar.$$, 161, 4, '{lgs,tyt}', '[{"question":"Metne göre teknoloji günlük yaşamı nasıl etkilemiştir?","options":["Yalnızca iş hayatını değiştirmiştir","Hayatın her alanına girerek yaşam biçimlerini köklü biçimde değiştirmiştir","Yalnızca iletişimi etkilemiştir","Olumsuz etkiler dışında bir etkisi olmamıştır"],"correctIndex":1},{"question":"Pandemi süreciyle birlikte hangi kavramlar yaygınlaşmıştır?","options":["Yapay zekâ ve robotik","Sosyal medya ve internet","Uzaktan çalışma ve çevrimiçi eğitim","Giyilebilir teknoloji ve akıllı ev sistemleri"],"correctIndex":2},{"question":"\"Screen addiction\" Türkçe''de ne anlama gelir?","options":["Ekran kalitesi","Ekran bağımlılığı","Ekran parlaklığı","Ekran boyutu"],"correctIndex":1},{"question":"Metne göre teknolojiyi nasıl kullanmak gereklidir?","options":["Olabildiğince çok kullanmak","Hiç kullanmamak","Bilinçli ve dengeli kullanmak","Yalnızca iş amaçlı kullanmak"],"correctIndex":2}]'::jsonb),
  ('ingilizce', 'Sağlık ve Yaşam Tarzı (Health and Lifestyle)', $$Sağlıklı bir yaşam sürmek, hem fiziksel hem de zihinsel refahın temelini oluşturur. Dengeli beslenme (balanced diet), düzenli egzersiz (regular exercise), yeterli uyku (sufficient sleep) ve stresin yönetimi sağlıklı yaşamın dört ana bileşenidir.

Dengeli bir beslenme düzeni; protein, karbonhidrat, yağ, vitamin ve minerallerin yeterli miktarda alınmasını gerektirir. İşlenmiş gıdalar (processed foods) ve şekerli içecekler uzun vadede obezite, diyabet ve kalp hastalıklarına zemin hazırlayabilir.

Düzenli fiziksel aktivite, kardiyovasküler sağlığı güçlendirir, kemikleri sağlamlaştırır ve ruh halini olumlu etkiler. Dünya Sağlık Örgütü, yetişkinlere haftada en az 150 dakika orta şiddette egzersiz önermektedir.

Uyku, vücudun onarım ve yenilenme sürecidir. Yetişkinlerin günde yedi ile dokuz saat uyuması gerektiği bilinmektedir. Yetersiz uyku bağışıklık sistemini zayıflatır ve dikkat süresini kısaltır.

Zihinsel sağlık da ihmal edilmemelidir. Meditasyon (meditation), hobiler ve sosyal bağlar stresin azaltılmasına katkı sağlar. Sağlıklı bir yaşam tarzı benimsemek, uzun ve kaliteli bir yaşamın anahtarıdır.$$, 164, 4, '{lgs,tyt}', '[{"question":"Sağlıklı yaşamın dört ana bileşeni hangileridir?","options":["Egzersiz, uyku, hobiler ve meditasyon","Dengeli beslenme, düzenli egzersiz, yeterli uyku ve stresin yönetimi","Su içmek, vitamin almak, spor yapmak ve erken uyumak","Diyet, yürüyüş, kitap okumak ve sosyalleşmek"],"correctIndex":1},{"question":"İşlenmiş gıdaların uzun vadede hangi hastalıklara zemin hazırlayabileceği belirtilmiştir?","options":["Kemik erimesi ve anemi","Obezite, diyabet ve kalp hastalıkları","Cilt hastalıkları ve alerji","Görme bozuklukları ve migren"],"correctIndex":1},{"question":"Dünya Sağlık Örgütü yetişkinlere haftada kaç dakika egzersiz önermektedir?","options":["En az 60 dakika","En az 100 dakika","En az 150 dakika","En az 200 dakika"],"correctIndex":2},{"question":"Zihinsel sağlığı desteklemek için metinde hangi yöntemler önerilmektedir?","options":["Daha fazla uyku ve egzersiz","Meditasyon, hobiler ve sosyal bağlar","Vitamin takviyeleri ve ilaçlar","Diyet ve su içmek"],"correctIndex":1}]'::jsonb),
  ('ingilizce', 'Dünyada Eğitim Sistemleri (Education Systems Around the World)', $$Dünya genelinde eğitim sistemleri büyük farklılıklar göstermektedir. Finlandiya, eğitim alanında uzun yıllardır en başarılı ülkeler arasında gösterilmektedir. Finlandiya modelinde rekabet yerine iş birliği, standart testler yerine bireysel değerlendirme ön plana çıkmaktadır. Öğretmenlik en saygın meslekler arasında yer alır ve öğretmen adayları yüksek akademik standartları karşılamak zorundadır.

Japonya ise disiplin, çalışkanlık ve grup dayanışmasını vurgulayan bir eğitim kültürüne sahiptir. Japon öğrenciler okullarını temizlemekte, bu uygulama sorumluluk bilincini pekiştirmektedir.

Amerika Birleşik Devletleri'nde ise eğitim sistemi eyaletten eyalete değişmektedir. Eleştirel düşünme (critical thinking), yaratıcılık ve bireysellik ön plana çıkarılmaktadır.

Türkiye'de eğitim sistemi son yıllarda köklü değişiklikler geçirmiştir. LGS ve YKS gibi ulusal sınavlar, öğrencilerin ortaöğretim ve yükseköğretim kurumlarına geçişini belirlemektedir.

Tüm bu sistemlerin ortak amacı, bireyleri topluma ve iş dünyasına hazırlamak, merak duygusunu ve öğrenme isteğini canlı tutmaktır. Küresel düzeyde en başarılı sistemler öğrenci merkezli yaklaşımı benimseyen sistemlerdir.$$, 166, 5, '{lgs,tyt}', '[{"question":"Finlandiya eğitim modelinde hangi yaklaşım ön plana çıkmaktadır?","options":["Rekabet ve standart testler","İş birliği ve bireysel değerlendirme","Disiplin ve grup çalışması","Eleştirel düşünme ve yaratıcılık"],"correctIndex":1},{"question":"Japon eğitim kültüründe öğrencilerin okullarını temizlemesinin amacı nedir?","options":["Temizlik alışkanlığı kazandırmak","Okul bütçesini düşürmek","Sorumluluk bilincini pekiştirmek","Disiplin uygulamak"],"correctIndex":2},{"question":"Türkiye''de LGS ve YKS sınavları ne amaçla kullanılmaktadır?","options":["Öğretmen istihdamı için","Öğrencilerin ortaöğretim ve yükseköğretim kurumlarına geçişini belirlemek için","Okul fonlaması için","Müfredat değerlendirmesi için"],"correctIndex":1},{"question":"Metne göre küresel düzeyde en başarılı eğitim sistemleri hangi yaklaşımı benimsemiştir?","options":["Öğretmen merkezli yaklaşım","Sınav odaklı yaklaşım","Öğrenci merkezli yaklaşım","Rekabetçi yaklaşım"],"correctIndex":2}]'::jsonb),
  ('teknoloji', 'Yapay Zeka ve Makine Öğrenmesi', $$Yapay zeka (YZ), bilgisayarların insan zekasını taklit ederek öğrenme, problem çözme ve karar verme gibi görevleri yerine getirmesini sağlayan teknoloji alanıdır. Makine öğrenmesi ise yapay zekanın en önemli alt dallarından biridir.

Makine öğrenmesinde bilgisayarlar, büyük miktarda veriden örüntü çıkararak kendi kendine öğrenir. Programcıların her kuralı tek tek yazması gerekmez; sistem, verilerden kendi kurallarını üretir. Örneğin bir e-posta sistemi, binlerce spam örneğini inceleyerek yeni spam iletileri otomatik olarak tanımayı öğrenebilir.

Yapay zeka üç temel kategoride incelenir: dar yapay zeka yalnızca belirli görevleri yapar; genel yapay zeka insan gibi geniş kapsamlı düşünebilir; süper yapay zeka ise teorik olarak insanı her alanda geride bırakır. Bugün kullandığımız sistemlerin tamamı dar yapay zeka kapsamındadır.

Günlük hayatta YZ'ye pek çok yerde rastlarız: sesli asistanlar, yüz tanıma sistemleri, öneri algoritmaları ve otonom araçlar bunların en bilinen örnekleridir.

Yapay zekanın hızlı gelişimi, etik soruları da gündeme getirmektedir. Gizlilik, önyargı ve iş kaybı riski, teknoloji uzmanlarının ve politika yapıcıların gündemindedir.$$, 165, 5, '{tyt,ayt}', '[{"question":"Makine öğrenmesinin temel özelliği nedir?","options":["Her kuralı programcıların tek tek yazmasıdır","Sistemin büyük verilerden örüntü çıkararak kendi kendine öğrenmesidir","Yalnızca matematiksel hesaplama yapmasıdır","İnternetin olmadığı ortamlarda çalışmasıdır"],"correctIndex":1},{"question":"Dar yapay zeka nasıl tanımlanır?","options":["İnsan gibi geniş kapsamlı düşünebilen sistemdir","İnsanı her alanda geride bırakan sistemdir","Yalnızca belirli görevleri yapabilen sistemdir","Duygusal zekaya sahip olan sistemdir"],"correctIndex":2},{"question":"Günlük hayatta yapay zekanın kullanıldığı örneklerden biri hangisidir?","options":["Kağıt üretimi","Yüz tanıma sistemleri","Matbaa makineleri","Demir çelik sanayii"],"correctIndex":1},{"question":"Yapay zekanın hızlı gelişimiyle birlikte gündeme gelen etik sorunlar nelerdir?","options":["Elektrik tüketimi ve su israfı","Gizlilik, önyargı ve iş kaybı riski","Trafik yoğunluğu ve kirlilik","Eğitim kalitesi ve okul sayısı"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Blockchain ve Kripto Para', $$Blockchain, verilerin birbirine zincir halinde bağlı bloklar içinde saklandığı dağıtık bir kayıt defteridir. Merkezi bir otoriteye ihtiyaç duymadan güvenli veri depolama ve aktarımı sağlar. Her blok, önceki bloğun özetini (hash) içerdiğinden geçmişe yönelik herhangi bir değişiklik hemen fark edilir.

Bitcoin, 2009 yılında Satoshi Nakamoto takma adlı kişi ya da grup tarafından oluşturulan ilk kripto paradır. Kripto paralar, blockchain teknolojisi üzerine inşa edilmiş dijital para birimleridir; devlet ya da merkez bankası gibi merkezi bir otoriteye bağlı değildir.

Blockchain madenciliği, yeni işlemleri onaylama sürecidir. Madenciler, karmaşık matematiksel problemleri çözerek blok zincire yeni blok ekler ve ödül olarak kripto para kazanır. Bu süreç çok fazla enerji tüketir; bu durum çevresel kaygılara yol açmaktadır.

Blockchain yalnızca kripto para ile sınırlı değildir. Akıllı sözleşmeler, tedarik zinciri takibi, sağlık kayıtları ve oylama sistemleri gibi alanlarda da kullanılmaktadır.

Türkiye'de kripto para işlemleri son yıllarda önemli ölçüde artmış; yasal düzenlemeler ve vergi uygulamaları tartışılmaya devam etmektedir.$$, 168, 5, '{tyt,ayt}', '[{"question":"Blockchain teknolojisinin temel özelliği nedir?","options":["Merkezi bir banka tarafından yönetilmesidir","Verilerin birbirine zincir halinde bağlı bloklarda dağıtık şekilde saklanmasıdır","Yalnızca kripto para transferinde kullanılmasıdır","Tek bir sunucu üzerinde çalışmasıdır"],"correctIndex":1},{"question":"Bitcoin''in oluşturulduğu yıl ve oluşturuculara atfedilen takma ad nedir?","options":["2005, Elon Musk","2009, Satoshi Nakamoto","2015, Mark Zuckerberg","2000, Bill Gates"],"correctIndex":1},{"question":"Blockchain madenciliğinin çevresel kaygıya yol açmasının nedeni nedir?","options":["Çok fazla su tüketmesi","Kimyasal atık üretmesi","Çok fazla enerji tüketmesi","Orman alanlarını kullanması"],"correctIndex":2},{"question":"Blockchain teknolojisi kripto para dışında hangi alanlarda kullanılmaktadır?","options":["Yalnızca bankacılık sektöründe","Akıllı sözleşmeler, tedarik zinciri takibi ve sağlık kayıtlarında","Yalnızca sosyal medya platformlarında","Yalnızca video oyunlarında"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Kuantum Bilgisayarlar', $$Klasik bilgisayarlar, verileri 0 veya 1 değerlerinden oluşan bitlerle işler. Kuantum bilgisayarlar ise "qubit" (kuantum bit) adı verilen birimler kullanır. Kuantum mekaniğinin "süperpozisyon" ilkesi sayesinde bir qubit, aynı anda hem 0 hem de 1 değerinde olabilir. Bu özellik, kuantum bilgisayarlara klasik bilgisayarlara göre çok daha büyük bir işlem kapasitesi kazandırır.

Dolanıklık (entanglement) ise iki qubitin durumlarının birbirinden bağımsız olmadığı, birinin durumunun diğerini anlık olarak etkilediği kuantum olgusudur. Bu özellik, hız ve güvenli iletişim açısından devrimsel potansiyel taşır.

Kuantum bilgisayarlar; ilaç geliştirme, şifreleme kırma, lojistik optimizasyonu ve iklim modellemesi gibi alanlarda devrim yaratabilir. Google, IBM ve çeşitli ülkelerin devlet laboratuvarları bu alanda yoğun araştırmalar yürütmektedir.

Ancak kuantum bilgisayarların kararlı çalışabilmesi için mutlak sıfıra yakın sıcaklıklar gereklidir. Bu durum teknolojiyi henüz pahalı ve sınırlı erişimli kılmaktadır.

Uzmanlar, "kuantum üstünlüğü" kavramını kuantum bilgisayarın belirli bir görevi klasik bilgisayarların yetersiz kalacağı hızda tamamlaması olarak tanımlar.$$, 163, 6, '{tyt,ayt}', '[{"question":"Klasik bilgisayarlar ile kuantum bilgisayarlar arasındaki temel fark nedir?","options":["Klasik bilgisayarlar daha hızlıdır","Kuantum bilgisayarlar qubit kullanırken klasik bilgisayarlar bit kullanır","Kuantum bilgisayarlar yalnızca internete bağlı çalışır","Klasik bilgisayarlar aynı anda hem 0 hem 1 işleyebilir"],"correctIndex":1},{"question":"Süperpozisyon ilkesi ne anlama gelir?","options":["Qubitin yalnızca 0 değerinde olabilmesi","Qubitin aynı anda hem 0 hem 1 değerinde olabilmesi","İki qubitin aynı değerde olması","Qubitin enerjisinin sıfıra eşit olması"],"correctIndex":1},{"question":"Kuantum bilgisayarların kararlı çalışabilmesi için hangi koşul gerekmektedir?","options":["Çok yüksek sıcaklık","Mutlak sıfıra yakın sıcaklık","Sabit internet bağlantısı","Güçlü bir manyetik alan"],"correctIndex":1},{"question":"\"Kuantum üstünlüğü\" kavramı nasıl tanımlanmaktadır?","options":["Kuantum bilgisayarın her alanda klasik bilgisayardan üstün olması","Kuantum bilgisayarın belirli bir görevi klasik bilgisayarların yetersiz kalacağı hızda tamamlaması","Kuantum bilgisayarın internet olmadan çalışması","Kuantum bilgisayarın insandan daha zeki olması"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Nesnelerin İnterneti - IoT', $$Nesnelerin İnterneti (IoT — Internet of Things), günlük hayatta kullandığımız fiziksel nesnelerin internet aracılığıyla birbirleriyle ve kullanıcılarıyla iletişim kurmasını sağlayan teknolojidir. Akıllı telefonlardan buzdolabına, trafiği düzenleyen sensörlerden fabrika makinelerine kadar pek çok cihaz bu ağın parçası olabilir.

Akıllı ev sistemleri IoT'nin en bilinen uygulamasıdır. Termostat, aydınlatma, güvenlik kamerası ve kapı kilidi gibi sistemler akıllı telefon üzerinden uzaktan kontrol edilebilir. Bu sayede enerji tasarrufu sağlanır ve kullanıcı konforu artar.

IoT, sağlık sektöründe de devrim yaratmaktadır. Giyilebilir cihazlar kalp atış hızı, uyku düzeni ve kan şekeri gibi verileri sürekli takip ederek doktora anında iletebilir.

Tarım alanında ise toprak nemi, hava sıcaklığı ve bitki büyümesini izleyen sensörler çiftçilere verimlilik artışı sağlamaktadır. Akıllı şehirlerde çöp konteynerleri doluluk düzeylerine göre otomatik olarak toplanmaktadır.

IoT'nin yaygınlaşmasıyla siber güvenlik riskleri de artmaktadır. Her bağlantılı cihaz potansiyel bir saldırı noktası oluşturduğundan güvenlik önlemlerinin titizlikle uygulanması gerekmektedir.$$, 162, 5, '{tyt,ayt}', '[{"question":"Nesnelerin İnterneti (IoT) ne anlama gelir?","options":["Yalnızca akıllı telefonların internete bağlanmasıdır","Fiziksel nesnelerin internet aracılığıyla birbirleriyle ve kullanıcılarıyla iletişim kurmasıdır","Bilgisayarların birbirine kablo ile bağlanmasıdır","Sosyal medya ağlarının bir araya gelmesidir"],"correctIndex":1},{"question":"IoT''nin sağlık sektöründeki kullanımına hangi örnek verilebilir?","options":["Hastane binalarının yapımı","Giyilebilir cihazların sağlık verilerini izleyip doktora iletmesi","İlaçların üretilmesi","Ameliyathane klimalarının kontrolü"],"correctIndex":1},{"question":"IoT''nin tarım alanındaki katkısı nedir?","options":["Tarım ilaçlarının otomatik üretilmesi","Toprak, hava ve bitki verilerini izleyen sensörler sayesinde verimlilik artışı","Çiftçilerin eğitim almasını sağlaması","Hayvanların sağlık kontrolü"],"correctIndex":1},{"question":"IoT''nin yaygınlaşmasıyla birlikte artan risk nedir?","options":["Enerji tüketiminin azalması","Siber güvenlik riskleri","İnternet hızının düşmesi","Tarımsal üretimin azalması"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Siber Güvenlik', $$Siber güvenlik, bilgisayar sistemlerini, ağları, yazılımları ve verileri dijital saldırılara karşı koruma bilimidir. Günümüzde bireylerden devletlere kadar herkes siber tehditlerin hedefi olabilir.

En yaygın siber tehditler arasında kötü amaçlı yazılımlar (malware), kimlik avı (phishing), fidye yazılımı (ransomware) ve DDoS saldırıları yer alır. Fidye yazılımı, kullanıcının dosyalarını şifreleyerek dosyalara erişim için para talep eder. Kimlik avı ise kullanıcıları sahte web siteleri veya e-postalar aracılığıyla kişisel bilgilerini ifşa etmeye yönlendirir.

Bireysel korunma yöntemleri arasında güçlü ve farklı şifreler kullanmak, iki faktörlü kimlik doğrulamayı etkinleştirmek, yazılımları güncel tutmak ve bilinmeyen bağlantılara tıklamamak sayılabilir.

Kurumsal düzeyde ise güvenlik duvarı (firewall), antivirüs yazılımları, veri şifreleme, düzenli yedekleme ve çalışan eğitimleri temel önlemlerdir.

Türkiye'de siber güvenlik alanındaki farkındalık son yıllarda artmış; BTK (Bilgi Teknolojileri ve İletişim Kurumu) başta olmak üzere pek çok kurum bu alanda politika ve düzenlemeler geliştirmektedir. Siber güvenlik uzmanlarına olan talep dünya genelinde hızla artmaktadır.$$, 167, 5, '{tyt,ayt}', '[{"question":"Fidye yazılımı (ransomware) nasıl çalışır?","options":["Kullanıcının internet bağlantısını keser","Kullanıcının dosyalarını şifreleyerek erişim için para talep eder","Kullanıcının ekranını karartır","Kullanıcının e-postalarını siler"],"correctIndex":1},{"question":"Kimlik avı (phishing) saldırısı ne amaçla yapılır?","options":["Sistemlerin hızını artırmak için","Kullanıcıları sahte site ya da e-postalarla kişisel bilgilerini ifşa etmeye yönlendirmek için","Kullanıcının dosyalarını şifrelemek için","Ağ bağlantısını kesmek için"],"correctIndex":1},{"question":"Bireysel siber güvenlik için önerilen yöntemlerden biri hangisidir?","options":["Her hesapta aynı şifreyi kullanmak","Bilinmeyen bağlantılara tıklamamak ve iki faktörlü kimlik doğrulamayı etkinleştirmek","Antivirüs yazılımını kaldırmak","Yazılım güncellemelerini ertelemek"],"correctIndex":1},{"question":"Türkiye''de siber güvenlik alanında düzenleme yapan kurum hangisidir?","options":["TÜBİTAK","BTK (Bilgi Teknolojileri ve İletişim Kurumu)","RTÜK","SPK"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Büyük Veri - Big Data', $$Büyük veri (Big Data), geleneksel veri işleme araçlarının kapasitesini aşan, çok büyük hacimli, hızlı üretilen ve farklı formatlarda gelen veri kümelerini tanımlar. Bu kavram üç temel özellikle açıklanır: Hacim (Volume), Hız (Velocity) ve Çeşitlilik (Variety) — kısaca "3V modeli" olarak bilinir.

Hacim, verilerin boyutunu ifade eder; günümüzde her gün milyarlarca mesaj, fotoğraf ve video üretilmektedir. Hız, verilerin üretilme ve işlenme hızını gösterir; anlık borsa verileri veya sosyal medya akışları buna örnektir. Çeşitlilik ise metninden görüntüsüne, sesinden coğrafi konumuna kadar farklı veri tiplerinin bir arada bulunmasını ifade eder.

Büyük veri analitiği, işletmelere müşteri davranışlarını anlamada, hastalık salgınlarını tahmin etmede ve trafik akışlarını optimize etmede büyük avantajlar sağlar.

Netflix ve Spotify gibi platformlar, büyük veri ile kullanıcılara kişiselleştirilmiş öneriler sunar. Sağlık sektöründe ise milyonlarca hasta verisini analiz ederek hastalıkların erken teşhis edilmesi mümkün hale gelmektedir.

Büyük verinin etik boyutları da tartışılmaktadır. Kişisel verilerin toplanması ve işlenmesi, gizlilik hakları ve veri güvenliği açısından ciddi sorunlar doğurabilir.$$, 164, 5, '{tyt,ayt}', '[{"question":"Büyük verinin \"3V modeli\" neleri kapsar?","options":["Verimlilik, Vizyon, Varlık","Hacim (Volume), Hız (Velocity) ve Çeşitlilik (Variety)","Veri, Veritabanı, Varlık yönetimi","Hız, Güvenlik, Depolama"],"correctIndex":1},{"question":"Büyük veride \"Hız\" (Velocity) ne anlama gelir?","options":["Verilerin ne kadar büyük olduğu","Verilerin kaç farklı formatta olduğu","Verilerin üretilme ve işlenme hızı","Verilerin güvenlik düzeyi"],"correctIndex":2},{"question":"Netflix ve Spotify büyük veriyi hangi amaçla kullanır?","options":["Kullanıcı şifrelerini korumak için","Kullanıcılara kişiselleştirilmiş öneriler sunmak için","Sunucu maliyetlerini düşürmek için","Abonelik fiyatlarını belirlemek için"],"correctIndex":1},{"question":"Büyük verinin etik boyutları hangi konuları kapsar?","options":["Enerji verimliliği ve çevre sorunları","Kişisel verilerin toplanması, gizlilik hakları ve veri güvenliği","Yazılım lisansları ve telif hakları","Sunucu donanım maliyetleri"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Artırılmış ve Sanal Gerçeklik - AR/VR', $$Artırılmış gerçeklik (AR — Augmented Reality) ve sanal gerçeklik (VR — Virtual Reality), kullanıcı deneyimini dönüştüren iki yakın ancak birbirinden farklı teknolojidir.

Sanal gerçeklik, kullanıcıyı tamamen bilgisayar tarafından oluşturulmuş bir ortama daldırır. VR gözlükleri takıldığında gerçek dünya algılanmaz; her şey dijital ortamda gerçekleşir. Oyun, eğitim simülasyonları ve psikoterapi bu teknolojinin başlıca kullanım alanlarıdır.

Artırılmış gerçeklik ise gerçek dünya görüntüsüne dijital katmanlar ekler. Akıllı telefon kamerasıyla bir mobilyanın evdeki görünümünü önceden test etmek, ya da bir cerrahın ameliyat sırasında 3D organ modellerini görmesi AR uygulamalarına örnektir.

Karma gerçeklik (MR — Mixed Reality) ise her iki teknolojinin özelliklerini birleştirir; dijital nesneler gerçek dünyayla etkileşime girebilir.

Eğitim alanında AR ve VR, öğrencilerin tarihi olayları "yaşayarak" öğrenmesine ya da insan vücudunu üç boyutlu olarak incelemesine olanak tanır. Mimarlık, turizm, askerlik eğitimi ve sağlık bu teknolojilerden en çok yararlanan sektörler arasındadır.

Donanım maliyetlerinin düşmesiyle birlikte AR ve VR'ın önümüzdeki yıllarda günlük hayatın daha büyük bir parçası olması beklenmektedir.$$, 161, 5, '{tyt,ayt}', '[{"question":"Sanal gerçeklik (VR) ile artırılmış gerçeklik (AR) arasındaki temel fark nedir?","options":["VR yalnızca oyun için, AR yalnızca tıp için kullanılır","VR kullanıcıyı tamamen dijital bir ortama daldırırken AR gerçek dünyaya dijital katmanlar ekler","AR gözlük gerektirirken VR gerektirmez","İkisi aynı teknolojidir, sadece isimleri farklıdır"],"correctIndex":1},{"question":"Artırılmış gerçekliğe (AR) günlük hayattan hangi örnek verilebilir?","options":["VR gözlükle oyun oynamak","Akıllı telefonla mobilyanın evdeki görünümünü önceden test etmek","Sanal bir ortamda uçuş simülasyonu yapmak","Bilgisayarda film izlemek"],"correctIndex":1},{"question":"Karma gerçeklik (MR) nasıl tanımlanır?","options":["Yalnızca sanal gerçekliğin gelişmiş halidir","Gerçek dünyadan tamamen kopuk bir deneyimdir","Dijital nesnelerin gerçek dünyayla etkileşime girdiği AR ve VR''ın birleşimidir","Yalnızca sosyal medyada kullanılan bir teknolojidir"],"correctIndex":2},{"question":"Eğitim alanında AR ve VR''ın sağladığı avantaj nedir?","options":["Kitapların dijital kopyasını sunmak","Öğrencilerin tarihi olayları yaşayarak öğrenmesine ve 3B inceleme yapmasına olanak tanımak","Sınav sorularını otomatik oluşturmak","Öğretmenlerin iş yükünü azaltmak"],"correctIndex":1}]'::jsonb),
  ('teknoloji', '5G Teknolojisi', $$5G, beşinci nesil mobil iletişim teknolojisidir ve önceki nesil olan 4G'ye kıyasla çok daha yüksek hız, çok daha düşük gecikme süresi (latency) ve çok daha fazla cihaza eş zamanlı bağlantı imkânı sunar. Teorik maksimum hızı saniyede 20 gigabit'e ulaşabilirken gecikme süresi 1 milisaniyenin altına inebilir.

Bu özellikler, 5G'yi yalnızca akıllı telefon internet deneyimini iyileştirmenin ötesinde bir altyapı haline getirir. Nesnelerin İnterneti (IoT), otonom araçlar, uzaktan cerrahi ve akıllı fabrikalar 5G'nin dönüştüreceği alanların başında gelir.

Türkiye'de 5G altyapı çalışmaları devam etmekte olup lisanslama ve frekans tahsis süreçleri BTK koordinasyonunda yürütülmektedir. Dünya genelinde Güney Kore, Çin ve Amerika Birleşik Devletleri 5G'de en hızlı yaygınlaşmayı gerçekleştiren ülkeler arasındadır.

5G'nin önemli tartışma konularından biri sağlık etkileridir. Bilimsel çalışmalar şu ana kadar onaylı frekanslarda kullanılan 5G'nin sağlık açısından zararlı olmadığını ortaya koymaktadır.

Altyapı maliyetleri ve baz istasyonu yoğunluğu ihtiyacı, 5G'nin yaygınlaşmasındaki başlıca engellerden biridir. Ancak teknoloji şirketleri ve hükümetler bu alanda yatırımlarını hızlandırmaktadır.$$, 166, 5, '{tyt,ayt}', '[{"question":"5G''nin 4G''ye göre temel avantajları nelerdir?","options":["Daha küçük telefon boyutu ve daha uzun pil ömrü","Çok daha yüksek hız, düşük gecikme süresi ve daha fazla eş zamanlı cihaz bağlantısı","Daha ucuz veri paketleri ve ücretsiz arama","Daha geniş kapsama alanı ve sinyal gücü"],"correctIndex":1},{"question":"5G teknolojisi hangi yeni uygulama alanlarını dönüştürmesi beklenmektedir?","options":["Yalnızca sosyal medya ve oyun sektörü","Otonom araçlar, uzaktan cerrahi ve akıllı fabrikalar","Yalnızca film izleme ve müzik akışı","Yalnızca banka işlemleri"],"correctIndex":1},{"question":"5G''nin maksimum teorik hızı ne kadardır?","options":["Saniyede 1 megabit","Saniyede 100 megabit","Saniyede 20 gigabit","Saniyede 1 terabit"],"correctIndex":2},{"question":"Türkiye''de 5G altyapı çalışmalarını hangi kurum koordine etmektedir?","options":["TÜBİTAK","BTK (Bilgi Teknolojileri ve İletişim Kurumu)","Sanayi ve Teknoloji Bakanlığı","RTÜK"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Otonom Araçlar', $$Otonom araçlar (self-driving cars), insan müdahalesi olmadan çevresini algılayıp yol üzerinde hareket edebilen taşıtlardır. Sensörler, kameralar, radar ve LiDAR (ışık radar) teknolojileri bu araçların çevresini "görmesini" sağlar. Yapay zeka algoritmaları ise bu verilerle an be an karar verir.

Uluslararası Otomotiv Mühendisleri Derneği (SAE), otonomluk düzeylerini 0'dan 5'e kadar altı seviyede tanımlamıştır. Seviye 0'da araç tamamen insan kontrolündeyken; Seviye 5'te araç her koşulda tam bağımsız hareket edebilir. Günümüzdeki araçların büyük çoğunluğu Seviye 2-3 arasında yer almaktadır.

Tesla, Waymo ve pek çok geleneksel otomobil üreticisi bu alanda yatırımlarını sürdürmektedir. Otonom araçların trafik kazalarını azaltması, yakıt tüketimini optimize etmesi ve şehir içi ulaşımı dönüştürmesi beklenmektedir.

Ancak yasal düzenlemeler, etik ikilemler ve siber güvenlik kaygıları otonom araçların geniş çaplı kullanımını yavaşlatmaktadır. Özellikle kaza durumlarında hukuki sorumluluk kimin olduğu sorusu henüz yanıt bekleyen önemli bir tartışma konusudur.

Türkiye'de de yerli otomobil TOGG bünyesinde yarı otonom sürüş teknolojileri geliştirilmektedir.$$, 162, 5, '{tyt,ayt}', '[{"question":"Otonom araçların çevresini algılamasını sağlayan teknolojiler hangileridir?","options":["GPS ve mobil internet","Sensörler, kameralar, radar ve LiDAR","Ses tanıma ve parmak izi okuyucu","Yalnızca kamera ve GPS"],"correctIndex":1},{"question":"SAE otonomluk düzeyi sınıflandırmasında Seviye 5 ne anlama gelir?","options":["Araç yalnızca şehir içinde bağımsız hareket edebilir","Araç her koşulda tam bağımsız hareket edebilir","Araç sadece otoyolda bağımsız hareket edebilir","Araç sürücü gözetiminde hareket eder"],"correctIndex":1},{"question":"Otonom araçların yaygınlaşmasını yavaşlatan etkenlerden biri hangisidir?","options":["Yakıt maliyetlerinin artması","Otomobil üreticilerinin ilgisizliği","Yasal düzenlemeler, etik ikilemler ve siber güvenlik kaygıları","Şarj altyapısının yetersizliği"],"correctIndex":2},{"question":"Türkiye''de otonom sürüş teknolojileriyle ilişkili yerli otomobil projesi hangisidir?","options":["ASELSAN","TOGG","TAI","TÜLOMSAŞ"],"correctIndex":1}]'::jsonb),
  ('teknoloji', 'Uzay Teknolojileri', $$Uzay teknolojisi, insanlığın atmosfer ötesini keşfetmesini, uydu sistemleri kurmasını ve diğer gezegenlere ulaşmasını mümkün kılan bilim ve mühendislik alanıdır. Uzay çağı, 1957'de Sovyetler Birliği'nin Sputnik uydusunu fırlatmasıyla başlamıştır.

Roketler, uzaya çıkışın temel aracıdır. Kimyasal yakıtlı roketler, dünyanın yer çekimini yenebilmek için saniyede yaklaşık 11,2 kilometre hıza ulaşmalıdır; buna "kaçış hızı" denir. SpaceX, yeniden kullanılabilir roket teknolojisiyle uzay fırlatma maliyetlerini büyük ölçüde düşürmüştür.

Uydular; iletişim, hava tahmini, coğrafi bilgi sistemleri, casusluk ve bilimsel araştırma gibi çok çeşitli amaçlarla kullanılmaktadır. GPS sistemi de aslında uydu ağına dayalı bir konum belirleme sistemidir.

Mars keşfi insan neslinin en büyük uzay hedeflerinden biri haline gelmiştir. NASA'nın Perseverance rover aracı, Mars'ta yaşam izleri aramaya devam etmektedir. Elon Musk liderliğindeki SpaceX ise 2030'lu yıllarda Mars'a insanlı görev planlamaktadır.

Türkiye, 2023 yılında "Ay'a Gidiyoruz" projesiyle uzay yarışına dahil olmuştur. TÜBİTAK UZAY ve Türkiye Uzay Ajansı bu alandaki çalışmaları yürütmektedir.$$, 170, 6, '{tyt,ayt}', '[{"question":"Uzay çağının başlangıcına işaret eden olay nedir?","options":["Apollo 11''in Ay''a inmesi","Sovyetler Birliği''nin 1957''de Sputnik uydusunu fırlatması","NASA''nın kurulması","SpaceX''in ilk roket fırlatması"],"correctIndex":1},{"question":"Kaçış hızı ne anlama gelir?","options":["Roketin yakıt tüketim hızı","Atmosferde ses hızı","Yer çekimini yenebilmek için gerekli minimum hız","Uydunun yörüngede dolaşma hızı"],"correctIndex":2},{"question":"GPS sistemi nasıl çalışır?","options":["Kara istasyonlarından gönderilen sinyallerle","Uydu ağına dayalı bir konum belirleme sistemi olarak","Denizaltı kablolarıyla","Radyo dalgalarıyla"],"correctIndex":1},{"question":"Türkiye''nin uzay faaliyetlerini yürüten kurumlar hangileridir?","options":["ASELSAN ve ROKETSAN","TÜBİTAK UZAY ve Türkiye Uzay Ajansı","BTK ve RTÜK","TSK ve Milli Savunma Bakanlığı"],"correctIndex":1}]'::jsonb),
  ('bilim', 'Kara Delikler', $$Kara delikler, maddenin öylesine yoğun biçimde sıkıştığı gök cisimlerdir ki ışık bile onların çekim alanından kaçamaz. Bir yıldızın yakıtı tükenip iç basınç yerçekimini dengeleyemez hale geldiğinde yıldız kendi üzerine çöker; eğer yeterince kütleliyse bir kara deliğe dönüşür.

Karl Schwarzschild, 1916'da Einstein'ın genel görelilik denklemlerini kullanarak kara deliklerin matematiksel varlığını ortaya koydu. "Schwarzschild yarıçapı", bir nesnenin kara deliğe dönüşeceği kritik sıkışma yarıçapıdır. Güneş için bu değer yaklaşık 3 kilometre olup Güneş'in bu boyuta sıkışması halinde kara deliğe dönüşeceği anlamına gelir.

Olay ufku (event horizon), kara deliğin "sınırı" olarak bilinir; buradan ileriye geçen hiçbir şey geri dönemez. Olay ufkunun tam merkezine ise tekillik (singularity) denir; burada madde sonsuz yoğunluğa ulaşır ve bilinen fizik yasaları geçerliliğini yitirir.

Nisan 2019'da Olay Ufku Teleskobu (EHT) projesi, 55 milyon ışık yılı uzaklıktaki M87 galaksisinin merkezindeki kara deliğin ilk gerçek fotoğrafını çekti. Bu görüntü, Albert Einstein'ın genel görelilik teorisini bir kez daha doğruladı.$$, 168, 6, '{tyt,ayt}', '[{"question":"Kara delikler nasıl oluşur?","options":["Büyük gezegenlerin birleşmesiyle","Yıldızın yakıtı tükenip iç basınç yerçekimini dengeleyemez hale geldiğinde yıldızın kendi üzerine çökmesiyle","Galaksilerin çarpışmasıyla","Atom altı parçacıkların bir araya gelmesiyle"],"correctIndex":1},{"question":"Schwarzschild yarıçapı ne anlama gelir?","options":["Kara deliğin manyetik alanının sınırı","Işığın kara delikteki hızı","Bir nesnenin kara deliğe dönüşeceği kritik sıkışma yarıçapı","Kara deliğin olay ufku ile merkezi arasındaki mesafe"],"correctIndex":2},{"question":"Olay ufku (event horizon) nedir?","options":["Kara deliğin en yoğun noktası","Kara deliğin sınırı; buradan ileriye geçen hiçbir şeyin geri dönemediği alan","Kara deliğin çekiminin en zayıf olduğu bölge","Kara delik etrafında dönen yıldız halkası"],"correctIndex":1},{"question":"Bir kara deliğin ilk gerçek fotoğrafı ne zaman ve hangi proje tarafından çekildi?","options":["2010, Hubble Uzay Teleskobu","2019, Olay Ufku Teleskobu (EHT) projesi","2005, NASA Mars görevi","2023, James Webb Uzay Teleskobu"],"correctIndex":1}]'::jsonb),
  ('bilim', 'CRISPR Gen Düzenleme', $$CRISPR-Cas9, bilim insanlarının bir organizmanın DNA'sını hassas biçimde kesip düzenlemesine olanak tanıyan devrimsel bir gen teknolojisidir. "CRISPR" kısaltması, bakterilerin doğal bağışıklık sisteminden esinlenilmiş bir DNA dizisini ifade eder; "Cas9" ise bu dizide kesme işlemini gerçekleştiren enzimdir.

Sistemin çalışma prensibi basit ama etkilidir: Bilim insanları, hedef DNA dizisiyle tamamlayıcı bir "kılavuz RNA" tasarlar. Bu kılavuz RNA, Cas9 enzimini DNA üzerindeki doğru konuma yönlendirir ve enzim orayı keser. Ardından hücrenin kendi onarım mekanizması devreye girer; bu süreçte istenilen genetik değişiklik yapılabilir.

CRISPR'in potansiyel uygulama alanları son derece geniştir. Orak hücreli anemi ve hemofili gibi kalıtsal hastalıkların tedavisi, kanser immunoterapisi, hastalıklara dirençli tarım ürünleri ve biyoyakıt üretimi bunların başında gelir.

Bununla birlikte CRISPR etik tartışmaları da beraberinde getirmektedir. İnsan embriyolarında yapılan gen düzenlemeleri "tasarım bebek" kaygılarını gündeme taşımıştır. 2018'de Çinli bir bilim insanının CRISPR ile düzenlenmiş bebek doğurması tüm dünyada büyük bir etik krize neden olmuştu.

Bu teknoloji 2020 Nobel Kimya Ödülü'ne layık görülmüştür.$$, 165, 7, '{tyt,ayt}', '[{"question":"CRISPR-Cas9 teknolojisinde Cas9''un görevi nedir?","options":["DNA''yı kopyalamak","Hedef DNA dizisini kesmek","Hücreye ilaç taşımak","Protein sentezlemek"],"correctIndex":1},{"question":"CRISPR sisteminde \"kılavuz RNA\" ne işlev üstlenir?","options":["Kesiği onarmak","Yeni gen yazmak","Cas9 enzimini DNA üzerindeki doğru konuma yönlendirmek","Hücre zarını geçmek"],"correctIndex":2},{"question":"CRISPR teknolojisinin etik tartışmalarına neden olan uygulama nedir?","options":["Kanser immunoterapisi deneyleri","İnsan embriyolarında gen düzenleme ve \"tasarım bebek\" kaygıları","Hayvanlar üzerinde yapılan deneyler","Biyoyakıt üretimi"],"correctIndex":1},{"question":"CRISPR teknolojisi 2020 Nobel Ödülü''nü hangi kategoride kazanmıştır?","options":["Nobel Fiziği","Nobel Tıbbı","Nobel Kimya Ödülü","Nobel Barış Ödülü"],"correctIndex":2}]'::jsonb),
  ('bilim', 'İklim Değişikliği Bilimi', $$İklim değişikliği, Dünya'nın uzun vadeli iklim örüntülerindeki büyük ölçekli değişimleri ifade eder. Bilimsel kanıtlar, son yüzyıldaki hızlanmış ısınmanın büyük ölçüde insan faaliyetlerinden kaynaklandığını ortaya koymaktadır.

Sera etkisi, atmosferdeki bazı gazların güneşten gelen ısıyı tutarak Dünya'nın ısınmasını sağlamasıdır. Bu süreç doğal olarak gerçekleşir ve yaşamı mümkün kılar. Ancak sanayi devrimi sonrasında karbondioksit (CO₂), metan (CH₄) ve azot oksit gibi sera gazlarının atmosferdeki konsantrasyonu hızla artmıştır. Fosil yakıt kullanımı, ormansızlaşma ve hayvancılık bu artışın başlıca nedenleridir.

Atmosferdeki CO₂ oranı, sanayi öncesi dönemde 280 ppm iken bugün 420 ppm'nin üzerine çıkmıştır. Küresel ortalama sıcaklık son 150 yılda yaklaşık 1,2 derece artmıştır.

İklim değişikliğinin sonuçları arasında deniz seviyelerinin yükselmesi, aşırı hava olaylarının sıklaşması, buzulların erimesi ve biyoçeşitlilik kaybı sayılabilir. Türkiye de kuraklaşma, orman yangınları ve seller gibi etkilerle bu değişimi doğrudan hissetmektedir.

Paris Anlaşması (2015), küresel ısınmayı sanayi öncesi düzeylerin 1,5 derece üzerinde sınırlamayı hedefleyen uluslararası bir iklim çerçevesidir.$$, 167, 6, '{tyt,ayt}', '[{"question":"Sera etkisi doğal olarak nasıl işlev görür?","options":["Atmosferi soğutarak deniz seviyelerini düşürür","Atmosferdeki bazı gazların güneşten gelen ısıyı tutarak Dünya''nın ısınmasını sağlar","Güneş ışığını tamamen geri yansıtır","Ozon tabakasını korur"],"correctIndex":1},{"question":"Atmosferdeki CO₂ konsantrasyonu bugün hangi düzeye ulaşmıştır?","options":["280 ppm","350 ppm","420 ppm''nin üzeri","500 ppm"],"correctIndex":2},{"question":"İklim değişikliğinin sonuçları arasında sayılan olgular hangileridir?","options":["Kuraklık, orman yangınları, seller ve buzulların erimesi","Atmosfer basıncının artması ve ozon tabakasının onarılması","Güneş aktivitesinin azalması","Bitkilerin fotosentez hızının düşmesi"],"correctIndex":0},{"question":"Paris Anlaşması''nın hedefi nedir?","options":["Fosil yakıt kullanımını tamamen yasaklamak","Küresel ısınmayı sanayi öncesi düzeylerin 1,5 derece üzerinde sınırlamak","Tüm ülkelerin nükleer enerji kullanmasını sağlamak","Sera gazı emisyonunu sıfıra indirmek"],"correctIndex":1}]'::jsonb),
  ('bilim', 'Kuantum Fiziği Temelleri', $$Kuantum fiziği, atom ve atom altı parçacıkların davranışlarını inceleyen fizik dalıdır. Klasik fizikten köklü biçimde ayrılır; çünkü bu ölçekte parçacıklar sezgiyle çelişen özelliklere sahiptir.

Dalga-parçacık ikiliği, kuantum fiziğinin en temel kavramlarından biridir. Elektron gibi parçacıklar deney koşullarına bağlı olarak hem dalga hem de parçacık özelliği sergileyebilir. 1801'de gerçekleştirilen çift yarık deneyi bu ikiliği açıkça ortaya koymuştur.

Heisenberg Belirsizlik İlkesi ise bir parçacığın konum ve momentumunun aynı anda tam olarak bilinemeyeceğini öne sürer. Konumu daha hassas ölçmek, momentum belirsizliğini artırır; tersi de geçerlidir. Bu sınırlama ölçüm hatalarından değil, doğanın temel bir özelliğinden kaynaklanır.

Schrödinger'in kedisi ise kuantum süperpozisyonunu esprili bir düşünce deneyi ile açıklar: Kuantum sistemleri gözlemlenene kadar eş zamanlı olarak birden fazla durumda var olabilir.

Kuantum fiziği, lazerler, transistörler, MRI cihazları ve güneş pilleri gibi modern teknolojilerin temelini oluşturmaktadır. Kuantum dolanıklığı ise gelecekteki iletişim ve bilgisayar teknolojileri için devrimsel bir potansiyel barındırmaktadır.$$, 164, 7, '{tyt,ayt}', '[{"question":"Dalga-parçacık ikiliği ne anlama gelir?","options":["Bir parçacığın hem büyük hem küçük olabilmesi","Elektronun hem dalga hem de parçacık özelliği sergileyebilmesi","Işığın hem görünür hem görünmez olabilmesi","Maddenin hem katı hem de sıvı halde bulunabilmesi"],"correctIndex":1},{"question":"Heisenberg Belirsizlik İlkesi''ne göre ne mümkün değildir?","options":["Bir parçacığın kütlesini ölçmek","Bir parçacığın konum ve momentumunu aynı anda tam olarak bilmek","Bir parçacığın hızını ölçmek","Bir parçacığın elektrik yükünü belirlemek"],"correctIndex":1},{"question":"Belirsizlik ilkesindeki sınırlama neyin ürünüdür?","options":["Ölçüm araçlarının yetersizliği","Bilim insanlarının bilgi eksikliği","Doğanın temel bir özelliği","Laboratuvar koşullarındaki hatalar"],"correctIndex":2},{"question":"Kuantum fiziğinin temel aldığı günlük yaşam teknolojilerine örnek nedir?","options":["Buharlı makineler ve dizel motorlar","Lazerler, transistörler ve MRI cihazları","Teleskoplar ve mikroskoplar","Gübre ve ilaç sanayii"],"correctIndex":1}]'::jsonb),
  ('bilim', 'Evrenin Kökeni - Büyük Patlama', $$Büyük Patlama (Big Bang) teorisi, evrenin yaklaşık 13,8 milyar yıl önce sonsuz küçük ve sonsuz yoğun bir noktadan kaynaklandığını öne süren kozmoloji teorisidir. Evren, bu başlangıç noktasından itibaren genişlemeye devam etmektedir.

Büyük Patlama'dan sonraki ilk saniyenin milyarda birinde evren son derece yüksek enerjide plazma hâlindeydi. İlk üç dakikada hafif çekirdekler (hidrojen, helyum ve az miktarda lityum) oluştu. Yaklaşık 380.000 yıl sonra evren serinleyerek ilk atomlar belirdi ve ışık serbestçe yayılmaya başladı; bu olaya "yeniden birleşme" (recombination) denir.

Büyük Patlama'nın en güçlü kanıtlarından biri kozmik mikrodalga arka plan ışıması (CMB) dir. 1965'te Arno Penzias ve Robert Wilson tarafından tesadüfen keşfedilen bu ışıma, evrenin erken dönemine ait bir "ısı izi" niteliği taşır. Hubble'ın 1929'da galaksilerin birbirinden uzaklaştığını gözlemlemesi de evrenin genişlediğini kanıtlayan önemli bulgulardan biridir.

Karanlık madde ve karanlık enerji, evrenin kütlesinin ve enerjisinin yüzde 95'inden fazlasını oluşturduğu tahmin edilen, ancak henüz doğrudan gözlemlenemeyen gizemli bileşenlerdir. Bunlar modern kozmolojinin en büyük açık sorularındandır.$$, 169, 6, '{tyt,ayt}', '[{"question":"Büyük Patlama teorisine göre evren kaç yıl önce oluşmuştur?","options":["4,5 milyar yıl önce","7 milyar yıl önce","13,8 milyar yıl önce","20 milyar yıl önce"],"correctIndex":2},{"question":"Kozmik mikrodalga arka plan ışıması (CMB) ne anlama gelir?","options":["Güneş''ten gelen yüksek enerjili ışınım","Evrenin erken dönemine ait bir ısı izi niteliğinde olan arka plan ışıması","Galaksilerin birbirinden uzaklaşması","Karanlık enerjinin görünür biçimi"],"correctIndex":1},{"question":"Hubble''ın 1929''daki gözleminin önemi nedir?","options":["Karanlık maddeyi keşfetmesi","Güneş sisteminin yaşını hesaplaması","Galaksilerin birbirinden uzaklaştığını göstererek evrenin genişlediğini kanıtlaması","Kozmik arka plan ışımasını ölçmesi"],"correctIndex":2},{"question":"Karanlık madde ve karanlık enerji hakkında ne söylenebilir?","options":["Tamamen keşfedilmiş ve iyi anlaşılan bileşenlerdir","Evren kütlesinin yüzde 5''ini oluştururlar","Evren kütlesinin ve enerjisinin yüzde 95''inden fazlasını oluşturduğu tahmin edilen henüz doğrudan gözlemlenemeyen bileşenlerdir","Tamamen ışık emip yayan cisimlerdir"],"correctIndex":2}]'::jsonb),
  ('bilim', 'DNA ve Genetik', $$DNA (Deoksiribonükleik Asit), canlıların genetik bilgisini taşıyan moleküldür. 1953 yılında James Watson ve Francis Crick, Rosalind Franklin'in X-ışını verilerini de kullanarak DNA'nın çift sarmal yapısını açıkladılar.

DNA, dört farklı nükleotit bazından oluşur: Adenin (A), Timin (T), Guanin (G) ve Sitozin (C). Bu bazlar her zaman belirli çiftler halinde eşleşir: A ile T, G ile C. Bu kural "tamamlayıcı baz eşleşmesi" olarak bilinir. İnsan genomu yaklaşık 3 milyar baz çiftinden oluşur.

Protein sentezi, DNA'daki genetik bilginin iki aşamada hayata geçirilmesidir. Transkripsiyon aşamasında DNA'dan mRNA (haberci RNA) kopyalanır. Translasyon aşamasında ise ribozomlar mRNA'daki şifreyi okuyarak amino asitleri belirli bir sırayla birleştirir ve protein oluşturur.

Genetik mutasyonlar, DNA dizisindeki kalıcı değişikliklerdir. Bazı mutasyonlar zararsızken bazıları kanser gibi hastalıklara yol açabilir; öte yandan mutasyonlar evrimsel çeşitlenmenin de temel mekanizmasıdır.

İnsan Genomu Projesi 2003'te tamamlanarak tüm insan DNA dizisi haritaya dökülmüştür. Bu proje, kişiselleştirilmiş tıp ve genetik hastalıkların tedavisinde çığır açan bir kilometre taşıdır.$$, 166, 6, '{tyt,ayt}', '[{"question":"DNA''nın çift sarmal yapısını kimler açıklamıştır?","options":["Albert Einstein ve Niels Bohr","James Watson ve Francis Crick (Rosalind Franklin''in verileriyle)","Louis Pasteur ve Robert Koch","Gregor Mendel ve Charles Darwin"],"correctIndex":1},{"question":"Tamamlayıcı baz eşleşmesi kuralına göre Adenin hangi bazla eşleşir?","options":["Guanin","Sitozin","Timin","Uraasil"],"correctIndex":2},{"question":"Protein sentezinin \"translasyon\" aşamasında ne gerçekleşir?","options":["DNA''dan mRNA kopyalanır","Ribozomlar mRNA''daki şifreyi okuyarak amino asitleri birleştirir ve protein oluşturur","DNA çift sarmalı açılır","Hücre çekirdeği yeni DNA üretir"],"correctIndex":1},{"question":"İnsan Genomu Projesi ne zaman tamamlanmıştır ve önemi nedir?","options":["1990, ilk DNA izolasyonu için","2003, tüm insan DNA dizisinin haritaya dökülmesi için","2010, kanser genlerinin keşfi için","2015, CRISPR teknolojisinin geliştirilmesi için"],"correctIndex":1}]'::jsonb),
  ('bilim', 'Nörobilim: Beyin Nasıl Çalışır?', $$İnsan beyni, yaklaşık 86 milyar nörondan oluşan, bilinen en karmaşık yapıdır. Nörobilim, beynin ve sinir sisteminin yapısını, işlevini ve hastalıklarını inceleyen disiplinlerarası bir bilim dalıdır.

Nöron, sinir sisteminin temel işlevsel birimidir. Her nöron dendritler aracılığıyla diğer nöronlardan elektrik sinyalleri alır, bu sinyali hücre gövdesinde işler ve akson boyunca ilerletir. İki nöron arasındaki iletişim noktasına sinaps denir. Sinaptik iletimde serotonin, dopamin ve asetilkolin gibi kimyasal haberciler devreye girer; bunlara nörotransmitter adı verilir.

Beyin plastisitesi (nöroplastisite), beynin deneyimler, öğrenme ve yaralanma sonrasında yapısal ve işlevsel değişiklikler gösterme kapasitesidir. Bu özellik sayesinde beyin, hasardan sonra kendini yeniden organize ederek işlevleri kısmen ya da tamamen geri kazanabilir.

Prefrontal korteks karar verme ve planlama, hipokampüs bellek oluşturma, amigdala ise duygusal tepkiler ve korku ile ilişkilidir.

Bilinç ve öznel deneyim gibi konular nörobilimin henüz yanıtlayamadığı "zor sorular" arasındadır. Alzheimer ve Parkinson gibi nörodejeneratif hastalıklar ise dünya genelinde milyonlarca insanı etkilemekte ve yoğun araştırmalara konu olmaktadır.$$, 163, 7, '{tyt,ayt}', '[{"question":"Sinaps ne anlama gelir?","options":["Nöronun ürettiği enerji birimi","İki nöron arasındaki iletişim noktası","Beyindeki bellek deposu","Aksonun uç kısmı"],"correctIndex":1},{"question":"Nörotransmitter nedir?","options":["Nöronların elektrik ürettiği organel","Sinaptik iletimde görev alan serotonin, dopamin gibi kimyasal haberciler","Beyin zarını koruyan sıvı","Nöronları besleyen kan damarları"],"correctIndex":1},{"question":"Beyin plastisitesi (nöroplastisite) ne anlama gelir?","options":["Beynin plastik madde içermesi","Beynin sabit ve değişmez olması","Beynin deneyim ve yaralanma sonrasında yapısal ve işlevsel değişiklikler gösterme kapasitesi","Beynin yalnızca çocukluk döneminde gelişmesi"],"correctIndex":2},{"question":"Hipokampüs beynin hangi işleviyle ilişkilidir?","options":["Korku ve duygusal tepkiler","Dil ve konuşma","Bellek oluşturma","Karar verme ve planlama"],"correctIndex":2}]'::jsonb),
  ('bilim', 'Biyomimikri: Doğadan İlham Alma', $$Biyomimikri, doğanın milyonlarca yıllık evrimsel çözümlerini model alarak teknoloji ve tasarım sorunlarını çözme yaklaşımıdır. "Bios" (yaşam) ve "mimesis" (taklit) sözcüklerinden türetilmiştir. Bu yaklaşım, doğanın en verimli ve sürdürülebilir tasarım mühendisi olduğu fikrine dayanır.

Velcro (cırt-cırt), biyomimikriyle geliştirilen ürünlerin en bilinen örneğidir. İsviçreli mühendis George de Mestral, 1948'de köpeğinin tüylerine yapışan kaçık tohumlarını incelemiş ve bunların kancalı yapısından ilham alarak Velcro'yu icat etmiştir.

Japonya'daki Shinkansen (kurşun treni) tasarımında da biyomimikri belirleyici rol oynamıştır. Tünelden çıkan trenin yarattığı boom sesi çevre sakinlerini rahatsız ediyordu. Mühendis Eiji Nakatsu, balıkçıl kuşunun su içine dalarken neredeyse ses çıkarmayan sivri gagasından ilham alarak trenin burnunu yeniden tasarlamış; hem gürültü sorununu çözmüş hem de yakıt verimliliğini artırmıştır.

Lotus etkisi ise lotus çiçeğinin yapraklarının kendi kendini temizlemesini sağlayan nano ölçekli yüzey yapısının teknolojiye aktarılmasıdır. Boya, tekstil ve cam sanayiinde bu prensipten yararlanan ürünler üretilmektedir.

Biyomimikri, iklim krizi çağında malzeme biliminden mimariye kadar pek çok alanda sürdürülebilir çözümler sunmaktadır.$$, 162, 6, '{tyt,ayt}', '[{"question":"Biyomimikri kavramı nasıl tanımlanır?","options":["Biyoloji ve kimyanın birleştirilmesi","Doğanın evrimsel çözümlerini model alarak teknoloji sorunlarını çözme yaklaşımı","Canlıları klonlama yöntemi","Bitkilerden ilaç üretme süreci"],"correctIndex":1},{"question":"Velcro (cırt-cırt) hangi doğal yapıdan ilham alınarak geliştirilmiştir?","options":["Lotus çiçeğinin yaprak yüzeyinden","Yılanın pul yapısından","Kaçık tohumlarının kancalı yapısından","Balıkçıl kuşunun gagasından"],"correctIndex":2},{"question":"Japonya Shinkansen treninin burnunun yeniden tasarlanmasında hangi canlı örnek alınmıştır?","options":["Köpekbalığı yüzgeci","Lotus çiçeği yaprakları","Kaçık tohumları","Balıkçıl kuşunun gagası"],"correctIndex":3},{"question":"Lotus etkisi hangi alanlarda ürün geliştirmede kullanılmaktadır?","options":["Uzay araçları ve roketler","Boya, tekstil ve cam sanayii","Elektrik üretimi ve depolama","İlaç ve biyoteknoloji"],"correctIndex":1}]'::jsonb),
  ('bilim', 'Hawking Işıması ve Kara Delikler', $$Stephen Hawking, 1974'te kara deliklerin mutlak kara olmadığını, aksine yavaş yavaş enerji yaydığını öne sürdü. Bu fenomen "Hawking ışıması" olarak adlandırıldı ve modern fiziğin en çarpıcı teorik bulgularından biri sayıldı.

Hawking ışıması, kuantum mekanik etkilerinden kaynaklanır. Kuantum teorisine göre boşluk gerçekten boş değildir; sanal parçacık-antiparçacık çiftleri anlık olarak oluşup yok olmaktadır. Olay ufku yakınında bu çiftlerden biri kara deliğe düşerken diğeri kaçabilir; kaçan parçacık gerçek enerji olarak gözlemlenir. Bu süreç, kara deliğin yavaş yavaş kütle ve enerji kaybetmesine yol açar.

Teorik olarak kara delikler Hawking ışıması yoluyla zamanla küçülerek "buharlaşabilir". Ancak bu süreç için gereken zaman, evrenin şimdiki yaşından çok daha uzundur; dolayısıyla günümüzde var olan hiçbir kara delik henüz buharlaşmamıştır.

Hawking ışıması, genel görelilik teorisi ile kuantum mekaniğini birleştirme çabasının en önemli adımlarından biridir. Bu iki büyük teori birbirleriyle çelişmekte olup birleşik bir "her şeyin teorisi" oluşturmak, teorik fiziğin en büyük açık problemi olmaya devam etmektedir.

Hawking ışıması henüz gözlemsel olarak doğrulanamamıştır; teorik olarak tahmin edilen bu ışımanın tespiti için son derece hassas araçlar gerekmektedir.$$, 164, 7, '{tyt,ayt}', '[{"question":"Hawking ışıması hangi temelden kaynaklanmaktadır?","options":["Kara deliğin içindeki yıldız parçalarından","Olay ufku yakınındaki kuantum mekanik etkilerinden","Kara deliğin manyetik alanından","Kara deliğin çevresindeki gazlardan"],"correctIndex":1},{"question":"Hawking ışımasının kara deliğe etkisi nedir?","options":["Kara deliğin büyümesine neden olur","Kara deliği daha yoğun hale getirir","Kara deliğin zamanla kütle ve enerji kaybederek buharlaşmasına yol açar","Kara deliğin etrafındaki yıldızları yok eder"],"correctIndex":2},{"question":"Hawking ışıması neden henüz gözlemsel olarak doğrulanamamıştır?","options":["Kara delikler çok uzakta olduğu için","Teorik olarak tahmin edilen bu ışımanın tespiti için son derece hassas araçlar gerektiğinden","Hawking ışımasının yalnızca kuramsal olduğu kanıtlandığı için","Gözlem yapacak teleskopların olmadığı için"],"correctIndex":1},{"question":"Hawking ışıması hangi iki büyük teoriyi birleştirmeye çalışmaktadır?","options":["Evrim teorisi ve genetik","Klasik mekanik ve elektromanyetizma","Genel görelilik teorisi ve kuantum mekaniği","Termodinamik ve atom teorisi"],"correctIndex":2}]'::jsonb),
  ('bilim', 'Mars Keşfi ve Yaşam Arayışı', $$Mars, Dünya'ya en yakın ve yaşam barındırma potansiyeli açısından en çok incelenen gezegendir. Kızıl gezegenin yüzeyi demir oksit (pas) ile kaplı olduğundan kırmızımsı görünür. Zayıf bir manyetik alana sahip olan Mars'ın ince atmosferi büyük ölçüde karbondioksit (CO₂) içerir.

NASA'nın Perseverance rover aracı, Şubat 2021'de Mars'a iniş yaparak Jezero Krateri'ni incelemeye başladı. Bu krater, milyarlarca yıl önce bir göl tabanıydı. Perseverance, Mars toprağından kayaç örnekleri topladı; bu örneklerin gelecekteki bir görevle Dünya'ya getirilmesi planlanmaktadır.

Mars'ta geçmişte sıvı suyun var olduğuna dair güçlü kanıtlar mevcuttur. Eski nehir yatakları, delta oluşumları ve mineraller bunu desteklemektedir. Perseverance'ın MOXIE deneyi ise Mars atmosferindeki CO₂'yi oksijene dönüştürmeyi başararak gelecekteki insanlı görevler için umut verici bir kanıt ortaya koydu.

Metan gazının varlığı da merak uyandırmaktadır. Metan, biyolojik kaynaklı olabileceği gibi jeolojik kökenli de olabilir; bu soruyu yanıtlamak Mars'taki yaşam arayışında kritik önem taşır.

Terraforming, Mars'ın atmosferini ve iklimini insanların yaşayabileceği biçimde dönüştürme fikrinin adıdır. Elon Musk liderliğindeki SpaceX, 2030'lu yıllarda Mars'a insanlı görev planlarken bilim insanları terraforming'in teknik ve etik boyutlarını tartışmaktadır.$$, 167, 6, '{tyt,ayt}', '[{"question":"NASA''nın Perseverance rover aracı Mars''a ne zaman indi?","options":["Ocak 2020","Şubat 2021","Mart 2022","Aralık 2019"],"correctIndex":1},{"question":"Perseverance''ın MOXIE deneyi nedir?","options":["Mars''ta metan gazını tespit etmek","Mars atmosferindeki CO₂''yi oksijene dönüştürmek","Mars yüzeyindeki suyu bulmak","Eski yaşam fosillerini taramak"],"correctIndex":1},{"question":"Mars''ta geçmişte sıvı suyun var olduğuna işaret eden kanıtlar nelerdir?","options":["Kutuplardaki buz tabakası","Eski nehir yatakları, delta oluşumları ve mineraller","Yüksek atmosfer basıncı","Metan gazının varlığı"],"correctIndex":1},{"question":"Terraforming kavramı ne anlama gelir?","options":["Mars yüzeyinde mineral arama","Mars''taki robotik araçları kontrol etme","Mars''ın atmosferini ve iklimini insanların yaşayabileceği biçimde dönüştürme","Mars''ın yüzeyini haritalama"],"correctIndex":2}]'::jsonb),
  ('felsefe', 'Felsefenin Tanımı ve Temel Soruları', $$Felsefe, Yunanca "philosophia" sözcüğünden gelir; "sophia" bilgelik, "philos" ise sevgi anlamına taşır. Dolayısıyla felsefe, bilgelik sevgisi ya da bilgeliği arama çabası olarak tanımlanabilir. İnsan varoluşunun anlam arayışını dile getiren bu disiplin, binlerce yıllık bir düşünce geleneğine dayanır.

Felsefenin başlıca alt dalları şunlardır: ontoloji (varlık felsefesi), epistemoloji (bilgi felsefesi), etik (ahlak felsefesi), estetik (güzellik felsefesi) ve mantık. Ontoloji "Var olan nedir?" diye sorarken epistemoloji "Bilgi mümkün müdür, kaynağı nedir?" diye sorar. Etik ise "Nasıl yaşamalıyım?" sorusunun peşindedir.

Felsefe, bilimden farklı olarak deney yoluyla değil; akıl yürütme, sorgulama ve kavramsal çözümleme yoluyla ilerler. Bu nedenle felsefi sorular kesin bir yanıta kavuşmaktan çok, düşünmeyi derinleştirmeyi ve yeni bakış açıları kazandırmayı amaçlar. Bir soru yanıtlanır yanıtlanmaz daha derin sorular doğar.

TYT ve AYT sınavlarında felsefe sorularının temelini bu alt dallar ve onların temel kavramları oluşturur. Felsefeye giriş yaparken hangi sorunun hangi alt dala ait olduğunu bilmek büyük kolaylık sağlar. Kavramları doğru sınıflandırmak sınavda puan kazanmanın ilk adımıdır.$$, 165, 6, '{tyt,ayt}', '[{"question":"\"Philosophia\" kelimesinin Türkçe anlamı nedir?","options":["Doğa bilimi","Bilgelik sevgisi","Mantık kuralları","Ahlak araştırması"],"correctIndex":1},{"question":"Epistemoloji hangi temel soruyu araştırır?","options":["Var olan nedir?","Güzel olan nedir?","Bilgi mümkün müdür ve kaynağı nedir?","İyi olan nedir?"],"correctIndex":2},{"question":"Felsefeyi bilimden ayıran temel özellik nedir?","options":["Felsefe yalnızca tarihsel konularla ilgilenir","Felsefe deney yerine akıl yürütme ve kavramsal çözümleme kullanır","Felsefe kesin yanıtlar üretir, bilim üretemez","Felsefe sayısal verilerle çalışır"],"correctIndex":1},{"question":"Ontoloji hangi soruyu araştırır?","options":["Bilgi nasıl edinilir?","Güzellik nedir?","Var olan nedir?","Ahlaki eylem nasıl tanımlanır?"],"correctIndex":2}]'::jsonb),
  ('felsefe', 'Sokrates ve Sokratik Yöntem', $$Sokrates (MÖ 470-399), Batı felsefesinin temel taşlarından biri olarak kabul edilir. Kendisinden önceki filozoflar doğayı açıklamaya çalışırken Sokrates, ilgiyi insanın kendisine, ahlaka ve iyi yaşama yöneltti. Ona atfedilen "Kendini tanı!" ilkesi, bu yönelişin simgesidir ve Delfi Tapınağı'nın giriş kapısına kazılıdır.

Sokrates hiçbir eser kaleme almadı; düşüncelerini diyalog yoluyla aktardı. Geliştirdiği yönteme maieutik (ebelik) yöntemi denir. Tıpkı bir ebenin doğuma yardım etmesi gibi Sokrates de muhataplarının zihnindeki bilgiyi ardı ardına sorduğu sorularla gün yüzüne çıkardı. Yöntem, "elenkhos" adı verilen çürütme tekniğiyle de desteklenirdi.

Sokratik ironi ise bilmediğini bilmek anlamına gelir. Sokrates, "Tek bildiğim, hiçbir şey bilmediğimdir." diyerek bilgeliğin gerçek başlangıcının cehaleti fark etmekten geçtiğini savundu. Bu yaklaşım, Atinalı devlet adamlarının ve sofistlerin sandıkları kadar bilgili olmadıklarını açıkça ortaya koydu.

Sokrates, gençleri ahlaki yoldan saptırmakla ve sahte tanrılara inanmakla suçlandı. İnançlarından vazgeçmeyeceği için MÖ 399 yılında baldıran zehri içirilerek idam edildi. Öğrencisi Platon bu son anları "Phaidon" adlı diyalogda kaleme aldı. Sokrates'in ölüme duyarsız kalışı ve inançlarından taviz vermemesi, felsefe tarihinin en etkileyici sahnelerinden biri olarak yüzyıllar boyunca tartışılmaya devam etti.$$, 168, 6, '{tyt,ayt}', '[{"question":"Sokrates''in \"maieutik yöntem\" olarak adlandırılan tekniği neye benzetilir?","options":["Bir öğretmenin ders anlatmasına","Bir ebenin doğuma yardım etmesine","Bir bilim insanının deney yapmasına","Bir sanatçının eser üretmesine"],"correctIndex":1},{"question":"\"Tek bildiğim, hiçbir şey bilmediğimdir.\" ifadesi neyi simgeler?","options":["Sokrates''in bilgiden kaçınması gerektiğini düşündüğünü","Bilgeliğin cehaleti fark etmekle başladığını","Bilginin imkânsız olduğunu","Sokrates''in eğitim almadığını"],"correctIndex":1},{"question":"Sokrates''ten önceki filozofların temel ilgi alanı neydi?","options":["Ahlak ve iyi yaşam","Siyaset ve demokrasi","Doğayı açıklamak","Matematik ve geometri"],"correctIndex":2},{"question":"Sokrates neden idam edildi?","options":["Devlete ihanet ettiği için","İnançlarından vazgeçmeyi reddettiği için","Öğrencilerine yanlış bilgi verdiği için","Siyasi iktidarı ele geçirmeye çalıştığı için"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Platon: İdealar Kuramı ve Mağara Alegorisi', $$Platon (MÖ 428-348), Sokrates'in öğrencisi ve Aristoteles'in hocasıdır. Atina'da kurduğu Akademi, Batı tarihinin ilk yüksek öğretim kurumu sayılır. Platon'un felsefesinin merkezinde idealar kuramı yer alır. Bu kurama göre gözlemlediğimiz nesneler geçici ve kusurludur; gerçek varlıklar ise mükemmel, değişmez ve sonsuz olan idealardır. Örneğin gördüğümüz her güzel nesne, mükemmel "Güzellik İdeasının" soluk bir yansımasıdır.

Mağara alegorisi bu kuramı somutlaştıran en ünlü felsefi imgedir. Platon, zincirli insanların duvardaki gölgelerden gerçeği anlamaya çalıştığı karanlık bir mağara tasvir eder. Dışarı çıkıp güneşi gören kişi gerçek bilgiye ulaşmış filozofu temsil eder. Gölgeler duyu dünyasının yanıltıcı görüntülerini; güneş ise en yüce idea olan "İyilik İdeasını" simgeler.

Platon epistemolojik açıdan da belirleyici bir isimdir: duyulardan gelen bilgi sanı (doxa) iken akıl yoluyla kavranılan bilgi gerçek bilgi (episteme) sayılır. Bu ayrım, rasyonalist geleneğin temelini atmıştır. Platon ayrıca ideal devletin filozoflar tarafından yönetilmesi gerektiğini savunmuş; bu görüşünü "Devlet" adlı eserinde ayrıntıyla işlemiştir. Platon'un felsefesi Batı düşüncesini o denli derinden etkilemiştir ki 20. yüzyıl filozofu Alfred North Whitehead, tüm Batı felsefesini Platon'a düşülen dipnotlar olarak tanımlamıştır.$$, 172, 7, '{tyt,ayt}', '[{"question":"Platon''un idealar kuramına göre gözlemlediğimiz nesneler nasıl tanımlanır?","options":["Gerçek ve mükemmel varlıklardır","Geçici ve kusurlu, ideaların yansımalarıdır","Tanrısal yaratılışın ürünleridir","Akıl yoluyla kavranabilen özlerdir"],"correctIndex":1},{"question":"Mağara alegorisinde güneş neyi simgeler?","options":["Duyusal dünyayı","Yanıltıcı gölgeleri","En yüce idea olan İyilik İdeasını","Zincirli insanların cahilliğini"],"correctIndex":2},{"question":"Platon''a göre \"doxa\" ne anlama gelir?","options":["Akıl yoluyla elde edilen gerçek bilgi","Duyulardan gelen sanı (yanıltıcı görüş)","İdeaların mükemmel formu","Filozofun kavradığı evrensel hakikat"],"correctIndex":1},{"question":"Platon''un ideal devletinde yönetimi kim üstlenmelidir?","options":["Askerler","Zenginler","Filozoflar","Din adamları"],"correctIndex":2}]'::jsonb),
  ('felsefe', 'Aristoteles: Mantık ve Kategoriler', $$Aristoteles (MÖ 384-322), Antik Yunan'ın en kapsamlı düşünürüdür; biyolojiden siyasete, fiziğten etik anlayışına kadar pek çok alanı sistematize etmiştir. Platon'un öğrencisi olan Aristoteles, idealar kuramını reddederek gerçekliğin somut nesnelerde bulunduğunu savundu. En kalıcı katkılarından biri mantık alanındadır. Aristoteles, geçerli akıl yürütmenin biçimini inceleyen mantığı bir "organon" (araç) olarak kuramsallaştırdı.

Aristoteles'in mantık sisteminin temeli kıyastır (syllogism). Kıyas, iki öncül ve bir sonuçtan oluşan bir akıl yürütme biçimidir. Klasik örnek: "Bütün insanlar ölümlüdür; Sokrates insandır; o hâlde Sokrates ölümlüdür." Öncüller doğruysa ve yapı geçerliyse sonuç zorunlu olarak doğrudur. Bu biçimsel çıkarım sistemi, çağlar boyu mantık eğitiminin temeli olmuştur.

Kategoriler öğretisinde Aristoteles, varlıkları on temel sınıfa ayırır: töz, nicelik, nitelik, bağıntı, yer, zaman, durum, iyelik, etki ve edilgi. Bunların en temel olanı tözdür (substans); diğerleri ona atfedilen ilineklerdir (accidents). Aristoteles bu çalışmalarıyla Orta Çağ İslam ve Hristiyan skolastiğini derinden etkiledi; felsefe tarihinde "Birinci Öğretmen" unvanıyla anıldı. İslam dünyasında İbn Rüşd gibi düşünürler Aristoteles'i yeniden yorumladı; bu şerh geleneği Avrupa Üniversitelerine taşınarak Ortaçağ aklî geleneğini biçimlendirdi. Aristoteles'in eserleri bugün hâlâ felsefe ve mantık eğitiminin temel kaynakları arasındadır.$$, 170, 6, '{tyt,ayt}', '[{"question":"Aristoteles mantığı hangi işlev için kuramsallaştırdı?","options":["Matematiksel hesaplama yapmak için","Geçerli akıl yürütmenin biçimini incelemek için","Doğa olaylarını gözlemlemek için","Ahlaki erdemleri sıralamak için"],"correctIndex":1},{"question":"Aristoteles''in kıyas (syllogism) yapısı nelerden oluşur?","options":["Üç öncül ve iki sonuç","Bir öncül ve bir sonuç","İki öncül ve bir sonuç","Üç sonuç ve bir öncül"],"correctIndex":2},{"question":"Aristoteles''in kategoriler öğretisinde en temel kategori hangisidir?","options":["Nicelik","Nitelik","Töz (substans)","Bağıntı"],"correctIndex":2},{"question":"Aristoteles felsefe tarihinde hangi unvanla anılır?","options":["İkinci Öğretmen","Birinci Öğretmen","Bilgelik Babası","Mantık Kurucusu"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Descartes: Cogito Ergo Sum ve Metodolojik Şüphecilik', $$René Descartes (1596-1650), modern felsefenin kurucusu olarak kabul edilir. Matematik ve geometri alanındaki derin birikimi, onu kesin ve güvenilir bir bilgi sistemi kurmaya yöneltti. Descartes, kesin bilgiye ulaşmak amacıyla metodolojik şüpheciliği bir araç olarak kullandı. Yöntemsel şüphe, her şeyin doğruluğundan geçici olarak şüphe duyarak yalnızca şüphe edilemeyen şeyleri temel almak demektir.

Descartes duyuların yanıltabileceğini, rüyalarla gerçeği karıştırabileceğimizi ve hatta kötü bir cinni tarafından aldatılıyor olabileceğimizi varsaydı. Bu radikal şüphe sürecinde şunu fark etti: şüphe eden bir varlığın var olması zorunludur. Bu keşfini Latince "Cogito ergo sum" (Düşünüyorum, öyleyse varım) olarak ifade etti.

Cogito, Descartes için şüphe götürmez ilk kesindir. Buradan hareketle Tanrı'nın varlığını ve dış dünyanın gerçekliğini de akıl yoluyla ispat etmeye girişti. Descartes'ın felsefesi zihin-beden ikiliğine (düalizm) dayanır: zihin ve beden iki ayrı, birbirinden bağımsız tözdür. Zihin düşünen (res cogitans), beden ise uzamlı (res extensa) tözdür. Bu ikicilik, Batı felsefesinde uzun soluklu tartışmalara zemin hazırladı. Spinoza ve Leibniz gibi rasyonalistler Descartes'ın mirasını kendi sistemleriyle genişletirken empiristler tam karşı yönde bir yola saparak onun temel varsayımlarını sorguladı.$$, 167, 7, '{tyt,ayt}', '[{"question":"Descartes''ın metodolojik şüpheden ulaştığı ilk kesin bilgi nedir?","options":["Tanrı''nın var olduğu","Dış dünyanın gerçek olduğu","Düşünen bir varlık olarak var olduğu (Cogito ergo sum)","Duyuların güvenilir olduğu"],"correctIndex":2},{"question":"Descartes''ın yöntemsel şüpheciliğinin amacı nedir?","options":["Her şeyin boş olduğunu kanıtlamak","Kesin bilgiye ulaşmak için şüphe edilemeyen temeli bulmak","Dini inançları reddetmek","Duyuların üstünlüğünü savunmak"],"correctIndex":1},{"question":"Descartes''ın zihin-beden ikiliği (düalizm) neyi savunur?","options":["Zihin ve beden aynı tözdür","Sadece zihin gerçektir, beden hayaldir","Zihin ve beden iki ayrı tözdür","Beden zihinden üstündür"],"correctIndex":2},{"question":"\"Cogito ergo sum\" Türkçeye nasıl çevrilir?","options":["Varım, öyleyse düşünüyorum","Düşünüyorum, öyleyse varım","Şüphe ediyorum, öyleyse biliyorum","Biliyorum, öyleyse düşünüyorum"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Kant: Saf Aklın Eleştirisi ve A Priori Bilgi', $$Immanuel Kant (1724-1804), rasyonalizm ile empirizmi uzlaştırmaya çalışan "eleştirel felsefe" geleneğinin kurucusudur. Hume'un şüpheciliğinin onu "dogmatik uykusundan" uyandırdığını söyleyen Kant, başyapıtı "Saf Aklın Eleştirisi"nde (1781) insan zihninin neleri bilebileceğinin sınırlarını titizlikle araştırdı.

Kant'a göre iki tür bilgi vardır: a priori bilgi ve a posteriori bilgi. A priori bilgi deneyimden bağımsız, önceden zihnimizde bulunan evrensel ve zorunlu bilgidir; matematiksel ve mantıksal önermeler bu türdendir. A posteriori bilgi ise deneyim ve duyular aracılığıyla sonradan kazanılan bilgidir. Kant ayrıca "sentetik a priori" adını verdiği üçüncü bir kategori belirledi.

Kant, zihnin pasif bir alıcı olmadığını savundu. Aksine zihin, zaman, uzay ve nedensellik gibi a priori kategoriler aracılığıyla ham duyum verilerini aktif biçimde biçimlendirir. Bu yaklaşım "Kopernik devrimi" olarak adlandırılır: bilgi nesneye değil, nesne bilgimizin koşullarına uyar. Dolayısıyla "kendinde şey" (Ding an sich) bilinemezdir; biz yalnızca deneyimlerimizin biçimlendirdiği görüngüleri tanıyabiliriz. Kant'ın etik anlayışında ise ahlakın temeli koşulsuz ödev bilincine dayanan kategorik buyruktur. Bu ilkeler TYT ve AYT sınavlarında doğrudan soru olarak karşıma çıkar.$$, 171, 7, '{tyt,ayt}', '[{"question":"Kant''a göre \"a priori bilgi\" nasıl tanımlanır?","options":["Deneyimden sonra kazanılan bilgi","Duyular aracılığıyla gelen bilgi","Deneyimden bağımsız, önceden zihnimizde bulunan evrensel bilgi","Deney ve gözlemle doğrulanan bilgi"],"correctIndex":2},{"question":"Kant''ın bilgi anlayışında \"Kopernik devrimi\" ne anlama gelir?","options":["Bilgi nesneye uyar","Nesne bilgimizin koşullarına uyar","Deneyim bilginin tek kaynağıdır","Zihin pasif bir alıcıdır"],"correctIndex":1},{"question":"Kant''ın \"kategorik buyruk\" ilkesi neyi savunur?","options":["Fayda maksimizasyonuna dayalı ahlakı","Duyguya dayalı ahlaki kararları","Koşulsuz, evrensel ve ödev bilincine dayalı ahlaki eylemi","Sonuçlara göre değerlendirilen ahlakı"],"correctIndex":2},{"question":"\"Saf Aklın Eleştirisi\" hangi temel soruyu araştırır?","options":["Tanrı''nın varlığı kanıtlanabilir mi?","İnsan zihninin neleri bilebileceğinin sınırları nelerdir?","Ahlaki eylem nasıl tanımlanır?","Toplumun ideal yönetim biçimi nedir?"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Nietzsche: Güç İstenci ve Üstinsan', $$Friedrich Nietzsche (1844-1900), Batı felsefesinin en sarsıcı düşünürlerinden biridir. Filolog kökenli olan Nietzsche, döneminin ahlak anlayışına, Hristiyanlığa ve Aydınlanma ideallerine sert eleştiriler yöneltti. En çarpıcı ifadelerinden biri "Tanrı öldü!" cümlesidir; bu, tanrısal bir otoritenin yok olmasından çok metafizik temellerin çöküşünü ve nihilizm tehlikesini simgeler.

Nihilizm, değerlerin anlamsızlaştığı, yaşamın amacını yitirdiği derin bunalım hâlidir. Nietzsche nihilizmi pasif bir çöküş olarak değil, aşılması gereken bir eşik olarak gördü. Nihilizmi aşmak için güç istenci (Wille zur Macht) kavramını geliştirdi. Güç istenci, salt egemenlik kurma arzusu değil; varoluşu anlam, yaratıcılık ve büyüme yönünde dönüştüren derin içsel güçtür.

Nietzsche'nin ideal insan tipi üstinsandır (Übermensch). Üstinsan, toplumun empoze ettiği köle ahlakından ve dinî buyruklardan bağımsız olarak kendi değerlerini özgürce yaratan kişidir. Efendi ahlakı yaşamı ve gücü olumlarken köle ahlakı kıskançlık ve zayıflıktan türer. Ebedi dönüş düşüncesi ise kişiyi her seçiminin sonsuza dek tekrarlanacakmış gibi yaşamaya davet eder. Nietzsche'nin fikirleri 20. yüzyılda varoluşçuluk ve postmodernizm başta olmak üzere pek çok felsefi akımı derinden etkiledi. Siyasi ideolojiler tarafından çarpıtılarak kullanılmış olsa da Nietzsche'nin gerçek amacı insanı yaratıcılığa ve anlam üretmeye yönlendirmekti.$$, 169, 7, '{tyt,ayt}', '[{"question":"Nietzsche''nin \"Tanrı öldü!\" ifadesi neyi simgeler?","options":["Ateizmin bilimsel kanıtını","Metafizik temellerin çöküşünü ve nihilizm tehlikesini","Dinin toplumsal gücünü yitirdiğini","Hristiyanlığın tarihsel bir hatayı düzelttiğini"],"correctIndex":1},{"question":"Nietzsche''ye göre güç istenci (Wille zur Macht) nasıl tanımlanır?","options":["Diğerlerine fiziksel üstünlük kurma arzusu","Varoluşu anlam, yaratıcılık ve büyüme yönünde dönüştüren içsel güç","Toplumsal normlara boyun eğme","Zenginlik ve maddi güce ulaşma isteği"],"correctIndex":1},{"question":"Nietzsche''nin \"üstinsan\" (Übermensch) kavramı kimi tanımlar?","options":["Toplumun dayattığı değerlere körü körüne uyan kişiyi","Bilimsel zeka açısından üstün olan bireyi","Kendi değerlerini yaratan, köle ahlakından bağımsız kişiyi","Devleti yöneten güçlü lideri"],"correctIndex":2},{"question":"Nietzsche''ye göre nihilizm nedir?","options":["Tüm değerlerin mükemmelleştiği hâl","Değerlerin anlamsızlaştığı ve yaşamın amacını yitirdiği bunalım","Güç istencininin doruğa ulaşması","Üstinsanın eriştiği ahlaki olgunluk"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Varoluşçuluk: Sartre ve Özgürlük', $$Varoluşçuluk, 20. yüzyılda özellikle iki dünya savaşı arasındaki varoluşsal bunalım ortamında gelişen felsefi bir akımdır. Kierkegaard ve Heidegger'in hazırladığı zemin üzerinde şekillenen bu akımın en önde gelen temsilcisi Jean-Paul Sartre'dır (1905-1980). Sartre'ın felsefesinin çıkış noktası "varoluş özden önce gelir" devrimci ilkesidir.

Geleneksel felsefede nesnelerin önce özü (amacı, doğası) belirlenir, sonra varoluşa kavuşur. Bir bıçak, işlevi belirlendikten sonra yapılır. Sartre'a göre insanda bu sıra tersine çevrilmiştir: insan önce varolur, ardından seçimleriyle kendini tanımlar. Yani insan, doğuştan hazır bir öze sahip değildir.

Bu durum radikal bir özgürlük anlamına gelir. Ancak Sartre bu özgürlüğü yük olarak da tanımlar: insan seçmekten kaçamaz; kaçınmak da bir seçimdir. Her seçimin sorumluluğu kişinin üzerindedir. Sartre bu kaçınma tutumunu "kötü niyet" (mauvaise foi) olarak adlandırır. Varoluşçuluğun önemli kavramları arasında kaygı, bulantı ve ötekiyle ilişki de yer alır. "Cehennem başkalarıdır." sözü, ötekinin bakışının özgürlüğümüzü nasıl kısıtladığını özetler. Simone de Beauvoir ise varoluşçuluğu feminist perspektifle buluşturarak toplumsal cinsiyet baskısının özgürlüğü nasıl engellediğini gösterdi. Varoluşçuluk bugün psikoloji, edebiyat ve siyaset felsefesinde etkisini sürdürmektedir.$$, 166, 7, '{tyt,ayt}', '[{"question":"Sartre''ın \"varoluş özden önce gelir\" ilkesi ne anlama gelir?","options":["İnsan doğuştan belirlenmiş bir özle gelir","İnsan önce varolur, ne olduğunu seçimleriyle belirler","Varlık, değerlerden önce anlam kazanır","Öz, varoluşu mümkün kılar"],"correctIndex":1},{"question":"Sartre''a göre \"kötü niyet\" (mauvaise foi) ne anlama gelir?","options":["Başkalarına zarar verme niyeti taşımak","Özgürlüğü ve sorumluluğu inkâr ederek seçimden kaçmak","Ahlaki değerlere aykırı davranmak","Varoluşçu felsefeyi reddetmek"],"correctIndex":1},{"question":"\"Cehennem başkalarıdır.\" sözü ne anlama gelir?","options":["Toplumdan uzak yaşamak gerekir","Ötekinin bakışı özgürlüğümüzü kısıtlar","Cehennem kavramı gerçek değildir","İnsan yalnız yaşamalıdır"],"correctIndex":1},{"question":"Varoluşçuluğa göre insan özgürlüğü nasıl tanımlanır?","options":["Toplumun izin verdiği ölçüde sınırlıdır","Tanrı tarafından belirlenmiştir","Radikaldir; seçmekten kaçınmak da bir seçimdir","Yalnızca bilinçli düşünceyle mümkündür"],"correctIndex":2}]'::jsonb),
  ('felsefe', 'Epistemoloji: Bilginin Kaynakları', $$Epistemoloji, bilginin doğasını, kaynağını, kapsamını ve sınırlarını araştıran felsefe dalıdır. Temel sorusu şudur: "Neyi, nasıl bilebiliriz?" Epistemoloji aynı zamanda bilginin doğru sanıdan nasıl ayrıldığını da sorgular. Bu alanda iki ana okul birbirine zıt tutumlar sergiler: rasyonalizm ve empirizm.

Rasyonalizm, bilginin temel kaynağının akıl olduğunu savunur. Descartes, Spinoza ve Leibniz bu geleneğin önde gelen temsilcileridir. Rasyonalistlere göre duyular yanıltıcıdır; güvenilir bilgi ancak akıl yoluyla elde edilebilir. Deneyimden bağımsız zorunlu doğrular olan a priori önermeler rasyonalizmin temelidir.

Empirizm ise tüm bilginin kaynağının deneyim olduğunu savunur. Locke, Berkeley ve Hume bu akımın önde gelen temsilcileridir. Empiristlere göre zihin doğuşta "tabula rasa" (boş levha) durumundadır; tüm fikirler deneyimden türer. Hume, nedensellik gibi soyut kavramların bile tekrarlanan gözlemlerden damıtıldığını öne sürdü.

Kant, bu iki akımı sentezlemeye çalıştı: deneyim bilginin hammaddesidir, ancak aklın a priori kategorileri bu hammaddeyi etkin biçimde biçimlendirir. Bu uzlaştırıcı tutum "eleştirel felsefe" olarak adlandırılır ve modern epistemolojinin dönüm noktasını oluşturur. Epistemoloji bugün yapay zeka, bilim felsefesi ve bilişsel bilimlerle kesişerek güncelliğini korumaktadır; "gerçek bilgi nedir?" sorusu dijital çağda yeni boyutlar kazanmaktadır.$$, 164, 6, '{tyt,ayt}', '[{"question":"Epistemoloji nedir?","options":["Var olan varlıkları araştıran felsefe dalı","Bilginin doğasını, kaynağını ve sınırlarını araştıran felsefe dalı","Güzellik ve estetik değerleri inceleyen felsefe dalı","Ahlaki eylemin ilkelerini araştıran felsefe dalı"],"correctIndex":1},{"question":"Rasyonalizme göre bilginin temel kaynağı nedir?","options":["Duyular ve gözlem","Sosyal çevre ve kültür","Akıl","Deney ve sınama"],"correctIndex":2},{"question":"Empirizmde \"tabula rasa\" kavramı ne anlama gelir?","options":["Zihnin doğuştan sahip olduğu evrensel kategoriler","Deneyimden bağımsız zorunlu doğrular","Zihnin doğuşta boş bir levha gibi olduğu görüşü","Duyuların yanıltıcı olduğu ilkesi"],"correctIndex":2},{"question":"Kant rasyonalizm ve empirizmi nasıl sentezledi?","options":["Duyuları tamamen reddederek sadece akla güvenerek","Deneyimi hammadde, aklın a priori kategorilerini biçimlendirici unsur olarak tanımlayarak","Her iki akımı da geçersiz ilan ederek","Deneyimi aklın önüne koyarak"],"correctIndex":1}]'::jsonb),
  ('felsefe', 'Etik Teoriler: Faydacılık ve Deontoloji', $$Etik, ahlaki değerleri, iyi ve kötüyü, doğru ve yanlış eylemleri inceleyen felsefe dalıdır. Tarihte pek çok etik teorisi geliştirilmiş olmakla birlikte TYT ve AYT sınavları açısından en önemli ikisi faydacılık ve deontoloji (ödev ahlakı) olup bu iki teori birbirinden köklü biçimde ayrılır.

Faydacılık, Jeremy Bentham (1748-1832) ve John Stuart Mill (1806-1873) tarafından geliştirilmiştir. Bu teoriye göre bir eylemin ahlaki değeri yalnızca sonuçlarıyla ölçülür. Doğru eylem, en fazla sayıda insana en büyük mutluluğu sağlayandır; bu ilke "en büyük mutluluk ilkesi" olarak bilinir. Faydacılık sonuççu (teleolojik) bir yaklaşımdır; niyetten bağımsız olarak sonuç belirleyicidir.

Deontoloji ise Kant tarafından kuramsallaştırılmıştır. Deontolojik etik, eylemin ahlaki değerini sonuçlarına değil, ödeve ve evrensel kurala uygunluğuna göre belirler. Kant'a göre sonuçlar ne olursa olsun ahlaki yükümlülük yerine getirilmelidir. İki teori arasındaki çatışma en iyi masum birini hapsedip toplumu kurtarma ikileminde görülür: faydacı bunu kabul eder, Kantçı ise reddeder. Günümüzde bu iki teori arasındaki tartışma; yapay zeka etiği, sağlık hizmetleri dağılımı ve iklim politikaları gibi alanlarda pratikte karşımıza çıkmakta ve toplumların nasıl karar vermesi gerektiğini doğrudan etkilemektedir.$$, 170, 6, '{tyt,ayt}', '[{"question":"Faydacılığa göre bir eylemin ahlaki değeri neyle ölçülür?","options":["Eylemin ödeve uygun olup olmadığıyla","En fazla sayıda insana en büyük mutluluğu sağlayıp sağlamadığıyla","Eylemin evrenselleştirilebilir bir ilkeye dayanıp dayanmadığıyla","Eylemin Tanrı buyruklarına uygun olup olmadığıyla"],"correctIndex":1},{"question":"Faydacılığı geliştiren filozoflar kimlerdir?","options":["Kant ve Hegel","Bentham ve Mill","Descartes ve Spinoza","Nietzsche ve Sartre"],"correctIndex":1},{"question":"Kant''ın deontolojik etiğine göre bir eylem ne zaman ahlakidir?","options":["En çok insana yarar sağladığında","Toplumun onayladığı bir eylem olduğunda","Evrenselleştirilebilir bir ilkeye dayandığında","Olumlu duygular uyandırdığında"],"correctIndex":2},{"question":"Faydacılık hangi etik yaklaşım türüne girer?","options":["Deontolojik (ödev temelli)","Erdem temelli","Sonuççu (teleolojik)","Dinî ahlak"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Osmanlı İmparatorluğunun Kuruluşu ve Yükselişi', $$Osmanlı İmparatorluğu, 1299 yılında Söğüt'te Osman Bey tarafından kuruldu. Küçük bir Anadolu beyliği olarak başlayan bu devlet, güçlü askerî örgütlenmesi ve esnek yönetim anlayışı sayesinde kısa sürede Anadolu ve Balkanlar'a yayıldı. Orhan Bey döneminde İznik ve Bursa alınarak Bursa başkent yapıldı; düzenli ordu birlikleri ve yeniçeri ocakları oluşturuldu.

Fatih Sultan Mehmed, 1453'te İstanbul'u fethederek Bizans İmparatorluğu'na son verdi. Bu fetih, Orta Çağ'ın kapandığını ve Yeni Çağ'ın başladığını simgeleyen tarihsel bir kırılma noktasıdır. İstanbul yeni başkent oldu ve İslam dünyasının en önemli siyasi ve kültürel merkezi hâline getirildi.

Yavuz Sultan Selim döneminde Mısır ve Suriye fethedildi; halifelik Osmanlılara geçerek devlete dinî otorite de kazandırdı. Kanuni Sultan Süleyman döneminde (1520-1566) imparatorluk en geniş sınırlarına ulaştı: Macaristan'dan Arabistan'a, Cezayir'den Bağdat'a uzanan geniş bir coğrafyayı yönetti. Bu dönem, Osmanlı'nın altın çağı olarak kabul edilir. Güçlü merkezi yönetim, devşirme sistemi ve tımar düzeni bu başarının temel taşlarıdır. Kanuni döneminde mükemmelleşen Osmanlı hukuk sistemi "Kanunname"ler aracılığıyla düzenlendi; şer'i hukuk ve örfi hukuk bir arada uygulandı. Bu dönem aynı zamanda mimar Sinan'ın başyapıtlarını yarattığı bir kültürel altın çağ olarak da tarihe geçmiştir.$$, 172, 5, '{lgs,tyt,ayt}', '[{"question":"Osmanlı Devleti hangi yılda ve nerede kuruldu?","options":["1281''de Bursa''da","1299''da Söğüt''te","1326''da İznik''te","1453''te İstanbul''da"],"correctIndex":1},{"question":"İstanbul''un fethinin tarihsel önemi nedir?","options":["Osmanlı Devleti''nin kuruluşunu simgeler","Orta Çağ''ın kapandığını ve Yeni Çağ''ın başladığını simgeler","Osmanlı''nın Halifeliği almasını simgeler","Anadolu''nun tamamen fethini simgeler"],"correctIndex":1},{"question":"Osmanlı''nın altın çağı hangi padişah döneminde yaşandı?","options":["Fatih Sultan Mehmed","Yavuz Sultan Selim","Kanuni Sultan Süleyman","Osman Bey"],"correctIndex":2},{"question":"Halifelik hangi padişah döneminde Osmanlılara geçti?","options":["Orhan Bey","Kanuni Sultan Süleyman","Yavuz Sultan Selim","Fatih Sultan Mehmed"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Fransız Devrimi ve Dünya Üzerindeki Etkileri', $$Fransız Devrimi, 1789'da patlak vererek hem Fransa'yı hem de tüm dünyayı derinden dönüştüren büyük bir siyasi kırılma noktasıdır. Devrimin uzun vadeli nedenleri arasında monarşinin baskıcı yönetimi, soylular ve ruhban sınıfının vergi muafiyeti, ağır yük altındaki halkın yoksulluğu ve Voltaire, Rousseau gibi Aydınlanma filozoflarının özgürlük, eşitlik ve kardeşlik fikirlerini yayması sayılabilir.

Devrim sürecinde Bastille Hapishanesi'nin ele geçirilmesi (14 Temmuz 1789), İnsan ve Yurttaş Hakları Bildirgesi'nin yayımlanması ve monarşinin kaldırılarak cumhuriyetin ilan edilmesi öne çıkan olaylardır. Kral Louis XVI, 1793'te giyotin ile idam edildi. Ardından gelen "terör dönemi" binlerce insanı etkiledi.

Fransız Devrimi'nin dünyaya taşıdığı milliyetçilik ve demokrasi idealleri Avrupa'daki eski düzeni sarstı. Osmanlı İmparatorluğu'nda Balkan milletleri arasında bağımsızlık hareketleri alevlendi. Napolyon Bonaparte devrim sonrası iktidara gelerek bu fikirleri Avrupa'ya yaydı. Napolyon Kanunları modern hukuku biçimlendirdi. Devrim, ulus devlet çağının başlangıcı olarak tarihe geçti. Fransız Devrimi'nin özgürlük, eşitlik ve kardeşlik ilkeleri yüzyıllar boyunca dünyada pek çok devrime, bağımsızlık mücadelesine ve anayasal düzene ilham kaynağı olmaya devam etmiştir.$$, 169, 5, '{lgs,tyt,ayt}', '[{"question":"Fransız Devrimi''nin temel sloganı nedir?","options":["Adalet, Barış, Refah","Özgürlük, Eşitlik, Kardeşlik","Güç, Birlik, İlerleme","Akıl, Bilim, Hürriyet"],"correctIndex":1},{"question":"Bastille Hapishanesi''nin ele geçirilmesi hangi tarihe denk gelir?","options":["1 Ocak 1789","14 Temmuz 1789","4 Ağustos 1789","21 Eylül 1792"],"correctIndex":1},{"question":"Fransız Devrimi Osmanlı İmparatorluğu''nu nasıl etkiledi?","options":["Osmanlı''nın Avrupa ile ticaretini geliştirdi","Balkan milletleri arasında bağımsızlık hareketlerini alevlendirdi","Osmanlı''nın Fransa ile ittifak kurmasını sağladı","Osmanlı''nın hukuk sistemini doğrudan değiştirdi"],"correctIndex":1},{"question":"Napolyon Kanunları (Code Civil) tarihsel açıdan neden önemlidir?","options":["İlk anayasa belgesi olduğu için","Modern hukuk sistemlerini etkilediği için","Kilise ile devleti birleştirdiği için","Serfliği kaldıran ilk belge olduğu için"],"correctIndex":1}]'::jsonb),
  ('tarih', 'Birinci Dünya Savaşı: Nedenleri ve Sonuçları', $$Birinci Dünya Savaşı (1914-1918), insanlık tarihinin o güne dek görmediği ölçekte yıkım yaratan küresel bir çatışmadır. Savaşın nedenleri uzun vadeli ve kısa vadeli olarak ikiye ayrılır. Uzun vadeli nedenler; iki büyük ittifak sistemi (İtilaf ve İttifak devletleri), hızlı silahlanma yarışı, Balkanlar'da yükselen milliyetçilik akımları ve sömürge rekabetinden doğan gerginliklerdir.

Kısa vadeli neden ise Avusturya-Macaristan Veliahdı Arşidük Franz Ferdinand'ın 28 Haziran 1914'te Saraybosna'da Sırp milliyetçisi Gavrilo Princip tarafından öldürülmesidir. Bu suikast, ittifak sistemi aracılığıyla domino etkisi yaratarak büyük güçlerin savaşa sürüklenmesine yol açtı.

Osmanlı İmparatorluğu Almanya'nın yanında İttifak devletleri safında savaşa girdi. Çanakkale Cephesi'nde İngiliz ve ANZAC kuvvetlerinin çıkarma girişimi başarıyla püskürtüldü; bu zafer ulusal bilincin simgesi hâline geldi.

Savaş 1918'de İtilaf devletlerinin zaferiyle sona erdi. Versailles Antlaşması (1919) Almanya'ya ağır siyasi ve ekonomik yaptırımlar getirdi; Almanya'nın toprakları küçülürken savaş tazminatı ekonomisini çöküşe sürükledi. Osmanlı İmparatorluğu parçalanma sürecine girerken Avusturya-Macaristan ve Rusya İmparatorluğu da dağıldı. Haritalar yeniden çizildi; yeni ulus devletler ortaya çıktı. Versailles'ın ağır koşulları Almanya'da milliyetçi öfkeyi körükledi ve Nazizmin yükselişinin zeminini oluşturdu. Tüm bu dönüşümler yalnızca yirmi yıl sonra patlak verecek olan İkinci Dünya Savaşı'nın altyapısını hazırladı.$$, 173, 5, '{lgs,tyt,ayt}', '[{"question":"Birinci Dünya Savaşı''nın yakın (kısa vadeli) nedeni nedir?","options":["Almanya''nın Fransa''ya saldırması","Arşidük Franz Ferdinand''ın Saraybosna''da öldürülmesi","Osmanlı''nın İttifak devletlerine katılması","Rusya''nın Avusturya''ya savaş ilan etmesi"],"correctIndex":1},{"question":"Osmanlı İmparatorluğu Birinci Dünya Savaşı''nda hangi tarafta yer aldı?","options":["İtilaf devletleri (İngiltere, Fransa, Rusya) yanında","Tarafsız kaldı","İttifak devletleri (Almanya, Avusturya-Macaristan) yanında","Her iki tarafla da savaştı"],"correctIndex":2},{"question":"Versailles Antlaşması hangi devlete ağır yaptırımlar getirdi?","options":["Osmanlı İmparatorluğu''na","Avusturya-Macaristan''a","Almanya''ya","Rusya''ya"],"correctIndex":2},{"question":"Birinci Dünya Savaşı''nın uzun vadeli nedenleri arasında hangisi sayılmaz?","options":["Silahlanma yarışı","Milliyetçilik akımları","Franz Ferdinand suikastı","İttifak sistemleri"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Türk Kurtuluş Savaşı ve Lozan Antlaşması', $$Birinci Dünya Savaşı'nın ardından imzalanan Mondros Mütarekesi (30 Ekim 1918), Osmanlı topraklarının büyük bölümünü işgale açtı. İngiltere İstanbul'u; Fransa Güney Anadolu'yu; İtalya Batı Anadolu'yu işgal ederken İzmir, 15 Mayıs 1919'da Yunan kuvvetlerince işgal edildi. Bu işgal, Anadolu'da millî direniş ateşini tutuşturdu. Mustafa Kemal, 19 Mayıs 1919'da Samsun'a ayak basarak direnişi örgütlemeye başladı.

Erzurum ve Sivas kongreleri (1919), Millî Mücadele'nin ilkelerini ve yönetim çerçevesini belirledi. Türkiye Büyük Millet Meclisi 23 Nisan 1920'de Ankara'da açıldı. Doğu Cephesi'nde Ermeni kuvvetleri yenilgiye uğratıldı; Güney'de Fransızlarla Ankara Antlaşması imzalandı.

Batı Cephesi'nde Yunan kuvvetlerine karşı verilen zorlu mücadele, Sakarya Meydan Muharebesi (Ağustos-Eylül 1921) ve ardından gerçekleştirilen Büyük Taarruz (Ağustos 1922) ile zaferle sonuçlandı. Mudanya Ateşkesi imzalandı ve diplomatik süreç başladı. Lozan Antlaşması 24 Temmuz 1923'te imzalanarak Türkiye'nin bağımsızlığını uluslararası alanda tescil etti; Sevr Antlaşması geçersiz kılındı. Türkiye Cumhuriyeti 29 Ekim 1923'te ilan edildi. Lozan Antlaşması, bugün Türk dış politikasında ve ulusal kimliğinde merkezi bir yere sahip olmaya devam etmektedir; bu nedenle her yıl 24 Temmuz'da ulusal düzeyde kutlanmaktadır.$$, 171, 5, '{lgs,tyt,ayt}', '[{"question":"Mustafa Kemal Atatürk hangi tarihte Samsun''a çıktı?","options":["30 Ekim 1918","23 Nisan 1920","19 Mayıs 1919","24 Temmuz 1923"],"correctIndex":2},{"question":"Lozan Antlaşması hangi antlaşmanın geçersiz sayılmasını sağladı?","options":["Mondros Mütarekesi","Mudanya Ateşkesi","Sevr Antlaşması","Versailles Antlaşması"],"correctIndex":2},{"question":"Türkiye Büyük Millet Meclisi hangi tarihte açıldı?","options":["19 Mayıs 1919","23 Nisan 1920","24 Temmuz 1923","29 Ekim 1923"],"correctIndex":1},{"question":"Türkiye Cumhuriyeti hangi tarihte ilan edildi?","options":["24 Temmuz 1923","19 Mayıs 1919","23 Nisan 1920","29 Ekim 1923"],"correctIndex":3}]'::jsonb),
  ('tarih', 'Atatürk''ün İnkılapları ve Cumhuriyet''in İlanı', $$Türkiye Cumhuriyeti'nin 29 Ekim 1923'te ilanının ardından Mustafa Kemal Atatürk, toplumun her alanını modern bir yapıya kavuşturmak amacıyla köklü inkılaplar gerçekleştirdi. Bu inkılaplar siyasi, hukuki, sosyal ve kültürel alanlarda derin ve kalıcı değişimler meydana getirdi.

Siyasi alanda halifelik 1924'te kaldırıldı; çok partili hayata geçiş denemeleri yapıldı. Hukuk alanında İsviçre Medeni Kanunu esas alınarak Türk Medeni Kanunu 1926'da kabul edildi; bu düzenleme kadın-erkek eşitliğini hukuki güvenceye aldı ve çok eşliliği yasakladı. Eğitimde 1924'te Tevhid-i Tedrisat Kanunu çıkarılarak tüm okullar devlet çatısı altında toplandı.

1928'de harf devrimi gerçekleştirildi ve Latin kökenli Türk alfabesi benimsendi; okuma yazma oranını artırmak için "Millet Mektepleri" açıldı. Kıyafet devrimi ile şapka zorunluluğu getirildi; tekke ve zaviyelerin kapatılmasıyla dinî tasavvuf kurumları faaliyetlerini durdurdu. Takvim, ölçü ve saat sistemleri uluslararası standartlara uyarlandı. Kadınlara 1930'da belediye seçimlerinde, 1934'te ise milletvekili seçme ve seçilme hakkı tanındı; bu adım pek çok Avrupa ülkesinin önünde gerçekleşti. Tüm bu inkılapların ortak paydası laikleşme, çağdaşlaşma ve ulusal egemenlik ilkeleridir. Atatürk'ün hedefi, Türkiye'yi "muasır medeniyetler seviyesine" ulaştırmaktı ve bu vizyon Cumhuriyet'in kurucu felsefesinin özünü oluşturur.$$, 175, 5, '{lgs,tyt,ayt}', '[{"question":"Türk Medeni Kanunu hangi ülkenin medeni kanunundan yararlanılarak hazırlandı?","options":["Almanya","Fransa","İsviçre","İtalya"],"correctIndex":2},{"question":"Harf devrimi hangi yılda gerçekleştirildi?","options":["1924","1926","1928","1934"],"correctIndex":2},{"question":"Kadınlara milletvekili seçme ve seçilme hakkı hangi yılda tanındı?","options":["1926","1930","1932","1934"],"correctIndex":3},{"question":"Tevhid-i Tedrisat Kanunu''nun amacı nedir?","options":["Yeni harflerin öğretimini zorunlu kılmak","Eğitimi devlet tekeline alarak birleştirmek","Üniversiteleri kurmak","Yabancı dil eğitimini yaygınlaştırmak"],"correctIndex":1}]'::jsonb),
  ('tarih', 'İkinci Dünya Savaşı: İdeolojiler ve Sonuçları', $$İkinci Dünya Savaşı (1939-1945), tarihte en fazla can kaybına yol açan silahlı çatışmadır; yaklaşık 70-80 milyon kişi hayatını kaybetmiştir. Savaşın ideolojik temelinde faşizm (Almanya ve İtalya), milliyetçi militarizm (Japonya) ile demokrasi ve komünizm (İngiltere, ABD, SSCB) arasındaki derin karşıtlık yatar. Birinci Dünya Savaşı sonrasının ağır koşulları ve Büyük Buhran, otoriter rejimlerin yükselmesine zemin hazırladı.

Savaş, 1 Eylül 1939'da Nazi Almanyası'nın Polonya'yı işgal etmesiyle başladı. Almanya kısa sürede Fransa dahil Batı Avrupa'nın büyük bölümünü ele geçirdi. Avrupa Yahudilerini ve diğer azınlıkları hedef alan Holokost sistematik biçimde uygulandı; yaklaşık 6 milyon Yahudi toplama ve imha kamplarında katledildi. 1941'de Almanya'nın SSCB'ye saldırması ve Japonya'nın Pearl Harbor'ı bombalamasıyla savaş gerçek anlamda küresel boyut kazandı.

Normandiya çıkarması (6 Haziran 1944) Batı Cephesi'nde belirleyici dönüm noktası oldu. 1945'te Almanya teslim oldu. ABD'nin Hiroşima ve Nagazaki'ye attığı atom bombaları Japonya'nın teslimiyetini hızlandırdı. Savaş sonrasında Birleşmiş Milletler kuruldu; Almanya bölündü ve ABD ile SSCB süper güç olarak öne çıktı. Soğuk Savaş başladı.$$, 174, 5, '{lgs,tyt,ayt}', '[{"question":"İkinci Dünya Savaşı hangi olayla başladı?","options":["Japonya''nın Pearl Harbor''ı bombalamasıyla","Almanya''nın Fransa''yı işgal etmesiyle","Nazi Almanyası''nın Polonya''yı işgal etmesiyle","İtalya''nın Etiyopya''ya saldırmasıyla"],"correctIndex":2},{"question":"Holokost''ta yaklaşık kaç Yahudi katledildi?","options":["1 milyon","3 milyon","6 milyon","10 milyon"],"correctIndex":2},{"question":"Normandiya çıkarması hangi tarihte gerçekleşti?","options":["1 Eylül 1939","22 Haziran 1941","6 Haziran 1944","8 Mayıs 1945"],"correctIndex":2},{"question":"İkinci Dünya Savaşı sonrasında kurulan uluslararası örgüt hangisidir?","options":["NATO","Birleşmiş Milletler","Avrupa Birliği","Milletler Cemiyeti"],"correctIndex":1}]'::jsonb),
  ('tarih', 'Soğuk Savaş: ABD-SSCB Çatışması', $$Soğuk Savaş (1947-1991), İkinci Dünya Savaşı'nın ardından ABD önderliğindeki Batı bloku ile SSCB önderliğindeki Doğu bloku arasında yaşanan ideolojik, siyasi ve ekonomik gerginlik dönemidir. "Soğuk" olarak adlandırılmasının nedeni, iki süper güç arasında doğrudan silâhlı bir çatışmanın yaşanmamasıdır; ancak buna karşın vekâlet savaşları ve tehlikeli krizler ardı ardına patlak verdi.

Truman Doktrini (1947) ve ardından açıklanan Marshall Planı, ABD'nin komünizmin yayılmasını engelleme politikasının (kontainment) somut çerçevesini oluşturdu. SSCB yanıt olarak Doğu Avrupa'da uydu devletler kurdu ve Berlin'i abluka altına aldı. 1949'da NATO, 1955'te ise Varşova Paktı kurularak bloklaşma resmî şeklini aldı.

En kritik an 1962'deki Küba Füze Krizi oldu; SSCB'nin Küba'ya nükleer füze yerleştirmesi, iki süper gücü nükleer savaşın eşiğine getirdi. Kriz, Kennedy ve Kruşçev arasındaki yoğun diplomatik görüşmelerle atlatıldı. Kore ve Vietnam savaşları bu dönemin en kanlı vekâlet savaşlarıdır; Orta Doğu, Afrika ve Latin Amerika da iki blok arasındaki nüfuz mücadelesinden payını aldı. Berlin Duvarı'nın 1989'da yıkılması Soğuk Savaş'ın fiilen sona erişinin simgesi oldu; SSCB 1991'de 15 bağımsız devlete ayrılarak tarihe karıştı. Bu süreç, ABD'yi dünyanın tek süper gücü olarak öne çıkardı.$$, 168, 5, '{lgs,tyt,ayt}', '[{"question":"Soğuk Savaş''ın \"soğuk\" olarak adlandırılmasının nedeni nedir?","options":["Çatışmaların kutuplarda yaşanması","İki süper güç arasında doğrudan silâhlı çatışma yaşanmaması","ABD ve SSCB''nin birbirinden uzak coğrafyalarda yer alması","Nükleer silahların soğuk havalarda etkisiz kalması"],"correctIndex":1},{"question":"Truman Doktrini''nin temel amacı nedir?","options":["Avrupa''nın ekonomik açıdan yeniden inşası","Komünizmin yayılmasını engelleme (kontainment) politikası","SSCB ile nükleer silah sınırlaması anlaşması yapmak","NATO''yu kurmak"],"correctIndex":1},{"question":"Küba Füze Krizi hangi yılda yaşandı?","options":["1949","1955","1962","1972"],"correctIndex":2},{"question":"Soğuk Savaş''ın fiilen sona erişinin simgesi hangi olaydır?","options":["SSCB''nin 1991''de dağılması","Küba Füze Krizi''nin çözüme kavuşması","Berlin Duvarı''nın 1989''da yıkılması","NATO''nun kurulması"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Rönesans ve Reform Hareketleri', $$Rönesans (Yeniden Doğuş), 14.-16. yüzyıllarda Floransa ve Venedik gibi İtalyan şehir devletlerinde başlayıp Avrupa'ya yayılan büyük bir kültürel ve entelektüel canlanma hareketidir. Orta Çağ'ın katı Kilise egemenliğinden uzaklaşılarak Antik Yunan ve Roma kültürüne yeniden yönelme bu hareketin özünü oluşturur. Hümanizm akımı, insanı ve aklı evrenin merkezine koyarak Rönesans'ın felsefi temelini sağladı.

Leonardo da Vinci, Michelangelo ve Raphael sanatın doruk noktalarını temsil ederken Erasmus ve Thomas More hümanizmin edebî ve felsefî sözcülüğünü üstlendiler. Gutenberg'in matbaayı geliştirmesi (1450'ler) kitapların çoğaltılmasını ve bilginin hızla yayılmasını sağladı.

Reform hareketi ise Kilise'nin yozlaşmasına, endüljanslara (günah affı mektupları) ve din adamlarının ahlaki çöküşüne duyulan toplumsal tepkinin ürünüdür. Martin Luther 1517'de "95 Tez"ini Wittenberg Kilisesi'nin kapısına astı; bu eylem reform ateşinin kıvılcımı oldu. Calvin İsviçre'de, Zwingli ise başka bölgelerde reformu yayarak hareketin kapsamını genişletti.

Reform, Avrupa'yı Katolik ve Protestan olmak üzere ikiye böldü; kanlı mezhep savaşlarını beraberinde getirdi. Kilise'nin siyasi otoritesi sarsılırken ulus devletlerin güçlenmesi hız kazandı.$$, 170, 6, '{lgs,tyt,ayt}', '[{"question":"Rönesans hareketi hangi ülkede başladı?","options":["Fransa","Almanya","İtalya","İngiltere"],"correctIndex":2},{"question":"Martin Luther''in Reform''u başlatmak için yaptığı eylem nedir?","options":["Papa''ya suikast girişimi","Wittenberg Kilisesi''nin kapısına 95 Tez''ini asması","İncil''i Almancaya çevirmesi","Katolik Kilisesi''nden resmi olarak ayrılması"],"correctIndex":1},{"question":"Hümanizm akımının temel özelliği nedir?","options":["Tanrı''yı ve dini her şeyin merkezine koymak","İnsanı ve aklı merkeze almak","Orta Çağ değerlerine dönmek","Kilise otoritesini güçlendirmek"],"correctIndex":1},{"question":"Reform hareketinin sonuçları arasında hangisi sayılabilir?","options":["Avrupa''nın tek bir mezhepte birleşmesi","Kilisenin siyasi gücünün pekişmesi","Avrupa''nın Katolik ve Protestan olarak bölünmesi","Rönesans''ın sona ermesi"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Coğrafi Keşifler ve Kolonizasyon', $$15. ve 16. yüzyıllarda Avrupalı denizciler, Asya ile Hindistan'a yeni ticaret yolları bulmak amacıyla büyük deniz seferlerine çıktı. Bu büyük sefer dalgasına Coğrafi Keşifler denir. Osmanlı İmparatorluğu'nun geleneksel İpek Yolu ve Baharat Yolu üzerindeki denetimi, Avrupalıları deniz aşırı alternatif yollar aramaya zorladı.

Portekizli denizci Bartolomeu Dias, 1488'de Afrika'nın güney ucundaki Ümit Burnu'nu aşarak Atlas ve Hint okyanuslarının birleştiği noktayı keşfetti. Vasco da Gama, 1498'de Hindistan'a deniz yoluyla ulaşmayı başardı; bu başarı Portekiz'e Uzakdoğu ticaretinde büyük bir üstünlük sağladı.

1492'de Cenevizli denizci Kristof Kolomb, İspanya adına yola çıkarak Karayipler aracılığıyla Amerika kıtasına ulaştı; aslında Hindistan'a gitmek niyetindeydi. Bu keşif, Avrupa ile Amerika arasında kalıcı bir temasın başlangıcı oldu. İspanya ve Portekiz başta olmak üzere Avrupalı güçler Amerika kıtasını sömürgeleştirdi; yerli halklar hem sömürüden hem de Avrupalıların getirdiği salgın hastalıklardan büyük kayıplar yaşadı.

Atlantik köle ticareti bu dönemde hız kazandı; milyonlarca Afrikalı zorla Amerika'ya taşındı. Coğrafi Keşifler dünya ticaret dengelerini alt üst etti ve kapitalizmin doğuşunu hızlandırdı. Akdeniz'in tarihsel ticaret merkezi konumu zayılarken Atlas Okyanusu kıyısındaki İspanya ve Portekiz zenginlik ve güç açısından zirveye taşındı.$$, 166, 5, '{lgs,tyt,ayt}', '[{"question":"Coğrafi Keşifler''in temel nedeni nedir?","options":["Yeni dinleri yayma arzusu","Asya ve Hindistan''a yeni ticaret yolları bulma ihtiyacı","Askeri üs elde etme isteği","Bilimsel araştırma merakı"],"correctIndex":1},{"question":"Ümit Burnu''nu hangi denizci keşfetti?","options":["Vasco da Gama","Kristof Kolomb","Bartolomeu Dias","Ferdinand Magellan"],"correctIndex":2},{"question":"Kristof Kolomb Amerika''ya hangi yılda ulaştı?","options":["1488","1492","1498","1519"],"correctIndex":1},{"question":"Coğrafi Keşifler''in ekonomik sisteme etkisi nedir?","options":["Feodalizmi güçlendirdi","İpek Yolu ticaretini canlandırdı","Merkantilist anlayışı ve kapitalizmin gelişimini destekledi","Osmanlı ticaretini olumlu etkiledi"],"correctIndex":2}]'::jsonb),
  ('tarih', 'Mezopotamya Uygarlıkları: Sümer, Akad, Babil', $$Mezopotamya, Yunanca "iki nehir arasındaki ülke" anlamına gelir; Dicle ve Fırat nehirleri arasındaki bu verimli topraklar insanlığın bilinen ilk kentsel uygarlıklarına ev sahipliği yaptı. Günümüz Irak coğrafyasında yer alan bu bölge, MÖ 3500 civarında ortaya çıkan Sümerlerin beşiği oldu. Sümerler, insanlık tarihinin bilinen en eski yazı sistemini geliştirdi: kil tabletlere kazınan çivi yazısı, dini metinleri, ticari kayıtları ve edebî eserleri aktarmayı mümkün kıldı.

Sümerler; Ur, Uruk ve Lagaş gibi rekabetçi şehir devletleri kurdu. Tarımsal sulama kanalları inşa ettiler; takvim, matematik ve astronomide öncü çalışmalar yaptılar. Ziggurat adı verilen basamaklı tapınak kuleleri Sümer mimarisinin simgesidir.

Akadlar, MÖ 2350'de Sargon önderliğinde Sümerleri birleştirerek tarihte bilinen ilk imparatorluğu kurdu. Akad dili bölgenin ortak iletişim diline dönüştü. Daha sonra yükselen Babil Uygarlığı'nın altın çağı Kral Hammurabi (MÖ 1792-1750) döneminde yaşandı. Hammurabi Kanunları, yazılı hukukun en erken ve en kapsamlı örneklerinden biridir; kısas ilkesini ve toplumsal sınıflar arasındaki hukuki farklılıkları belgelemektedir. Yeni Babil döneminde inşa edildiği söylenen Asma Bahçeler ise dünyanın yedi harikasından biri olarak tarihe geçmiştir.$$, 167, 5, '{lgs,tyt,ayt}', '[{"question":"Çivi yazısını geliştiren uygarlık hangisidir?","options":["Akadlar","Babilliler","Sümerler","Asurlular"],"correctIndex":2},{"question":"Tarihte bilinen ilk imparatorluğu hangi önder kurdu?","options":["Hammurabi","Sargon","Nebukadnezar","Gilgameş"],"correctIndex":1},{"question":"Hammurabi Kanunları tarihsel açıdan neden önemlidir?","options":["İlk alfabe sistemini içerdiği için","Tarihte bilinen en kapsamlı yazılı hukuk belgeleri arasında yer aldığı için","İlk şehir devletlerini düzenlediği için","İlk demokratik anayasa örneği olduğu için"],"correctIndex":1},{"question":"Mezopotamya coğrafyası günümüz hangi ülkesine karşılık gelir?","options":["Mısır","Suriye","İran","Irak"],"correctIndex":3}]'::jsonb),
  ('psikoloji', 'Pavlov ve Klasik Koşullanma', $$Ivan Pavlov, 20. yüzyılın başında köpekler üzerinde yaptığı deneylerle öğrenme psikolojisine temel katkılar sağlamıştır. Pavlov, köpeklere yemek verirken zil sesi çaldığını fark etti; başlangıçta yalnızca yemeğe tepki veren köpekler zamanla yalnızca zil sesini duyduklarında salya salmaya başladı.

Bu süreç klasik koşullanma olarak adlandırılır. Başlangıçta nötr olan bir uyaran (zil sesi), koşulsuz uyaranla (yemek) tekrar tekrar eşleştirildiğinde, tek başına koşullu tepkiyi (salya) uyandırabilir hale gelir.

Koşulsuz uyaran doğal olarak tepkiye yol açan uyarandır; koşullu uyaran ise öğrenme yoluyla tepki uyandıran uyarandır. Bu öğrenme türü bilinçsiz gerçekleşir ve hem hayvanlarda hem insanlarda gözlemlenebilir.

Günlük yaşamda klasik koşullanmaya pek çok örnek verilebilir. Belirli bir koku, geçmişteki anıları canlandırabilir. Diş hekimi koltuğunu görmek kaygı yaratabilir. TYT psikoloji sorularında Pavlov deneyi sıkça karşımıza çıkmaktadır.$$, 165, 5, '{tyt,ayt}', '[{"question":"Pavlov''un deneyinde zil sesi başlangıçta nasıl bir uyarandır?","options":["Koşulsuz uyaran","Koşullu uyaran","Nötr uyaran","Doğal uyaran"],"correctIndex":2},{"question":"Klasik koşullanmada koşullu tepki nedir?","options":["Yemeğe verilen doğal salya tepkisi","Yalnızca zil sesine verilen öğrenilmiş tepki","Köpeğin yemeği görmesi","Pavlov''un zil çalması"],"correctIndex":1},{"question":"Klasik koşullanma hangi tür öğrenmeyi temsil eder?","options":["Bilinçli ve kasıtlı öğrenme","Bilinçsiz ve otomatik öğrenme","Sözel öğrenme","Gözlemsel öğrenme"],"correctIndex":1},{"question":"Günlük yaşamda klasik koşullanmaya hangi durum örnek gösterilebilir?","options":["Bisiklet sürmeyi öğrenmek","Matematik formülü ezberlemek","Diş hekimi koltuğunu görünce kaygı hissetmek","Ders çalışmak için masa başına oturmak"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Maslow''un İhtiyaçlar Hiyerarşisi', $$Abraham Maslow, 1943 yılında insan motivasyonunu açıklamak için beş kademeli bir ihtiyaçlar hiyerarşisi geliştirdi. Bu model genellikle bir piramit şeklinde gösterilir; alt katmanlardaki temel ihtiyaçlar karşılanmadan üst katmanlara geçilmez.

Piramidin tabanında fizyolojik ihtiyaçlar bulunur: yemek, su, uyku ve barınak. İkinci katmanda güvenlik ihtiyaçları yer alır; fiziksel güvenlik, iş güvencesi ve düzen bu kategoriye girer. Üçüncü katmanda ait olma ve sevgi ihtiyaçları vardır; aile bağları ve arkadaşlık bu düzeye karşılık gelir.

Dördüncü katman saygınlık ihtiyacını kapsar. Başarı duygusu, tanınma ve öz saygı bu aşamanın temel unsurlarıdır. En üst katmanda ise öz gerçekleştirme yer alır; bireyin kendi potansiyelini tam anlamıyla kullanması ve anlam araması bu en yüksek ihtiyaca karşılık gelir.

Maslow'un kuramı, eğitim, yönetim ve klinik psikoloji gibi pek çok alanda uygulanmaktadır. TYT sınavlarında ihtiyaç kademeleri ve öz gerçekleştirme kavramı sıkça sorulmaktadır.$$, 170, 5, '{tyt,ayt}', '[{"question":"Maslow''un hiyerarşisinde piramidin tabanında hangi ihtiyaçlar bulunur?","options":["Güvenlik ihtiyaçları","Saygınlık ihtiyaçları","Fizyolojik ihtiyaçlar","Öz gerçekleştirme"],"correctIndex":2},{"question":"Maslow''un hiyerarşisinde en üst katmanda yer alan ihtiyaç hangisidir?","options":["Güvenlik","Ait olma","Saygınlık","Öz gerçekleştirme"],"correctIndex":3},{"question":"Maslow''a göre ihtiyaçlar arasında nasıl bir ilişki vardır?","options":["Tüm ihtiyaçlar eşit öneme sahiptir","Alt katmanlardaki ihtiyaçlar karşılanmadan üst katmanlara geçilmez","Üst katmanlar önce karşılanmalıdır","İhtiyaçlar birbirinden bağımsızdır"],"correctIndex":1},{"question":"Aile bağları ve arkadaşlık Maslow''un hiyerarşisinin hangi katmanına girer?","options":["Fizyolojik ihtiyaçlar","Güvenlik ihtiyaçları","Ait olma ve sevgi ihtiyaçları","Saygınlık ihtiyaçları"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Freud ve Bilinçdışı: İd, Ego, Süperego', $$Sigmund Freud, psikanalizin kurucusudur. Freud'a göre insan zihninin büyük bölümü bilinçdışında yer alır ve bu kısmın davranışlar üzerinde belirleyici bir etkisi vardır. Freud zihinsel yapıyı üç bölüme ayırmıştır: id, ego ve süperego.

İd, doğuştan gelen dürtüleri, hazlarını ve ilkel arzuları barındırır. Anlık doyum arar ve gerçeklikle bağı yoktur. Süperego ise toplumsal kuralları, ahlaki değerleri ve vicdanı temsil eder; idnin dürtülerini denetlemeye çalışır.

Ego, id ile süperego arasındaki dengeyi kuran ve gerçeklik ilkesiyle çalışan yapıdır. Bireyin dış dünyayla olan ilişkisini düzenler. Ego, bu dengeyi kurarken savunma mekanizmalarına başvurabilir; bastırma, yansıtma ve yüceltme bunların en bilinenleridir.

Freud'un kuramı zaman zaman eleştirilse de bilinçdışı kavramı modern psikolojide hâlâ önemli bir yer tutmaktadır. TYT sınavlarında id, ego ve süperego arasındaki farklar ve savunma mekanizmaları sıklıkla sorulmaktadır.$$, 168, 6, '{tyt,ayt}', '[{"question":"Freud''a göre idnin temel özelliği nedir?","options":["Toplumsal kuralları temsil eder","Gerçeklik ilkesiyle çalışır","Anlık doyum arayan ilkel dürtüleri barındırır","Bilinçli düşüncelerden oluşur"],"correctIndex":2},{"question":"Süperego hangi işlevi yerine getirir?","options":["Anlık zevk arar","İd ile dış dünya arasında denge kurar","Toplumsal kuralları ve vicdanı temsil eder","Bilinçdışı arzuları dışa vurur"],"correctIndex":2},{"question":"Ego hangi ilkeyle çalışır?","options":["Haz ilkesi","Gerçeklik ilkesi","Ahlak ilkesi","Denge ilkesi"],"correctIndex":1},{"question":"Savunma mekanizmalarına örnek olarak hangi kavram verilebilir?","options":["Öz gerçekleştirme","Koşullanma","Bastırma","Pekiştirme"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Sosyal Psikoloji: Grup Dinamikleri ve Uyma Davranışı', $$Sosyal psikoloji, bireylerin grup içindeki davranışlarını ve sosyal etkileşimlerin psikolojik süreçleri nasıl şekillendirdiğini inceler. Bu alanda yapılan iki önemli deney, insan davranışının sosyal baskıdan ne denli etkilendiğini çarpıcı biçimde ortaya koymuştur.

Solomon Asch'in uyma deneyi (1951) katılımcılara açıkça doğru olan bir cevabın grubun yanlış cevabını destekleyip desteklemeyeceğini test etmiştir. Katılımcıların önemli bir bölümü doğru bildikleri hâlde gruba uymayı tercih etmiştir.

Stanley Milgram'ın itaat deneyi ise otorite figürünün emirleri karşısında bireylerin başkalarına zarar verebileceğini göstermiştir. Deneyin sonuçları, itaat ve bağımsız düşünme arasındaki gerilimi gündeme taşımıştır.

Grup dinamikleri; konformizm (uyma), sosyal kollanma, grup düşüncesi (groupthink) ve deindividüasyon gibi kavramları kapsar. Bu kavramlar, kalabalık ortamlardaki bireysel davranışları anlamak için temel araçlar sunar.

Sınavlarda Milgram ve Asch deneyleri, sosyal etki mekanizmaları bağlamında sıkça sorulan konular arasındadır.$$, 172, 6, '{tyt,ayt}', '[{"question":"Asch''in uyma deneyinde katılımcıların büyük bölümü ne yapmıştır?","options":["Doğru cevabı vermiştir","Deneyi reddetmiştir","Doğru bildikleri hâlde gruba uymuştur","Birbirlerini etkilememiştir"],"correctIndex":2},{"question":"Milgram''ın deneyinin temel bulgusu nedir?","options":["İnsanlar grup baskısına direnir","Otorite figürünün emirleri karşısında bireyler başkalarına zarar verebilir","Sosyal baskı yalnızca çocukları etkiler","Konformizm azınlık baskısından kaynaklanır"],"correctIndex":1},{"question":"Konformizm kavramı ne anlama gelir?","options":["Bireyin gruba uyma eğilimi","Bireyin gruba liderlik etmesi","Grupların birbirinden ayrışması","Bireysel karar verme süreci"],"correctIndex":0},{"question":"Grup düşüncesi (groupthink) hangi durumu tanımlar?","options":["Grubun eleştirel düşünme kapasitesini artırması","Bireysel fikirlerin gruba hâkim olması","Uyumu koruma adına eleştirel düşüncenin baskılanması","Grup üyelerinin oy birliğiyle karar vermesi"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Bilişsel Önyargılar', $$Bilişsel önyargılar, bireylerin karar verme ve düşünme süreçlerinde sistematik olarak yaptıkları hatalar ve yargılama yanılgılarıdır. Bu önyargılar, zihnin karmaşık bilgiyi hızlıca işlemek için kullandığı kısa yollardan kaynaklanır.

Onay önyargısı (confirmation bias), bireyin mevcut inançlarını destekleyen bilgileri araması ve bunlarla çelişen bilgileri görmezden gelmesidir. Örneğin bir kişi tuttuğu takımın iyi olduğuna inancını güçlendiren haberleri fark ederken karşı kanıtları atlayabilir.

Çıpalama önyargısı (anchoring), ilk alınan bilginin ya da sayının sonraki yargıları aşırı biçimde etkilemesidir. Bir ürünün ilk fiyatı, indirimin ne kadar cazip görüneceğini belirler.

Kullanılabilirlik sezgisi (availability heuristic), belleğe daha kolay gelen olayların daha sık gerçekleştiğinin sanılmasıdır. Uçak kazaları nadirdir; ancak çarpıcı haberleri kolayca hatırlandığı için uçak yolculuğu olduğundan tehlikeli algılanabilir.

TYT psikoloji testlerinde bu üç önyargı kavramı sıklıkla soruların konusunu oluşturmaktadır.$$, 166, 5, '{tyt,ayt}', '[{"question":"Onay önyargısı nasıl tanımlanır?","options":["İlk bilginin yargıları etkilemesi","Mevcut inançları destekleyen bilgileri aramak ve zıt bilgileri görmezden gelmek","Belleğe kolay gelen olayları sık sanmak","Otorite figürlerine güvenmek"],"correctIndex":1},{"question":"Çıpalama önyargısına günlük yaşamdan hangi örnek verilebilir?","options":["Uçak kazalarının tehlikeli sanılması","Gruba uyma eğilimi","Bir ürünün ilk fiyatının indirimi cazip göstermesi","Başarıyı yeteneğe bağlamak"],"correctIndex":2},{"question":"Kullanılabilirlik sezgisi hangi durumda ortaya çıkar?","options":["İlk edinilen bilginin çok güçlü olması","Belleğe kolay gelen olayların daha sık olduğunun sanılması","Grup baskısına boyun eğilmesi","Kendi fikirlerini koruma güdüsü"],"correctIndex":1},{"question":"Bilişsel önyargılar nereden kaynaklanır?","options":["Bireylerin kötü niyetli olmasından","Zihnin karmaşık bilgiyi hızlıca işlemek için kullandığı kısa yollardan","Sosyal baskıdan","Hafıza bozukluklarından"],"correctIndex":1}]'::jsonb),
  ('psikoloji', 'Duygusal Zeka: Goleman ve Beş Bileşen', $$Daniel Goleman, 1995 yılında yayımladığı kitabıyla duygusal zeka (EQ) kavramını geniş kitlelere tanıttı. Goleman'a göre duygusal zeka, bireyin hem kendi duygularını hem de başkalarının duygularını anlama ve yönetme kapasitesidir.

Goleman duygusal zekayı beş temel bileşene ayırmıştır. Birincisi öz farkındalıktır; bireyin kendi duygularını tanıması ve bunların davranışları üzerindeki etkisini kavramasıdır. İkincisi öz düzenlemedir; ani duygusal tepkileri kontrol etme ve kışkırtıcı durumlarda sakinliği koruma becerisidir.

Üçüncü bileşen motivasyondur; bireyin içsel güdülerle harekete geçebilmesi ve başarısızlık karşısında direncini korumasıdır. Dördüncüsü empatidir; başkalarının duygularını hissetme ve anlamlandırma kapasitesidir.

Beşinci ve son bileşen sosyal becerilerdir; ilişki kurmak, iletişim kurmak ve grupları yönetmek bu başlık altında toplanır.

Araştırmalar, duygusal zekanın akademik başarı, liderlik ve ilişki kalitesi üzerinde güçlü bir etkisi olduğunu ortaya koymuştur. Sınavlarda Goleman'ın beş bileşeni sıkça sorulmaktadır.$$, 168, 5, '{tyt,ayt}', '[{"question":"Goleman''a göre duygusal zekanın kaç temel bileşeni vardır?","options":["Üç","Dört","Beş","Altı"],"correctIndex":2},{"question":"Öz farkındalık nasıl tanımlanır?","options":["Başkalarının duygularını hissetmek","Ani duygusal tepkileri kontrol etmek","Bireyin kendi duygularını tanıması ve bunların etkisini kavraması","İçsel güdülerle harekete geçmek"],"correctIndex":2},{"question":"Empati bileşeni ne anlama gelir?","options":["Kendi duygularını düzenlemek","Başkalarının duygularını hissetme ve anlamlandırma kapasitesi","Grup yönetimi becerisi","Motivasyon kaynağı oluşturma"],"correctIndex":1},{"question":"Sosyal beceriler bileşeni hangi yetenekleri kapsar?","options":["Kendi duygularını kontrol etme","Başarısızlık karşısında direnç","İlişki kurmak, iletişim kurmak ve grupları yönetmek","Duygusal tepkileri bastırmak"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Stres ve Başa Çıkma Mekanizmaları', $$Stres, bireyin kaynaklarını aşan ya da onları zorlayan iç veya dış taleplere verdiği fizyolojik ve psikolojik tepkidir. Kısa süreli stres performansı artırabilirken kronik stres sağlığı ciddi biçimde tehdit eder.

Tehdit algılandığında beyin, amigdala üzerinden anında tepki üretir ve sempatik sinir sistemi devreye girerek savaş ya da kaç (fight-or-flight) tepkisini başlatır. Bu süreçte kalp atışı hızlanır, adrenalin salgılanır ve kas grupları harekete hazırlanır.

Başa çıkma stratejileri iki ana gruba ayrılır. Probleme odaklı başa çıkma, stresin kaynağını doğrudan hedef alır; sorun çözme, planlama ve bilgi toplama bu yaklaşıma girer. Duygusallığa odaklı başa çıkma ise stresin yarattığı duygusal sıkıntıyı azaltmayı amaçlar; sosyal destek arama, dinlenme ve kabul stratejileri bu gruba dahildir.

Sağlıklı başa çıkma biçimleri arasında düzenli egzersiz, meditasyon, zaman yönetimi ve sosyal bağlantılar sayılabilir. Alkol ya da kaçınma gibi sağlıksız stratejiler ise stresi geçici olarak bastırır ancak uzun vadede durumu kötüleştirir.

TYT sınavlarında savaş ya da kaç tepkisi ve başa çıkma stratejileri sıklıkla sorulan konular arasındadır.$$, 170, 6, '{tyt,ayt}', '[{"question":"Savaş ya da kaç tepkisi hangi sistem tarafından başlatılır?","options":["Parasempatik sinir sistemi","Sempatik sinir sistemi","Merkezi sinir sistemi","Endokrin sistem"],"correctIndex":1},{"question":"Probleme odaklı başa çıkma stratejisine hangi örnek verilebilir?","options":["Sosyal destek arama","Dinlenme ve kabul","Sorun çözme ve planlama","Kaçınma"],"correctIndex":2},{"question":"Kronik stresin uzun vadede yarattığı etki nedir?","options":["Performansı artırır","Sağlığı ciddi biçimde tehdit eder","Duygusal zekayı geliştirir","Motivasyonu yükseltir"],"correctIndex":1},{"question":"Aşağıdakilerden hangisi sağlıklı bir başa çıkma biçimidir?","options":["Alkol kullanımı","Kaçınma","Meditasyon ve zaman yönetimi","Stresi bastırma"],"correctIndex":2}]'::jsonb),
  ('psikoloji', 'Bellek Türleri: Duyusal, Kısa Süreli ve Uzun Süreli', $$Bellek, bilginin kodlanması, depolanması ve gerektiğinde geri çağrılması süreçlerini kapsayan bilişsel bir işlevdir. Psikolojide bellek genel olarak üç ana türe ayrılarak incelenir.

Duyusal bellek, çevreden gelen bilgilerin milisaniyeler ile birkaç saniye arasında tutulduğu ilk aşamadır. Görsel duyusal belleğe ikonik bellek, işitsel duyusal belleğe ise ekhoik bellek adı verilir.

Kısa süreli bellek (çalışan bellek), dikkat edildiğinde bilginin birkaç saniye ile birkaç dakika arasında tutulduğu ikinci aşamadır. Miller'in araştırmalarına göre bu belleğin kapasitesi yaklaşık yedi unsurdur.

Uzun süreli bellek, bilginin günlerden yıllara hatta ömür boyu saklanabildiği son aşamadır. Açık (bilinçli) ve örtük (bilinçsiz) olmak üzere iki alt türe ayrılır. Açık bellek; anısal (episodik) ve anlamsal (semantik) belleği kapsar. Örtük bellek ise bisiklet sürme gibi prosedürel bilgileri barındırır.

TYT sınavlarında bellek türleri arasındaki farklar ve unutma süreci hakkındaki sorular düzenli olarak karşımıza çıkmaktadır.$$, 167, 5, '{tyt,ayt}', '[{"question":"Duyusal bellekte bilgi ne kadar süre tutulur?","options":["Birkaç dakika","Milisaniyeler ile birkaç saniye arasında","Birkaç saat","Gün boyu"],"correctIndex":1},{"question":"Miller''e göre kısa süreli belleğin kapasitesi yaklaşık kaç unsurdur?","options":["Üç","Beş","Yedi","On"],"correctIndex":2},{"question":"Bisiklet sürme gibi beceriler belleğin hangi türünde saklanır?","options":["Episodik bellek","Semantik bellek","Duyusal bellek","Prosedürel (örtük) bellek"],"correctIndex":3},{"question":"Uzun süreli belleğin açık alt türleri nelerdir?","options":["İkonik ve ekhoik bellek","Episodik ve semantik bellek","Kısa süreli ve duyusal bellek","Prosedürel ve örtük bellek"],"correctIndex":1}]'::jsonb),
  ('psikoloji', 'Piaget''nin Bilişsel Gelişim Kuramı', $$Jean Piaget, çocukların dünyayı yetişkinlerden farklı biçimde kavradığını savunarak bilişsel gelişim kuramını geliştirdi. Piaget'ye göre bilişsel gelişim dört evrede gerçekleşir ve bu evreler biyolojik olgunlaşma ile çevre etkileşimiyle belirlenir.

Birinci evre duyusal-motor dönemdir (0-2 yaş). Bebek çevresiyle duyular ve motor hareketler aracılığıyla etkileşime girer. Nesne kalıcılığı kavramı bu dönemde kazanılır.

İkinci evre işlem öncesi dönemdir (2-7 yaş). Dil gelişimi hızlanır ancak çocuk düşüncesi hâlâ benmerkezcidir ve mantıksal işlemleri gerçekleştiremez. Korunum kavramı henüz tam olarak gelişmemiştir.

Üçüncü evre somut işlemler dönemidir (7-11 yaş). Çocuk mantıksal düşünebilir ancak soyut kavramlarla başa çıkmakta güçlük çeker. Korunum, sınıflandırma ve sıralama bu dönemde yerleşir.

Dördüncü ve son evre soyut işlemler dönemidir (11 yaş ve üzeri). Birey soyut kavramlar üzerinde düşünebilir, hipotez kurabilir ve sistemli akıl yürütme yapabilir.

TYT sınavlarında Piaget'nin dört evresi ve temel kavramlar sıkça sorulmaktadır.$$, 171, 5, '{tyt,ayt}', '[{"question":"Piaget''nin kuramına göre kaç bilişsel gelişim evresi vardır?","options":["İki","Üç","Dört","Beş"],"correctIndex":2},{"question":"Nesne kalıcılığı kavramı hangi dönemde kazanılır?","options":["İşlem öncesi dönem","Somut işlemler dönemi","Duyusal-motor dönem","Soyut işlemler dönemi"],"correctIndex":2},{"question":"Benmerkezcilik düşüncesi hangi döneme özgüdür?","options":["Duyusal-motor dönem","İşlem öncesi dönem","Somut işlemler dönemi","Soyut işlemler dönemi"],"correctIndex":1},{"question":"Hipotez kurma ve sistemli akıl yürütme hangi dönemde ortaya çıkar?","options":["Duyusal-motor dönem","İşlem öncesi dönem","Somut işlemler dönemi","Soyut işlemler dönemi"],"correctIndex":3}]'::jsonb),
  ('psikoloji', 'Motivasyon Teorileri: İçsel ve Dışsal Motivasyon', $$Motivasyon, bireyi bir hedefe yönelten ve bu hedefe ulaşmak için çaba harcamasını sağlayan güçtür. Psikolojide motivasyon genel olarak içsel ve dışsal olmak üzere ikiye ayrılır.

İçsel motivasyon, bireyin bir etkinliği kendi başına anlamlı, zevkli ya da tatmin edici bulması nedeniyle gerçekleştirmesidir. Resim yapmayı sevdiği için resim yapan bir çocuk içsel olarak motive olmaktadır.

Dışsal motivasyon ise bireyin bir ödül kazanmak ya da cezadan kaçınmak amacıyla davranması durumunda ortaya çıkar. Para, not ya da övgü dışsal motive edicilere örnek gösterilebilir.

Deci ve Ryan tarafından geliştirilen Öz Belirleme Kuramı, insanın üç temel psikolojik ihtiyacı karşılandığında içsel motivasyonun en yüksek düzeye ulaştığını savunur: yeterlik (competence), özerklik (autonomy) ve bağlılık (relatedness).

Araştırmalar, dışsal ödüllerin zaman zaman içsel motivasyonu azaltabileceğini ortaya koymuştur. Bu durum "motivasyon kalabalığı" (crowding out) ya da aşırı yargılama etkisi olarak adlandırılır.

Motivasyon kuramları TYT sınavlarında sıkça karşılaşılan konular arasındadır.$$, 169, 5, '{tyt,ayt}', '[{"question":"İçsel motivasyona en iyi örnek hangisidir?","options":["Para kazanmak için çalışmak","Not almak için ders okumak","Sevdiği için resim yapan bir çocuk","Ceza almamak için kurallara uymak"],"correctIndex":2},{"question":"Dışsal motivasyona örnek olarak hangisi verilebilir?","options":["Merak nedeniyle kitap okumak","Hobi olarak müzik çalmak","Ödül kazanmak için yarışmaya katılmak","Anlam arayışıyla gönüllü çalışmak"],"correctIndex":2},{"question":"Öz Belirleme Kuramına göre içsel motivasyonu destekleyen üç temel ihtiyaç nelerdir?","options":["Güç, statü ve ödül","Yeterlik, özerklik ve bağlılık","Güvenlik, saygınlık ve özgürlük","Başarı, para ve tanınma"],"correctIndex":1},{"question":"Aşırı yargılama etkisi ne anlama gelir?","options":["İçsel motivasyonun dışsal ödüllerle artması","Dışsal ödüllerin zaman zaman içsel motivasyonu azaltması","Ödüllerin davranışı kalıcı olarak pekiştirmesi","Cezanın motivasyonu tamamen yok etmesi"],"correctIndex":1}]'::jsonb),
  ('cografya', 'Türkiye''nin Yüzey Şekilleri: Ovalar, Dağlar ve Platolar', $$Türkiye'nin yüzey şekilleri oldukça engebeli ve çeşitlidir. Ülke topraklarının yaklaşık %55'ini dağlar oluşturmaktadır. Kuzey Anadolu'yu boydan boya geçen Kuzey Anadolu Dağları ile güneyden kuşatan Toros Dağları, ülkenin ana dağ sıralarıdır.

Platolar, ortalama yüksekliği fazla olan geniş düzlüklerdir. Türkiye'nin iç bölgelerinde yer alan Anadolu Platosu, yüzey şekilleri bakımından önemli bir yere sahiptir. Bu platoda bozkır bitki örtüsü hâkimdir ve kuraklık karakteristik bir özelliktir.

Ovalar ise tarım açısından büyük değer taşır. Çukurova, Gediz Ovası ve Konya Ovası Türkiye'nin en verimli tarım alanları arasındadır. Bu ovaların büyük bölümü akarsular tarafından aşındırılarak düzleştirilmiş alüvyal alanlardır.

Yüksek dağlar, bölgeler arasında hem iklimsel hem de beşeri farklılıklara yol açmaktadır. Dağların karanlık yamaçlarında yağış artar; güneş gören yamaçlarda ise iklim daha ılımandır.

LGS coğrafya sorularında Türkiye'nin başlıca ovası, dağı ve platosu sıkça sorulmaktadır.$$, 163, 4, '{lgs,tyt}', '[{"question":"Türkiye topraklarının yaklaşık kaçta kaçını dağlar oluşturmaktadır?","options":["%25","%35","%55","%70"],"correctIndex":2},{"question":"Aşağıdakilerden hangisi Türkiye''nin en verimli ovalarından biri değildir?","options":["Çukurova","Gediz Ovası","Konya Ovası","Kuzey Anadolu Dağları"],"correctIndex":3},{"question":"Anadolu Platosunda hâkim bitki örtüsü nedir?","options":["Orman","Maki","Bozkır (step)","Tundra"],"correctIndex":2},{"question":"Alüvyal ovalar nasıl oluşmuştur?","options":["Rüzgârın kum biriktirmesiyle","Volkanik faaliyetlerle","Akarsuların taşıyıp biriktirdiği materyallerle","Buzul erimesiyle"],"correctIndex":2}]'::jsonb),
  ('cografya', 'Türkiye''de Nüfus ve İç Göç', $$Türkiye'nin nüfusu 2023 yılı itibarıyla 85 milyonu aşmıştır. Ancak nüfus ülke genelinde dengeli dağılmamaktadır. Batı kıyıları, Marmara Bölgesi ve büyük sanayi kentleri yoğun nüfuslu alanlardır; Doğu ve Güneydoğu Anadolu'nun dağlık kesimleri ise seyrek nüfuslu bölgelerdir.

İç göç, kırsal kesimden kentlere yönelik nüfus hareketleridir. Türkiye 1950'lerden itibaren yoğun bir iç göç sürecine girmiştir. İstanbul, Ankara ve İzmir başta olmak üzere büyük şehirler bu dönemde hızla büyümüştür.

İç göçün temel nedenleri arasında tarımın makineleşmesiyle birlikte kırsal alanda iş imkânlarının azalması, kentlerdeki eğitim ve sağlık hizmetlerine olan talep ve sanayileşmenin getirdiği iş fırsatları sayılabilir.

Göçün kentler üzerindeki etkileri arasında gecekondulaşma, alt yapı sorunları ve kentsel yoksulluk öne çıkmaktadır. Öte yandan göç veren bölgeler yaşlı ve nüfus kaybı sorunuyla karşı karşıya kalmaktadır.

LGS sınavlarında nüfus dağılımı, göç nedenleri ve sonuçları sıklıkla sorulmaktadır.$$, 165, 4, '{lgs,tyt}', '[{"question":"Türkiye''de en yoğun nüfuslu bölgeler hangileridir?","options":["Doğu Anadolu''nun dağlık kesimleri","Güneydoğu Anadolu''nun kırsal alanları","Batı kıyıları ve Marmara Bölgesi","İç Anadolu platoları"],"correctIndex":2},{"question":"Türkiye''de yoğun iç göç süreci ne zaman başlamıştır?","options":["1920''lerden itibaren","1950''lerden itibaren","1980''lerden itibaren","2000''lerden itibaren"],"correctIndex":1},{"question":"İç göçün temel nedenleri arasında hangisi yer almaz?","options":["Tarımın makineleşmesiyle kırsal iş imkânlarının azalması","Kentlerdeki eğitim ve sağlık hizmetleri talebi","Sanayileşmenin iş fırsatları sunması","Kentlerdeki nüfus fazlasının kırsal alanlara dönmesi"],"correctIndex":3},{"question":"Göç veren bölgeler hangi sorunla karşılaşır?","options":["Kentsel yoksulluk","Gecekondulaşma","Yaşlı nüfus yapısı ve nüfus kaybı","Altyapı yetersizliği"],"correctIndex":2}]'::jsonb),
  ('cografya', 'Ekonomik Coğrafya: Türkiye''de Tarım Bölgeleri', $$Türkiye, farklı iklim ve toprak koşulları sayesinde çok çeşitli tarımsal ürünler yetiştiren önemli bir tarım ülkesidir. Ülke, birçok üründe dünya üretiminde üst sıralarda yer almaktadır.

Karadeniz Bölgesi, nemli iklimi sayesinde çay ve fındık üretiminde öne çıkar. Türkiye dünya fındık üretiminin yaklaşık %70'ini sağlamaktadır. Ege Bölgesi; zeytin, incir, üzüm ve pamuk üretim merkezleridir. Akdeniz Bölgesi ise turunçgil, muz ve narenciye tarımıyla dikkat çeker.

İç Anadolu tahıl üretiminin kalbidir. Geniş düzlüklerde buğday ve arpa yetiştirilir. Konya Ovası Türkiye'nin en önemli hububat havzalarından biridir. Güneydoğu Anadolu'da ise Harran Ovası'nda sulama kanalları aracılığıyla pamuk ve mısır üretimi yapılmaktadır.

Tarımda verimlilik iklim koşullarına, sulama imkânlarına ve toprak yapısına bağlıdır. Son yıllarda akıllı tarım ve modern sulama teknolojileri tarım verimliliğini artırmak için yaygın biçimde kullanılmaktadır.

LGS ve TYT coğrafya sorularında Türkiye'nin tarım bölgeleri ve ürünleri sıkça yer almaktadır.$$, 164, 5, '{lgs,tyt}', '[{"question":"Türkiye, dünya fındık üretiminin yaklaşık kaçta kaçını sağlamaktadır?","options":["%30","%50","%70","%90"],"correctIndex":2},{"question":"Ege Bölgesi''nin öne çıkan tarım ürünleri hangileridir?","options":["Çay ve fındık","Zeytin, incir, üzüm ve pamuk","Turunçgil ve muz","Buğday ve arpa"],"correctIndex":1},{"question":"İç Anadolu''da yetişen başlıca tarım ürünleri nelerdir?","options":["Çay ve fındık","Zeytin ve incir","Buğday ve arpa","Turunçgil ve muz"],"correctIndex":2},{"question":"Harran Ovası hangi bölgede yer alır ve hangi ürünleriyle bilinir?","options":["Ege — zeytin ve üzüm","Akdeniz — narenciye ve muz","Güneydoğu Anadolu — pamuk ve mısır","Karadeniz — çay ve fındık"],"correctIndex":2}]'::jsonb),
  ('cografya', 'Türkiye''nin Komşuları ve Jeopolitik Konumu', $$Türkiye, Asya ile Avrupa kıtalarını birleştiren stratejik bir konumda bulunmaktadır. Ülke sekiz komşuyla kara sınırına sahiptir: kuzeybatıda Bulgaristan ve Yunanistan; doğuda Gürcistan, Ermenistan, Azerbaycan (Nahçıvan) ve İran; güneyde Irak ve Suriye.

Türkiye'nin deniz sınırları da son derece önemlidir. Kuzeyde Karadeniz, batıda Ege Denizi ve güneyde Akdeniz ülkeyi üç taraftan kuşatmaktadır. İstanbul Boğazı ve Çanakkale Boğazı, Karadeniz ile Akdeniz arasındaki tek deniz geçididir ve küresel ticaret için hayati önem taşır.

Bu jeopolitik konum Türkiye'yi tarihsel süreçte önemli bir ticaret, kültür ve siyaset merkezi hâline getirmiştir. İpek Yolu, tarihte Türkiye topraklarından geçen önemli ticaret güzergâhlarından biridir.

Günümüzde Türkiye; NATO üyeliği, AB adaylığı ve çevre ülkelerle ilişkileri bakımından bölgesel ve küresel siyasette etkin bir rol üstlenmektedir.

LGS sınavlarında Türkiye'nin komşuları ve konumunun getirdiği avantajlar ve zorluklar sıkça sorulmaktadır.$$, 162, 4, '{lgs,tyt}', '[{"question":"Türkiye''nin kara sınırı bulunan komşu sayısı kaçtır?","options":["Altı","Yedi","Sekiz","Dokuz"],"correctIndex":2},{"question":"İstanbul Boğazı ve Çanakkale Boğazı hangi iki denizi birbirine bağlar?","options":["Ege Denizi ve Akdeniz","Karadeniz ve Akdeniz","Karadeniz ve Ege Denizi","Akdeniz ve Kızıldeniz"],"correctIndex":1},{"question":"Türkiye''nin güney sınırında hangi iki ülke yer almaktadır?","options":["Yunanistan ve Bulgaristan","Gürcistan ve Ermenistan","Irak ve Suriye","İran ve Azerbaycan"],"correctIndex":2},{"question":"Türkiye''nin jeopolitik konumunun tarihsel önemi nedir?","options":["Yalnızca askeri açıdan önemlidir","Ticaret, kültür ve siyaset merkezi hâline gelmesini sağlamıştır","Yalnızca enerji kaynakları nedeniyle önemlidir","Çevre ülkelere ham madde sağlamaktadır"],"correctIndex":1}]'::jsonb),
  ('cografya', 'Su Kaynakları ve Türkiye''nin Büyük Havzaları', $$Su, yaşamın ve tarımın temel kaynağıdır. Türkiye zengin akarsu ağına sahip olmakla birlikte su kaynaklarının dağılımı bölgeden bölgeye büyük farklılıklar göstermektedir.

Fırat ve Dicle nehirleri, Doğu Anadolu'dan doğup Mezopotamya'yı sulayan iki büyük akarsudur. Bu nehirlerin havzası hem Türkiye hem de Orta Doğu için stratejik öneme sahiptir. GAP (Güneydoğu Anadolu Projesi) bu havzalarda inşa edilen barajlar ve sulama kanalları aracılığıyla bölgenin tarımsal potansiyelini geliştirmeyi amaçlamaktadır.

Kızılırmak, Türkiye'nin en uzun iç nehridir. Anadolu platosunu kat ederek Karadeniz'e dökülür. Yeşilırmak ve Sakarya da kuzeye akan önemli nehirler arasında yer alır.

Suların yönetimi; enerji üretimi, içme suyu temini ve sulama bakımından kritik politika alanları arasındadır. Türkiye'de hidroelektrik santraller önemli bir enerji kaynağı oluşturmakta ve ülkenin enerji bağımsızlığına katkı sağlamaktadır.

LGS sınavlarında nehir havzaları, barajlar ve su yönetimi sıkça sorulan coğrafya konuları arasındadır.$$, 163, 4, '{lgs,tyt}', '[{"question":"Kızılırmak''ın temel özelliği nedir?","options":["Güneye akan en uzun nehirdir","Türkiye''nin en uzun iç nehridir","Ege Denizi''ne dökülür","Fırat''ın koludur"],"correctIndex":1},{"question":"GAP Projesi hangi amaçla hayata geçirilmiştir?","options":["Karadeniz kıyılarını geliştirmek için","Fırat ve Dicle havzalarında tarımsal potansiyeli geliştirmek için","İstanbul''un su ihtiyacını karşılamak için","Ege nehirlerini ıslah etmek için"],"correctIndex":1},{"question":"Fırat ve Dicle nehirleri hangi bölgeden doğar?","options":["İç Anadolu","Ege Bölgesi","Doğu Anadolu","Güneybatı Anadolu"],"correctIndex":2},{"question":"Hidroelektrik santraller Türkiye için ne anlama gelir?","options":["Yalnızca sulama amaçlıdır","Enerji bağımsızlığına katkı sağlayan önemli bir enerji kaynağıdır","Sadece İç Anadolu''da yaygındır","Çevre kirliliğinin başlıca nedenidir"],"correctIndex":1}]'::jsonb),
  ('cografya', 'Deprem Kuşakları ve Türkiye''nin Sismik Yapısı', $$Dünya üzerindeki deprem faaliyetleri belirli kuşaklar boyunca yoğunlaşmaktadır. Bu kuşakların en önemlileri Pasifik Ateş Çemberi ve Alp-Himalaya kuşağıdır. Türkiye, Alp-Himalaya deprem kuşağı üzerinde yer almaktadır.

Türkiye'nin sismik yapısı büyük ölçüde üç levha hareketinden kaynaklanmaktadır: Anadolu Levhası, Avrasya Levhası ve Arap Levhası. Arap Levhası'nın kuzeye doğru hareketi, Anadolu Levhası'nı batıya itmektedir. Bu hareket sonucunda Kuzey Anadolu Fay Hattı ve Doğu Anadolu Fay Hattı oluşmuştur.

Kuzey Anadolu Fay Hattı, Erzincan'dan Marmara'ya uzanan sağ yanal atımlı bir fay sistemidir. 1999 Gölcük ve Düzce depremleri bu fayın yol açtığı yıkıcı sonuçlara somut örneklerdir.

Deprem riskini azaltmak için binaların depreme dayanıklı inşa edilmesi, imar planlarında fay hatlarının dikkate alınması ve toplumsal farkındalığın artırılması gerekmektedir.

LGS sınavlarında Türkiye'nin fay hatları, deprem bölgeleri ve alınması gereken önlemler sıkça sorulan konulardandır.$$, 165, 5, '{lgs,tyt}', '[{"question":"Türkiye hangi deprem kuşağı üzerinde yer almaktadır?","options":["Pasifik Ateş Çemberi","Alp-Himalaya kuşağı","Atlantik Okyanus kuşağı","Afrika Rift kuşağı"],"correctIndex":1},{"question":"Kuzey Anadolu Fay Hattı nereden nereye uzanmaktadır?","options":["Akdeniz''den Karadeniz''e","İstanbul''dan Doğu Anadolu''ya","Erzincan''dan Marmara''ya","Van Gölü''nden Ege kıyılarına"],"correctIndex":2},{"question":"Türkiye''nin sismik yapısının temel nedeni nedir?","options":["Volkanik faaliyetler","Anadolu, Avrasya ve Arap levhalarının hareketi","Büyük nehirlerin erozyonu","İklim değişikliği"],"correctIndex":1},{"question":"Deprem riskini azaltmak için hangi önlem alınmalıdır?","options":["Nüfusu kırsal alanlara taşımak","Binaları depreme dayanıklı inşa etmek ve fay hatlarını imar planlarında dikkate almak","Deprem bölgelerinde tarım yapmamak","Tüm şehirleri deniz kıyısına kurmak"],"correctIndex":1}]'::jsonb),
  ('cografya', 'Küresel İklim Değişikliği ve Coğrafi Sonuçları', $$İklim değişikliği, atmosferdeki sera gazı birikiminin artmasıyla birlikte küresel ortalama sıcaklıkların yükselmesi sürecidir. Sanayileşme, ulaşım ve enerji üretiminde fosil yakıt kullanımı bu değişimin başlıca nedenleri arasındadır.

Küresel ısınmanın coğrafi sonuçları çok boyutludur. Buzulların erimesi deniz seviyelerini yükseltmekte ve kıyı kentlerini tehdit etmektedir. Aşırı hava olaylarının sıklığı artmaktadır; seller, kuraklıklar ve fırtınalar daha yıkıcı boyutlara ulaşmaktadır.

Türkiye'de de iklim değişikliğinin etkileri giderek belirginleşmektedir. Güney ve iç bölgelerde çölleşme eğilimi artmakta, su kaynaklarının azalması tarım ve içme suyu güvenliğini tehdit etmektedir. Akdeniz havzasının en kırılgan bölgelerinden biri olarak Türkiye, bu süreçten derinden etkilenmektedir.

Uluslararası toplum iklim değişikliğiyle mücadele için Paris Anlaşması çerçevesinde karbonsuzlaşma hedefleri belirlemiştir. Yenilenebilir enerji kaynaklarına geçiş, enerji verimliliği ve yeşil ekonomi modeli bu süreçte kritik rol oynamaktadır.

LGS ve TYT sınavlarında iklim değişikliğinin nedenleri ve coğrafi sonuçları düzenli olarak sorulmaktadır.$$, 167, 5, '{lgs,tyt}', '[{"question":"Küresel ısınmanın başlıca nedenleri arasında hangisi yer alır?","options":["Ormanların genişlemesi","Fosil yakıt kullanımı ve sanayileşme","Nüfus azalması","Tarım alanlarının daralması"],"correctIndex":1},{"question":"Buzulların erimesi hangi coğrafi sonuca yol açmaktadır?","options":["Kuraklıkların azalması","Tarım veriminin artması","Deniz seviyelerinin yükselmesi ve kıyı kentlerinin tehdit altına girmesi","İç bölgelerde yağışın artması"],"correctIndex":2},{"question":"Türkiye''de iklim değişikliğinin en belirgin etkilerinden biri nedir?","options":["Karadeniz kıyılarında kuruluğun artması","Güney ve iç bölgelerde çölleşme eğiliminin artması","Kış mevsiminin uzaması","Yağış miktarının genel olarak artması"],"correctIndex":1},{"question":"Paris Anlaşması''nın temel amacı nedir?","options":["Deniz ticaretini düzenlemek","Karbonsuzlaşma hedefleriyle iklim değişikliğiyle mücadele etmek","Yenilenebilir enerji ihracatını artırmak","Sera gazlarını artırmak"],"correctIndex":1}]'::jsonb),
  ('cografya', 'Enerji Kaynakları: Yenilenebilir ve Fosil Yakıtlar', $$Enerji, modern uygarlığın en temel gereksinimlerinden biridir. Enerji kaynakları yenilenebilir ve yenilenemez olmak üzere iki ana gruba ayrılır.

Fosil yakıtlar; kömür, petrol ve doğalgaz gibi milyonlarca yıl boyunca oluşmuş organik maddelerden elde edilir. Bu kaynaklar tükenebilir niteliktedir ve yakıldığında karbondioksit ve diğer sera gazlarını atmosfere bırakırlar. Türkiye kömür rezervleri bakımından zengin olmakla birlikte petrol ve doğalgazda büyük ölçüde ithalata bağımlıdır.

Yenilenebilir enerji kaynakları ise güneş, rüzgâr, hidroelektrik, jeotermal ve biyokütle enerjisini kapsar. Bu kaynaklar doğal süreçler sayesinde sürekli yenilenir ve çevre dostu niteliktedir. Türkiye, güneş ve rüzgâr enerjisi potansiyeli yüksek bir ülkedir.

Güneş enerjisinde Ege ve Akdeniz bölgeleri öne çıkarken rüzgâr enerjisinde kıyı şeritleri büyük avantaj sağlar. Jeotermal enerji ise özellikle Batı Anadolu'da yaygın biçimde kullanılmaktadır.

Enerji bağımsızlığı ve sürdürülebilir kalkınma hedefleri doğrultusunda Türkiye yenilenebilir enerji yatırımlarını artırmaktadır.$$, 165, 5, '{lgs,tyt}', '[{"question":"Fosil yakıtların temel olumsuz özelliği nedir?","options":["Tükenebilir olmaları ve sera gazı salmaları","Pahalı olmaları ve taşınamaz olmaları","Yalnızca kışın kullanılabilmeleri","Enerji verimliliğinin düşük olması"],"correctIndex":0},{"question":"Türkiye''nin jeotermal enerji potansiyeli en yüksek bölge hangisidir?","options":["Doğu Anadolu","Karadeniz kıyıları","Batı Anadolu","İç Anadolu platoları"],"correctIndex":2},{"question":"Yenilenebilir enerji kaynakları arasında hangisi yer almaz?","options":["Güneş enerjisi","Rüzgâr enerjisi","Doğalgaz","Hidroelektrik"],"correctIndex":2},{"question":"Türkiye enerji alanında hangi konuda büyük ölçüde ithalata bağımlıdır?","options":["Kömür","Hidroelektrik","Petrol ve doğalgaz","Güneş enerjisi"],"correctIndex":2}]'::jsonb),
  ('cografya', 'Kentleşme ve Şehirleşme Sorunları', $$Kentleşme, nüfusun kırsal alanlardan kentlere doğru yer değiştirmesi ve kentlerin büyümesi sürecidir. Sanayileşmeyle birlikte hız kazanan kentleşme, 20. yüzyılın en belirgin demografik dönüşümlerinden biri olmuştur.

Türkiye'de kentleşme oranı 1950'de yaklaşık %25 iken günümüzde %80'in üzerine çıkmıştır. Bu hızlı dönüşüm çeşitli sorunları beraberinde getirmiştir. Plansız yapılaşma ve gecekondulaşma kentlerin en önemli sorunları arasındadır. Altyapı yetersizliği, trafik sıkışıklığı, konut açığı ve çevre kirliliği büyük şehirlerde kronik sorunlar hâline gelmiştir.

Kentleşmenin sosyal sonuçları da göz ardı edilemez. Kültürel kimlik sorunları, toplumsal yalnızlaşma ve eşitsizliklerin derinleşmesi bu başlık altında değerlendirilebilir. Öte yandan kentle birlikte gelen yenilikler; eğitim, sağlık ve ekonomik fırsatları da beraberinde taşımaktadır.

Sürdürülebilir kentleşme, mevcut kaynaklara zarar vermeden gelecek nesillere de yaşanabilir bir şehir ortamı bırakabilmeyi hedefler. Akıllı şehircilik uygulamaları bu hedef doğrultusunda giderek daha fazla önem kazanmaktadır.

LGS sınavlarında hızlı kentleşmenin nedenleri ve sonuçları düzenli olarak sorulan konular arasındadır.$$, 163, 4, '{lgs,tyt}', '[{"question":"Türkiye''de kentleşme oranı 1950''de yaklaşık kaçtı?","options":["%10","%25","%50","%70"],"correctIndex":1},{"question":"Hızlı kentleşmenin başlıca sorunları arasında hangisi yer almaz?","options":["Gecekondulaşma","Trafik sıkışıklığı","Altyapı yetersizliği","Tarım alanlarının artması"],"correctIndex":3},{"question":"Sürdürülebilir kentleşmenin temel amacı nedir?","options":["Şehirleri olabildiğince büyütmek","Kaynakları tüketmeden gelecek nesillere yaşanabilir şehir bırakmak","Kırsal alanları tamamen ortadan kaldırmak","Nüfusu tek bir merkezde toplamak"],"correctIndex":1},{"question":"Kentleşmenin olumlu sonuçları arasında hangisi sayılabilir?","options":["Gecekondulaşma","Çevre kirliliği","Eğitim, sağlık ve ekonomik fırsatlara erişimin artması","Trafik sorunlarının artması"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Sinir Sistemi: Merkezi ve Çevresel', $$Sinir sistemi, vücudun tüm işlevlerini koordine eden ve çevreden gelen uyaranlara yanıt veren karmaşık bir ağdır. İki ana bölüme ayrılır: merkezi sinir sistemi (MSS) ve çevresel sinir sistemi (ÇSS).

Merkezi sinir sistemi beyin ve omurilikten oluşur. Beyin; düşünme, duygu, hafıza ve hareket kontrolünden sorumlu en üst merkezdir. Omurilik ise beyinle vücut arasındaki iletişimi sağlar ve bazı refleks tepkilerinin merkezidir.

Çevresel sinir sistemi, beyin ve omurilikten çıkıp vücudun tüm bölgelerine ulaşan sinirlerden oluşur. İki alt gruba ayrılır: somatik sinir sistemi ve otonom sinir sistemi. Somatik sistem istemli hareketleri kontrol ederken otonom sistem kalp atışı ve sindirim gibi istemsiz işlevleri düzenler.

Otonom sinir sistemi sempatik ve parasempatik olmak üzere iki bölüme ayrılır. Sempatik sistem stres durumunda "savaş ya da kaç" tepkisini harekete geçirir; parasempatik sistem ise dinlenme ve onarım süreçlerini yönetir.

TYT sınavlarında sinir sistemi bölümleri ve işlevleri sıklıkla sorulmaktadır.$$, 166, 5, '{lgs,tyt}', '[{"question":"Merkezi sinir sistemi hangi yapılardan oluşur?","options":["Sinirler ve ganglionlar","Beyin ve omurilik","Somatik ve otonom sistem","Sempatik ve parasempatik sistem"],"correctIndex":1},{"question":"Otonom sinir sisteminin alt grupları hangileridir?","options":["Beyin ve omurilik","Somatik ve otonom","Sempatik ve parasempatik","Merkezi ve çevresel"],"correctIndex":2},{"question":"Somatik sinir sistemi ne işlev görür?","options":["Kalp atışını düzenler","Sindirim işlevini kontrol eder","İstemli hareketleri kontrol eder","Stres tepkisini yönetir"],"correctIndex":2},{"question":"Parasempatik sinir sistemi hangi süreçleri yönetir?","options":["Savaş ya da kaç tepkisi","Adrenalin salgılanması","Dinlenme ve onarım süreçleri","İstemli kas hareketleri"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Endokrin Sistem ve Hormonlar', $$Endokrin sistem, kan dolaşımı aracılığıyla hormon salgılayan bez ve organların oluşturduğu iletişim ağıdır. Hormonlar, vücuttaki çeşitli işlevleri düzenleyen kimyasal haberci moleküllerdir.

Hipofiz bezi, "bez bezlerinin bezi" olarak bilinir çünkü diğer endokrin bezlerin salgı faaliyetlerini düzenler. Büyüme hormonu, tiroid uyarıcı hormon ve üreme hormonları hipofizden salgılanır.

Tiroid bezi, boyundaki kelebek şeklindeki bezdir ve tiroksin hormonunu üretir. Tiroksin metabolizmayı, büyümeyi ve vücut ısısını düzenler. Yetersiz tiroid salgısı hipotiroidi, fazla salgı ise hipertiroidi oluşturur.

Böbreküstü bezleri adrenalin ve kortizol hormonlarını salgılar. Adrenalin stres durumlarında kalp hızını artırır; kortizol ise uzun süreli stresin yönetiminde rol oynar. Pankreas; insülin ve glukagon salgılayarak kan şekerini düzenler. İnsülin yetersizliği diyabete yol açar.

Cinsiyet hormonları olan östrojen ve testosteron, üreme organlarının gelişimi ve ikincil cinsiyet özelliklerinin belirginleşmesini sağlar.

TYT sınavlarında endokrin bezler, hormonlar ve işlevleri sıklıkla sorulmaktadır.$$, 167, 6, '{lgs,tyt}', '[{"question":"Hipofiz bezinin temel işlevi nedir?","options":["Kan şekerini düzenlemek","Diğer endokrin bezlerin salgı faaliyetlerini düzenlemek","Metabolizmayı kontrol etmek","Stres tepkisini başlatmak"],"correctIndex":1},{"question":"Tiroksin hormonu hangi bezi tarafından üretilir?","options":["Hipofiz","Böbreküstü","Pankreas","Tiroid"],"correctIndex":3},{"question":"İnsülin hormonu yetersizliği hangi hastalığa yol açar?","options":["Hipotiroidi","Hipertiroidi","Diyabet","Osteoporoz"],"correctIndex":2},{"question":"Adrenalin hormonu hangi durumda salgılanır?","options":["Uykuya geçişte","Sindirim sırasında","Stres durumlarında","Büyüme sürecinde"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Kalp-Damar Sistemi', $$Kalp-damar sistemi, kanın vücutta dolaşımını sağlayan ve oksijen ile besin maddelerini dokulara taşıyan sistemdir. Kalp, atardamarlar, toplardamarlar ve kılcal damarlardan oluşur.

Kalp, göğüs boşluğunun sol tarafında yer alan ve dört odacıktan oluşan kasıl organdır. Sağ atrium ve sağ ventrikül, akciğerlere kan pompalar; sol atrium ve sol ventrikül ise oksijenlenen kanı tüm vücuda dağıtır.

Kan dolaşımı iki döngüden oluşur. Küçük kan dolaşımı (pulmoner dolaşım) kalp ile akciğerler arasında gerçekleşir ve kanın oksijenlenmesini sağlar. Büyük kan dolaşımı (sistemik dolaşım) ise oksijeni dokulardan alarak kalbe döndüren venöz kanı ve dokulara oksijen götüren arteryal kanı kapsar.

Kalp-damar hastalıkları dünyada önde gelen ölüm nedenlerinden biridir. Hipertansiyon, ateroskleroz ve kalp krizi bu hastalıkların başında gelir. Sağlıklı beslenme, düzenli egzersiz, sigarayı bırakma ve stresi yönetmek kalp sağlığını korumak için temel adımlardır.

TYT sınavlarında kalbin yapısı, kan dolaşımı döngüleri ve sağlık ilişkisi sıklıkla sorulmaktadır.$$, 168, 5, '{lgs,tyt}', '[{"question":"Kalp kaç odacıktan oluşmaktadır?","options":["İki","Üç","Dört","Altı"],"correctIndex":2},{"question":"Pulmoner dolaşım (küçük kan dolaşımı) nerede gerçekleşir?","options":["Kalp ile beyin arasında","Kalp ile akciğerler arasında","Akciğerler ile doku hücreleri arasında","Tüm vücut organları arasında"],"correctIndex":1},{"question":"Sol ventrikülün görevi nedir?","options":["Kanı akciğerlere pompalamak","Oksijensiz kanı sağ atriuma iletmek","Oksijenlenen kanı tüm vücuda dağıtmak","Kanı oksijenlendirmek"],"correctIndex":2},{"question":"Kalp sağlığını korumak için hangi yaşam tarzı değişikliği önerilmektedir?","options":["Yüksek yağlı diyet","Hareketsiz yaşam","Düzenli egzersiz ve sağlıklı beslenme","Uzun çalışma saatleri"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Sindirim Sistemi', $$Sindirim sistemi, besinlerin mekanik ve kimyasal süreçlerle parçalanarak vücut tarafından emilir hâle getirildiği organ sistemidir. Ağızdan başlayıp anüse kadar uzanan yaklaşık 8-10 metrelik bir kanaldır.

Sindirim ağızda başlar. Dişler besinleri mekanik olarak parçalar; tükürük bezlerinin salgıladığı amilaz enzimi karbonhidratların kimyasal sindirimini başlatır. Yemek borusu besinleri mideye taşır.

Mide, asidik ortamında proteinleri sindiren önemli bir organdır. Pepsin enzimi protein sindirimini katalize eder. Midenin kasılıp gevşemesiyle oluşan mekanik hareketler, besinleri ince bağırsağa hazırlar.

İnce bağırsak sindirim ve emilimin esas gerçekleştiği yerdir. Karaciğerden gelen safra ve pankreasın salgıladığı enzimler burada sindirimi tamamlar. Besin maddeleri bağırsak duvarındaki villüsler aracılığıyla kana geçer.

Kalın bağırsak su ve mineralleri geri emer; sindirilemeyen atıkları dışkıya dönüştürür. Bağırsak florasındaki yararlı bakteriler sindirim sağlığında kritik rol oynar.

TYT sınavlarında sindirim organları, enzimler ve emilim mekanizmaları sıkça sorulmaktadır.$$, 166, 5, '{lgs,tyt}', '[{"question":"Ağızda karbonhidrat sindirimini başlatan enzim hangisidir?","options":["Pepsin","Lipaz","Amilaz","Tripsin"],"correctIndex":2},{"question":"Protein sindirimi hangi organda gerçekleşir?","options":["Ağız","Mide","Kalın bağırsak","Karaciğer"],"correctIndex":1},{"question":"İnce bağırsakta besin emilimi hangi yapılar aracılığıyla gerçekleşir?","options":["Amilaz enzimleri","Safra kesesi","Villüsler","Midenin kasılmaları"],"correctIndex":2},{"question":"Kalın bağırsağın temel işlevi nedir?","options":["Protein sindirimini tamamlamak","Su ve mineralleri geri emip atıkları dışkıya dönüştürmek","Safra üretmek","İnsülin salgılamak"],"correctIndex":1}]'::jsonb),
  ('saglik', 'Solunum Sistemi', $$Solunum sistemi, vücuda oksijen alınmasını ve karbondioksitin atılmasını sağlayan organ sistemidir. Burun, farinks, larinks, trakea, bronşlar ve akciğerlerden oluşur.

Hava burundan alındığında ısıtılır, nemlendirilir ve filtre edilir. Larinks (gırtlak) sesi üretmek için de işlev görür. Trakea (nefes borusu), havayı bronşlara ileten kıkırdak halkalarla desteklenmiş bir borudur.

Akciğerler, her biri loblardan oluşan çift yapılı organlardır. Bronşlar daha küçük bronşiyollere, onlar da hava keseciklerine (alveollere) ayrılır. Alveol duvarları son derece incedir ve kılcal damarlarla çevrelenmiştir; gaz alışverişi burada gerçekleşir.

Solunum iki aşamadan oluşur: dış solunum ve iç solunum. Dış solunum; akciğerlerde oksijenin kana geçmesi ve karbondioksitin akciğerlere verilmesidir. İç solunum ise kandan hücrelere oksijen geçmesi ve hücrelerden karbondioksit alınmasıdır.

Sigara, astım ve hava kirliliği akciğer sağlığını tehdit eden başlıca etkenlerdir.

TYT sınavlarında solunum organları, alveollerde gaz alışverişi ve solunum hastalıkları sıklıkla sorulan konulardır.$$, 165, 5, '{lgs,tyt}', '[{"question":"Gaz alışverişi solunum sisteminde nerede gerçekleşir?","options":["Trakea","Bronşlar","Alveolller","Larinks"],"correctIndex":2},{"question":"Dış solunum nedir?","options":["Hücrelerde gerçekleşen enerji üretimi","Akciğerlerde oksijenin kana geçmesi ve karbondioksitin akciğerlere verilmesi","Hücrelerden karbondioksit alınması","Burundan havanın filtre edilmesi"],"correctIndex":1},{"question":"Trakenin yapısal özelliği nedir?","options":["Kas lifleriyle güçlendirilmiştir","Kılcal damarlarla kaplıdır","Kıkırdak halkalarla desteklenmiştir","Alveollerden oluşur"],"correctIndex":2},{"question":"Akciğer sağlığını tehdit eden başlıca etkenler arasında hangisi yer alır?","options":["Düzenli egzersiz","Dengeli beslenme","Sigara ve hava kirliliği","Yeterli su tüketimi"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Beslenme ve Vitaminler', $$Sağlıklı bir yaşam sürdürebilmek için vücudun makro ve mikro besin ögelerine ihtiyacı vardır. Makro besin ögeleri; karbonhidratlar, proteinler ve yağlardır. Mikro besin ögeleri ise vitaminler ve minerallerdir.

Karbonhidratlar, vücudun birincil enerji kaynağıdır. Proteinler doku yapımı, onarımı ve enzim üretimi için gereklidir. Yağlar ise hücre zarı yapısı, hormon üretimi ve yağda çözünen vitaminlerin taşınması için önemlidir.

Vitaminler, çok küçük miktarlarda gereksinim duyulan ancak hayati öneme sahip organik bileşiklerdir. Yağda çözünen vitaminler A, D, E ve K iken suda çözünen vitaminler B grubu ve C vitaminidir.

C vitamini bağışıklık sistemini destekler ve skorbüt hastalığını önler. D vitamini kalsiyum emilimini artırır; eksikliğinde raşitizm ve osteoporoz gelişebilir. B12 vitamini sinir sistemi sağlığı için kritiktir ve özellikle et, balık ve yumurtada bulunur.

Dengeli beslenme; çeşitli besin gruplarından yeterli miktarlarda tüketilmesiyle sağlanır. Tek tip beslenme vitamin ve mineral eksikliklerine zemin hazırlayabilir.

TYT sınavlarında vitaminlerin işlevleri, eksiklik belirtileri ve kaynakları sıklıkla sorulmaktadır.$$, 167, 5, '{lgs,tyt}', '[{"question":"Yağda çözünen vitaminler hangileridir?","options":["B grubu ve C vitamini","A, D, E ve K vitaminleri","C ve D vitaminleri","B12 ve B6 vitaminleri"],"correctIndex":1},{"question":"D vitamini eksikliği hangi hastalığa yol açabilir?","options":["Skorbüt","Anemi","Raşitizm ve osteoporoz","Gece körlüğü"],"correctIndex":2},{"question":"C vitamini eksikliğinde hangi hastalık ortaya çıkar?","options":["Raşitizm","Skorbüt","Pellegra","Beriberi"],"correctIndex":1},{"question":"Vücudun birincil enerji kaynağı hangi makro besin ögesidir?","options":["Protein","Yağ","Karbonhidrat","Vitamin"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Hücre Bölünmesi: Mitoz ve Mayoz', $$Hücre bölünmesi, organizmaların büyüme, onarım ve üreme işlevlerini yerine getirmesi için zorunlu bir süreçtir. İki temel hücre bölünmesi türü mitoz ve mayozdur.

Mitoz bölünme, bir hücreden iki özdeş hücre oluşturan bölünme tipidir. Vücut hücrelerinde gerçekleşir ve yara iyileşmesi, büyüme ve doku yenilenmesi için kullanılır. Mitoz sonucunda ana hücreyle aynı kromozom sayısına (diploit) sahip iki yavru hücre elde edilir.

Mayoz bölünme ise gamet (yumurta ve sperm) üretmek amacıyla üreme organlarında gerçekleşir. İki ardışık bölünme içerir ve sonucunda dört haploit yavru hücre oluşur. Bu hücreler ana hücrenin yarısı kadar kromozom taşır. Mayoz, kalıtsal çeşitliliğin kaynağı olduğundan evrimsel açıdan son derece önemlidir.

Mitoz profaz, metafaz, anafaz ve telofaz evrelerinden geçer. Mayoz ise bu evreleri iki tur boyunca gerçekleştirir.

Hücre bölünmesindeki hatalar, tümör oluşumuna ve genetik hastalıklara yol açabilir. Hücre döngüsünü kontrol eden mekanizmaların bozulması kanser sürecinin başlangıç noktasını oluşturabilir.

TYT sınavlarında mitoz ve mayoz bölünmeleri arasındaki farklar sıklıkla sorulmaktadır.$$, 168, 6, '{lgs,tyt}', '[{"question":"Mitoz bölünme sonucunda kaç yavru hücre oluşur?","options":["Bir","İki","Dört","Sekiz"],"correctIndex":1},{"question":"Mayoz bölünme nerede ve ne amaçla gerçekleşir?","options":["Tüm vücut hücrelerinde, büyüme için","Üreme organlarında, gamet üretmek için","Karaciğerde, onarım için","Kemik iliğinde, kan hücresi üretmek için"],"correctIndex":1},{"question":"Mayoz sonucunda oluşan yavru hücrelerde kromozom sayısı nasıldır?","options":["Ana hücreyle aynıdır (diploit)","Ana hücrenin iki katıdır","Ana hücrenin yarısıdır (haploit)","Kromozom sayısı değişkendir"],"correctIndex":2},{"question":"Hücre bölünmesindeki hatalar hangi sonuçlara yol açabilir?","options":["Daha hızlı büyüme","Tümör oluşumu ve genetik hastalıklar","Daha güçlü bağışıklık sistemi","Hormonal denge sağlanması"],"correctIndex":1}]'::jsonb),
  ('saglik', 'Genetik Hastalıklar ve Kalıtım', $$Kalıtım, ebeveynlerin genetik özelliklerini yavru bireylere aktarması sürecidir. Gregor Mendel'in bezelye deneyleriyle temelleri atılan genetik bilimi, günümüzde moleküler düzeyde incelenmektedir.

Her insan hücresi 46 kromozom taşır; bunların 44'ü vücut kromozomu (otozom), 2'si ise cinsiyet kromozomudur. Dişilerde XX, erkeklerde XY cinsiyet kromozomu bulunur. Gen, DNA'nın belirli bir özelliği kodlayan birimidir.

Dominant genler, karşı allel ne olursa olsun kendini ifade eden genlerdir. Çekinik (resesif) genler ise ancak her iki allelinin de aynı olması durumunda fenotipte görülür. Renk körlüğü ve hemofili X'e bağlı çekinik kalıtım örnekleridir.

Genetik hastalıklar kalıtsal ya da mutasyon kaynaklı olabilir. Down sendromu 21. kromozomun fazladan bir kopyasından kaynaklanır. Kistik fibrozis otozomal çekinik, Huntington hastalığı ise otozomal dominant kalıtım örneğidir.

Genetik danışmanlık, aile öyküsü olan bireylerin risklerini değerlendirmelerinde önemli bir araçtır.

TYT sınavlarında kalıtım ilkeleri, dominant-çekinik gen ilişkisi ve genetik hastalıklar sıkça sorulmaktadır.$$, 169, 6, '{lgs,tyt}', '[{"question":"İnsan hücrelerinde kaç adet cinsiyet kromozomu bulunur?","options":["1","2","23","46"],"correctIndex":1},{"question":"Down sendromu hangi kromozomal değişiklikten kaynaklanır?","options":["21. kromozomun fazladan bir kopyası","X kromozomu eksikliği","Y kromozomunun fazladan olması","13. kromozomun silinmesi"],"correctIndex":0},{"question":"Çekinik (resesif) gen hangi durumda fenotipte kendini gösterir?","options":["Yalnızca bir allel resesif olduğunda","Her iki allelin de resesif olması durumunda","Dominant genin yokluğunda","Her zaman fenotipte görülür"],"correctIndex":1},{"question":"Renk körlüğü hangi kalıtım desenine örnek gösterilebilir?","options":["Otozomal dominant","Otozomal çekinik","X''e bağlı çekinik","Y''ye bağlı kalıtım"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Kanser: Oluşumu ve Korunma Yolları', $$Kanser, vücut hücrelerinin kontrolsüz biçimde bölünerek kitle (tümör) oluşturması ve çevre dokulara yayılmasıyla karakterize hastalıklar grubudur. Dünya genelinde önde gelen ölüm nedenlerinden biri olmaya devam etmektedir.

Normal hücre döngüsünde bölünmeyi durduran mekanizmalar görev yapar. Ancak genetik mutasyonlar bu denetim noktalarını bozduğunda hücreler sürekli çoğalmaya başlar. Kanser hücreleri, bağışıklık sisteminin tanımakta güçlük çektiği değişiklikler gösterir.

Kanserin başlıca risk faktörleri arasında sigara kullanımı, alkol tüketimi, ultraviyole ışınları, kanserojen kimyasallara maruz kalma, sağlıksız beslenme ve genetik yatkınlık sayılabilir. Sigara, akciğer kanserinin en önemli tek nedenidir.

Erken tanı, kanserde hayatta kalma oranını önemli ölçüde artırmaktadır. Mamografi, kolonoskopi ve PSA testi gibi tarama yöntemleri yaygın kanserlerin erken teşhisinde kullanılır. HPV aşısı ise rahim ağzı kanserini büyük ölçüde önlemektedir.

Korunma yolları arasında sigarayı bırakmak, sağlıklı beslenmek, düzenli egzersiz yapmak, güneş kremlerini kullanmak ve düzenli tarama yaptırmak yer almaktadır.

TYT sınavlarında kanserin oluşum mekanizması, risk faktörleri ve korunma yolları sıkça sorulan konulardandır.$$, 166, 6, '{lgs,tyt}', '[{"question":"Kanserin temel oluşum mekanizması nedir?","options":["Hücrelerin enerji üretiminin durması","Genetik mutasyonlarla hücre döngüsü denetiminin bozulması ve kontrolsüz çoğalma","Bağışıklık sisteminin aşırı çalışması","Hormon dengesizliği"],"correctIndex":1},{"question":"Akciğer kanserinin en önemli tek nedeni nedir?","options":["Genetik yatkınlık","Hava kirliliği","Sigara kullanımı","Radyasyon"],"correctIndex":2},{"question":"HPV aşısı hangi kansere karşı koruyucudur?","options":["Meme kanseri","Akciğer kanseri","Rahim ağzı kanseri","Kolon kanseri"],"correctIndex":2},{"question":"Kanserden korunmak için hangi önlem alınabilir?","options":["Düzenli olarak sigara içmek","Güneş kremlerini kullanmak ve düzenli tarama yaptırmak","Tek tip beslenme uygulamak","Egzersizden kaçınmak"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Servet-i Fünun Edebiyatı: Halit Ziya ve Tevfik Fikret', $$Servet-i Fünun edebiyatı, 1896-1901 yılları arasında Servet-i Fünun dergisi çevresinde oluşan bir Osmanlı edebiyat akımıdır. Bu dönemin en önemli temsilcileri Halit Ziya Uşaklıgil ve Tevfik Fikret'tir.

Halit Ziya Uşaklıgil, Türk romanını Batı tekniğiyle buluşturan ilk yazarlardan biridir. "Mai ve Siyah" adlı romanında genç bir şairin hayallerini ve hayal kırıklıklarını psikolojik bir derinlikle işlemiştir. "Aşk-ı Memnu" ise yasak bir aşkı anlatan olgun dönem eseridir.

Tevfik Fikret ise şiirde Servet-i Fünun anlayışını temsil eder. Aruz veznini ustalıkla kullanmış, toplumsal sorunlara şiiri aracılığıyla seslenen bir şairdir. "Sis" adlı şiirinde İstanbul'u karamsar ve bunaltıcı bir şekilde betimlemiştir.

Bu dönem edebiyatında Fransız empresyonizminin ve sembolizminin etkileri açıkça görülür. Dil ağır ve süslüdür; halk dilinden uzaklaşılmıştır.$$, 168, 6, '{lgs,tyt,ayt}', '[{"question":"Servet-i Fünun edebiyatının toplandığı derginin adı nedir?","options":["Tanin","Servet-i Fünun","Diyojen","Mecmua-i Fünun"],"correctIndex":1},{"question":"Halit Ziya Uşaklıgil''in \"Mai ve Siyah\" romanı neyi anlatır?","options":["Bir savaş kahramanının yaşamını","Genç bir şairin hayallerini ve hayal kırıklıklarını","Osmanlı saray entrikalarını","Köy yaşamını ve gelenekleri"],"correctIndex":1},{"question":"Tevfik Fikret''in \"Sis\" şiiri neyi betimler?","options":["Anadolu''nun güzelliklerini","Karamsar ve bunaltıcı bir İstanbul''u","Deniz yolculuğunu","Bahardaki doğayı"],"correctIndex":1},{"question":"Servet-i Fünun dönemi edebiyatında hangi Fransız akımlarının etkisi görülür?","options":["Realizm ve Natüralizm","Empresyonizm ve Sembolizm","Romantizm ve Klasikizm","Dadaizm ve Sürrealizm"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Milli Edebiyat Dönemi: Ömer Seyfettin ve Ziya Gökalp', $$Milli Edebiyat hareketi, 20. yüzyılın başında Türkçülük akımıyla birlikte yükselmiş ve sade dili esas alan bir edebiyat anlayışı geliştirmiştir. Bu dönemin öncü isimleri arasında Ömer Seyfettin ve Ziya Gökalp yer alır.

Ömer Seyfettin, modern Türk hikâyeciliğinin kurucusu sayılır. "Yüksek Ökçeler", "Bomba" ve "Forsa" gibi hikâyeleriyle konuşma diline yakın, akıcı bir anlatım benimsemiştir. Milli kimlik ve Türklük bilinci onun eserlerinin temel izleğidir.

Ziya Gökalp ise bir düşünür ve şairdir. "Türkleşmek, İslamlaşmak, Muasırlaşmak" adlı eseri Türk milliyetçiliğinin teorik temellerini oluşturur. Gökalp, halk kültürünü ve Türk geleneğini edebiyatın kaynağı olarak görmüştür.

Bu dönemde dilde sadeleşme hareketi hız kazanmış, Arapça ve Farsça sözcükler yerine Türkçe kökenli sözcüklerin kullanımı teşvik edilmiştir.$$, 165, 5, '{lgs,tyt,ayt}', '[{"question":"Modern Türk hikâyeciliğinin kurucusu kimdir?","options":["Ziya Gökalp","Refik Halit Karay","Ömer Seyfettin","Yahya Kemal"],"correctIndex":2},{"question":"Ziya Gökalp''in temel eseri olan \"Türkleşmek, İslamlaşmak, Muasırlaşmak\" hangi konuyu ele alır?","options":["Osmanlı tarihini","Türk milliyetçiliğinin teorik temellerini","Dil reformunu","Edebi eleştiriyi"],"correctIndex":1},{"question":"Milli Edebiyat döneminde dil anlayışı nasıldır?","options":["Ağır ve süslü bir dil benimsenmiştir","Arapça ve Farsça sözcükler tercih edilmiştir","Sade ve halk diline yakın bir dil benimsenmiştir","Fransızca sözcükler kullanılmıştır"],"correctIndex":2},{"question":"Ömer Seyfettin''in eserlerindeki temel izlek nedir?","options":["Aşk ve bireysel duygular","Milli kimlik ve Türklük bilinci","Tasavvuf ve mistisizm","Sanayi ve modernleşme"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Cumhuriyet Dönemi Edebiyatı: Nazım Hikmet ve Orhan Kemal', $$Cumhuriyet dönemi Türk edebiyatı, 1923 sonrasında siyasi ve sosyal dönüşümlerin edebiyata yansımasıyla şekillenmiştir. Bu dönemin iki önemli ismi Nazım Hikmet ve Orhan Kemal'dir.

Nazım Hikmet, Türk şiirini biçim açısından köklü biçimde dönüştürmüştür. Serbest nazımı Türk edebiyatına yerleştirmiş, aruz yerine konuşma diline yakın bir ritim benimsemiştir. "Memleketimden İnsan Manzaraları" epik bir şiir dizisidir. Siyasi görüşleri nedeniyle yıllarca hapiste kalmış, ardından yurt dışına çıkmak zorunda kalmıştır.

Orhan Kemal ise toplumcu gerçekçilik akımının önemli temsilcilerinden biridir. "Bereketli Topraklar Üzerinde" ve "Murtaza" adlı romanlarında işçilerin, köylülerin ve toplumun dezavantajlı kesimlerinin yaşamını kaleme almıştır.

Bu dönem edebiyatında toplumsal sorunlar, emek, eşitsizlik ve modernleşme sancıları önemli temalar olarak öne çıkmaktadır.$$, 170, 6, '{lgs,tyt,ayt}', '[{"question":"Nazım Hikmet Türk şiirini biçim açısından nasıl dönüştürmüştür?","options":["Aruz veznini daha etkin kullanarak","Serbest nazımı Türk edebiyatına yerleştirerek","Hece veznini yaygınlaştırarak","Divan şiiri biçimlerini canlandırarak"],"correctIndex":1},{"question":"Orhan Kemal hangi edebiyat akımının temsilcisidir?","options":["Romantizm","Sembolizm","Toplumcu gerçekçilik","Modernizm"],"correctIndex":2},{"question":"\"Bereketli Topraklar Üzerinde\" adlı eserde hangi kesimin yaşamı anlatılır?","options":["Saraylılar ve aristokratlar","Orta sınıf aydınlar","İşçiler ve köylüler","Askerler ve komutanlar"],"correctIndex":2},{"question":"Cumhuriyet dönemi edebiyatında öne çıkan temalar nelerdir?","options":["Dini ve mistik temalar","Toplumsal sorunlar, emek ve eşitsizlik","Doğa tasvirleri ve pastoral temalar","Mitoloji ve fantastik unsurlar"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Halk Edebiyatı: Aşık Tarzı Şiir', $$Aşık tarzı şiir, Türk halk edebiyatının en köklü ve yaygın geleneklerinden biridir. Saz eşliğinde söylenen bu şiirler, gezgin halk ozanları olan aşıklar tarafından üretilir. Aşıklar, sazlarıyla köy köy dolaşarak şiirlerini seslendirir ve halk kültürünü yaşatır.

Bu geleneğin en bilinen isimleri arasında Köroğlu, Karacaoğlan, Aşık Veysel ve Dadaloğlu yer almaktadır. Karacaoğlan, aşk ve doğa temalarını işlemesiyle tanınır; şiirleri sade ve içtendir. Aşık Veysel ise körlüğüne rağmen derin felsefi şiirler kaleme almış ve "Uzun İnce Bir Yoldayım" şiiriyle gönüllerde taht kurmuştur.

Aşık tarzı şiirlerde hece vezni kullanılır. Koşma, semai, varsağı ve destan bu geleneğin temel nazım biçimleridir. Koşma en yaygın biçimdir ve 11'li hece ölçüsüyle yazılır.

Şiirlerde aşk, doğa, özlem, ölüm ve yiğitlik gibi evrensel temalar işlenir.$$, 163, 5, '{lgs,tyt,ayt}', '[{"question":"Aşık tarzı şiirde hangi vezin kullanılır?","options":["Aruz vezni","Serbest vezin","Hece vezni","Divan vezni"],"correctIndex":2},{"question":"Aşık Veysel''in en tanınmış şiiri hangisidir?","options":["Sis","Uzun İnce Bir Yoldayım","Kınalı Kuzum","Bugün Bende Derin Bir Hüzün Var"],"correctIndex":1},{"question":"Aşık tarzı şiirde en yaygın nazım biçimi hangisidir?","options":["Varsağı","Semai","Destan","Koşma"],"correctIndex":3},{"question":"Karacaoğlan''ın şiirlerinde hangi temalar öne çıkar?","options":["Savaş ve kahramanlık","Din ve tasavvuf","Aşk ve doğa","Tarih ve destan"],"correctIndex":2}]'::jsonb),
  ('edebiyat', 'Divan Edebiyatı: Gazel ve Kaside', $$Divan edebiyatı, Osmanlı döneminde yaklaşık 600 yıl boyunca sürdürülen yazılı edebiyat geleneğidir. Arapça ve Farsça sözcüklerin yoğun biçimde kullanıldığı bu edebiyatta aruz vezni esastır.

Gazel, divan edebiyatının en sevilen nazım biçimlerinden biridir. Genellikle 5 ile 15 beyitten oluşur ve aşk, güzellik, şarap ve ölüm temalarını işler. Her beyit kendi içinde anlam bütünlüğü taşır; bu özelliğe "beyit bağımsızlığı" denir. Gazelin son beytine "makta" adı verilir ve çoğunlukla şairin mahlası bu beyitte geçer.

Kaside ise genellikle bir padişah ya da devlet büyüğünü övmek amacıyla yazılan uzun şiirlerdir. En az 15, bazen 100 beyti aşan bu şiirlerin giriş bölümüne "nesib", övgü bölümüne "methiye" denir.

Fuzuli, Baki ve Nedim Türk divan edebiyatının zirvesini temsil eden şairlerdir.$$, 166, 6, '{lgs,tyt,ayt}', '[{"question":"Divan edebiyatında kullanılan temel vezin sistemi hangisidir?","options":["Hece vezni","Serbest vezin","Aruz vezni","Ulusal vezin"],"correctIndex":2},{"question":"Gazelin son beytine ne ad verilir?","options":["Nesib","Matla","Methiye","Makta"],"correctIndex":3},{"question":"Kaside, kimleri övmek amacıyla yazılır?","options":["Halk kahramanlarını","Padişah ya da devlet büyüklerini","Halk ozanlarını","Dini figürleri"],"correctIndex":1},{"question":"Fuzuli hangi temayla tanınır?","options":["Savaş ve zafer","Neşe ve dünyevi zevkler","Aşk şiiri","Didaktik öğütler"],"correctIndex":2}]'::jsonb),
  ('edebiyat', 'Tanzimat Romanı: Namık Kemal ve İntibah', $$Namık Kemal, Tanzimat döneminin en önemli edebiyat ve fikir adamlarından biridir. Vatan, özgürlük ve hürriyet temalarını işlediği şiir ve yazılarıyla döneminin ateşli bir savunucusu olmuştur. Tiyatro eseri "Vatan Yahut Silistre" büyük yankı uyandırmış ve ona sürgün yolunu açmıştır.

"İntibah" (1876), Namık Kemal'in yazdığı ilk Türkçe roman denemelerinden biridir. Eserin kahramanı Ali Bey, kötü ahlaklı bir kadının etkisiyle yanlış kararlar verir ve hayatını mahveder. Roman, bireyin kendi kararlarından sorumlu olduğunu vurgular.

İntibah'ta alafrangalık eleştirisi de önemli bir yer tutar. Yanlış Batılılaşma, eserin temel eleştiri eksenini oluşturur. Yazar, topluma özgün kimliğinden uzaklaşmadan Batı'nın olumlu değerlerini benimsemesi gerektiğini ima eder.

Roman teknik açıdan henüz olgunlaşmamış olsa da toplumsal mesajıyla Türk roman tarihinde önemli bir yere sahiptir.$$, 162, 5, '{lgs,tyt,ayt}', '[{"question":"Namık Kemal''in tiyatro eseri \"Vatan Yahut Silistre\" hangi sonucu doğurmuştur?","options":["Ödül kazandırmıştır","Sürgüne gönderilmesine yol açmıştır","Gazete kurmasını sağlamıştır","Padişah tarafından takdir görmüştür"],"correctIndex":1},{"question":"\"İntibah\" romanının kahramanı Ali Bey''in temel sorunu nedir?","options":["Yoksulluk ve sefalet","Kötü ahlaklı bir kadının etkisiyle yanlış kararlar vermesi","Savaş yaralanmaları","Aile baskısına boyun eğmesi"],"correctIndex":1},{"question":"İntibah''ta öne çıkan temel eleştiri ekseni nedir?","options":["Dini baskılar","Yanlış Batılılaşma ve alafrangalık","Feodal düzen","Eğitimsizlik"],"correctIndex":1},{"question":"Namık Kemal''in eserlerinde öne çıkan temel temalar nelerdir?","options":["Aşk ve bireysel hüzün","Tasavvuf ve dini aşk","Vatan, özgürlük ve hürriyet","Doğa ve pastoral yaşam"],"correctIndex":2}]'::jsonb),
  ('edebiyat', 'Şiirde Ölçü: Aruz ve Hece', $$Şiirde ölçü, dizelerdeki hece ya da ses birimlerinin belirli bir kurala göre düzenlenmesidir. Türk şiirinde tarihsel süreç içinde iki temel ölçü sistemi kullanılmıştır: aruz vezni ve hece vezni.

Aruz vezni, Arapça ve Farsçadan Türkçeye geçmiş bir ses sistemidir. Hecelerin uzunluk ve kısalığına dayanır. Divan edebiyatında yaygın biçimde kullanılmış, ancak Türkçenin yapısına tam olarak uymadığı için eleştirilmiştir.

Hece vezni ise Türkçenin doğal yapısıyla örtüşen yerli bir ölçüdür. Dizeler belirli sayıda heceden oluşur. "7+7=14" ya da "4+4+3=11" gibi biçimler yaygındır. Halk şiiri ve Milli Edebiyat dönemi bu vezni benimsemiştir.

Serbest nazım ise herhangi bir ölçü kuralına bağlı kalmaksızın yazılan şiirdir. Nazım Hikmet bu biçimi Türk şiirine yerleştirmiştir. Sınavlarda verilen bir şiir dizesinin hangi ölçüyle yazıldığını belirlemek önemli bir beceridir.$$, 160, 5, '{lgs,tyt,ayt}', '[{"question":"Aruz vezni hangi edebiyat geleneğinde yaygın biçimde kullanılmıştır?","options":["Halk edebiyatında","Cumhuriyet edebiyatında","Divan edebiyatında","Milli edebiyatta"],"correctIndex":2},{"question":"Hece vezninde dizeler neye göre düzenlenir?","options":["Hecelerin uzunluk ve kısalığına","Dizedeki hece sayısına","Sözcük sayısına","Uyak düzenine"],"correctIndex":1},{"question":"Serbest nazımı Türk şiirine kim yerleştirmiştir?","options":["Yahya Kemal Beyatlı","Tevfik Fikret","Ömer Seyfettin","Nazım Hikmet"],"correctIndex":3},{"question":"Aruz vezni neden eleştirilmiştir?","options":["Çok kısa dizeler ürettiği için","Türkçenin yapısına tam olarak uymadığı için","Halk tarafından anlaşılmadığı için","Yabancı temalar içerdiği için"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Anlatı Teknikleri: Bakış Açısı Türleri', $$Bir anlatı eserinde yazar, olayları belirli bir bakış açısından aktarır. Bu bakış açısı, okuyucunun karakterlere ve olaylara nasıl baktığını doğrudan belirler. Türk ve dünya edebiyatında üç temel bakış açısı türü kullanılmaktadır.

İlahi (tanrısal) bakış açısında anlatıcı her şeyi bilir; tüm karakterlerin iç dünyasını, düşüncelerini ve duygu durumlarını aktarabilir. Bu bakış açısına "sınırsız bakış açısı" da denir. Geleneksel romanlarda yaygındır.

Kahraman bakış açısında anlatıcı, birinci tekil kişi ağzından ("ben") olayları aktarır. Yalnızca kendi iç dünyasını ve tanık olduğu olayları aktarabilir.

Gözlemci bakış açısında ise anlatıcı, karakterlerin dış davranışlarını aktarır; iç dünyalarına girmez. Bu bakış açısı kameranın nesnel görüntülemesine benzetilir.

Sınavlarda verilen bir metin parçasından bakış açısını belirlemek için kullanılan kişi zamiri ve anlatıcının bilgi sınırları incelenmelidir.$$, 164, 6, '{lgs,tyt,ayt}', '[{"question":"İlahi bakış açısının temel özelliği nedir?","options":["Anlatıcının yalnızca kendi duygularını aktarması","Anlatıcının her şeyi bilmesi ve tüm karakterlerin iç dünyasına erişebilmesi","Anlatıcının olayları dışarıdan gözlemlemesi","Anlatıcının ikinci tekil kişi kullanması"],"correctIndex":1},{"question":"Kahraman bakış açısında hangi kişi zamiri kullanılır?","options":["O (üçüncü tekil)","Biz (birinci çoğul)","Ben (birinci tekil)","Siz (ikinci çoğul)"],"correctIndex":2},{"question":"Gözlemci bakış açısı neye benzetilir?","options":["Bir günlüğe","Bir mektuba","Kameranın nesnel görüntülemesine","Tanrısal bir bakışa"],"correctIndex":2},{"question":"Sınavlarda bakış açısını belirlemek için ne incelenmelidir?","options":["Eserin başlığı ve yazarı","Kullanılan kişi zamiri ve anlatıcının bilgi sınırları","Eserin sayfa sayısı","Karakterlerin isimleri"],"correctIndex":1}]'::jsonb),
  ('edebiyat', 'Türk Masalları ve Halk Hikâyeleri: Köroğlu ve Kerem ile Aslı', $$Türk halk edebiyatı, masallar ve halk hikâyeleriyle zengin bir sözlü gelenek oluşturmuştur. Bu ürünler, yüzyıllar boyunca ozanlar ve meddahlar aracılığıyla kuşaktan kuşağa aktarılmıştır.

Köroğlu Destanı, Anadolu ve Orta Asya coğrafyasında geniş bir yayılım alanına sahiptir. Haksızlığa başkaldıran, ezilenlerin yanında duran Köroğlu; efsanevi atı Kırat ile birlikte yiğitliğin ve özgürlüğün simgesi olmuştur.

Kerem ile Aslı ise Türk edebiyatının en bilinen aşk hikâyelerinden biridir. Hikâyenin sonunda Kerem'in vuslatın eşiğinde yanar kül olması, trajik aşkın simgesi hâline gelmiştir.

Türk masallarında ise "bir varmış bir yokmuş" kalıp sözüyle açılan olağanüstü olaylar anlatılır. Cadı, dev, peri ve büyü unsurları sıkça karşılaşılan motiflerdir.$$, 167, 5, '{lgs,tyt,ayt}', '[{"question":"Köroğlu Destanı''nın temel teması nedir?","options":["Dinî öğütler ve tasavvuf","Haksızlığa başkaldırı ve özgürlük","Romantik bir aşk hikâyesi","Tarihî bir savaşın destanı"],"correctIndex":1},{"question":"Köroğlu''nun efsanevi atının adı nedir?","options":["Düldül","Karakaş","Kırat","Bozat"],"correctIndex":2},{"question":"Kerem ile Aslı hikâyesinde sonunda ne olur?","options":["Kerem ve Aslı mutlu sonla kavuşur","Aslı başka biriyle evlenir","Kerem vuslatın eşiğinde yanar kül olur","İkisi de uzak diyarlara gider"],"correctIndex":2},{"question":"Türk masalları genellikle nasıl bir kalıp sözle açılır?","options":["Uzun zaman önce...","Bir varmış bir yokmuş","Rivayet olunur ki...","Eskiden eskiye..."],"correctIndex":1}]'::jsonb),
  ('sosyal', 'Osmanlı Hukuk Sistemi ve Tanzimat', $$Osmanlı Devleti'nde hukuk sistemi iki temel kaynaktan besleniyordu: şeriat hukuku ve örfi hukuk. Şeriat, İslam dinine dayanan kuralları kapsarken örfi hukuk padişahın koyduğu kanunlardan oluşuyordu.

1839 yılında ilan edilen Tanzimat Fermanı, Osmanlı hukukunda köklü bir dönüşümü başlattı. Gülhane Hatt-ı Hümayunu adıyla da bilinen bu belge; can, mal ve namus güvenliğini tüm Osmanlı vatandaşlarına güvence altına alıyordu. Ferman, din ayrımı gözetmeksizin eşit muamele ilkesini benimsemesiyle çığır açıcıydı.

1856'da ilan edilen Islahat Fermanı ise azınlık haklarını daha da genişletti. Ardından hazırlanan Mecelle, Batı hukuku anlayışından etkilenerek derlenen bir medeni kanun niteliği taşıyordu.

Bu gelişmeler Cumhuriyet hukuk reformlarının temelini oluşturdu.$$, 165, 5, '{lgs,tyt}', '[{"question":"Osmanlı hukuk sisteminin iki temel kaynağı nelerdir?","options":["Roma hukuku ve Bizans hukuku","Şeriat hukuku ve örfi hukuk","Örf ve adet hukuku ve laik hukuk","Ferman hukuku ve sözleşme hukuku"],"correctIndex":1},{"question":"Tanzimat Fermanı hangi yılda ilan edilmiştir?","options":["1826","1839","1856","1876"],"correctIndex":1},{"question":"Tanzimat Fermanı''nın öne çıkan özelliği nedir?","options":["Yalnızca Müslümanlara haklar tanıması","Ordunun yeniden yapılandırılması","Din ayrımı gözetmeksizin eşit muamele ilkesini benimsemesi","Yeni bir vergi sisteminin kurulması"],"correctIndex":2},{"question":"Mecelle nedir?","options":["Osmanlı anayasasının adı","Batı hukuku anlayışından etkilenerek derlenen medeni kanun","Tanzimat Fermanı''nın ikinci bölümü","Osmanlı ceza kanunu"],"correctIndex":1}]'::jsonb),
  ('sosyal', 'Demokratikleşme Süreci: Magna Carta''dan Günümüze', $$Demokratikleşme, halkın yönetimdeki söz hakkının tarihsel süreç içinde genişlemesidir. Bu sürecin dönüm noktaları incelendiğinde 1215 tarihli Magna Carta öne çıkar. İngiltere'de imzalanan bu belge, kral iktidarını sınırlayarak bireysel hakların güvence altına alınması yolunda ilk adımı attı.

1688 İngiliz Haklar Bildirgesi ve 1776 Amerikan Bağımsızlık Bildirisi, bireyin devlet karşısındaki haklarını daha da genişletti. 1789 Fransız İnsan ve Yurttaş Hakları Bildirisi ise eşitlik, özgürlük ve kardeşlik kavramlarını evrensel düzeyde duyurdu.

19. ve 20. yüzyıllarda seçme ve seçilme hakkı giderek yaygınlaştı. Kadınların oy hakkı mücadelesi bu sürecin önemli bir parçasını oluşturur; İngiltere 1918, Türkiye ise 1934 yılında kadınlara bu hakkı tanıdı.

Günümüzde demokratikleşme yalnızca seçimlerle sınırlı kalmayıp basın özgürlüğü, azınlık hakları ve hukuk devleti ilkeleriyle değerlendirilmektedir.$$, 162, 5, '{lgs,tyt}', '[{"question":"Magna Carta hangi yılda imzalanmıştır?","options":["1066","1215","1492","1688"],"correctIndex":1},{"question":"Magna Carta''nın temel önemi nedir?","options":["Sömürge dönemini başlatması","Kral iktidarını sınırlayarak bireysel hakların güvenceye alınması","Oy hakkının herkese tanınması","Kilise ile devletin ayrışması"],"correctIndex":1},{"question":"Fransız İnsan ve Yurttaş Hakları Bildirisi hangi üç kavramı öne çıkardı?","options":["Kral, kilise ve devlet","Adalet, düzen ve refah","Eşitlik, özgürlük ve kardeşlik","Güvenlik, barış ve kalkınma"],"correctIndex":2},{"question":"Türkiye''de kadınlara oy hakkı hangi yılda tanındı?","options":["1923","1928","1934","1950"],"correctIndex":2}]'::jsonb),
  ('sosyal', 'Ekonomik Sistemler: Kapitalizm ve Sosyalizm', $$Ekonomik sistemler, bir toplumun üretim, dağıtım ve tüketim faaliyetlerini nasıl örgütlediğini belirler. Tarihsel süreçte en çok tartışılan iki sistem kapitalizm ve sosyalizmdir.

Kapitalizmde üretim araçları özel mülkiyete dayanır. Piyasa mekanizması arz ve talebi düzenler; fiyatlar serbestçe oluşur. Bireysel girişimcilik ve rekabet bu sistemin temel motorlarıdır.

Sosyalizmde ise üretim araçları devlet ya da toplum tarafından ortaklaşa kontrol edilir. Gelirin daha eşit dağıtılması ve sosyal güvencenin herkes için sağlanması temel hedeflerdir.

20. yüzyılda bu iki sistem arasındaki ideolojik çatışma Soğuk Savaş dönemini şekillendirdi. Günümüzde pek çok ülke her iki sistemin unsurlarını barındıran karma ekonomi modeli uygular. Türkiye de hem özel sektörü hem de kamu yatırımlarını içeren karma bir ekonomik yapıya sahiptir.$$, 168, 6, '{lgs,tyt}', '[{"question":"Kapitalizmde üretim araçları kimin mülkiyetindedir?","options":["Devletin","Toplumun","Özel mülkiyet sahiplerinin","Uluslararası kuruluşların"],"correctIndex":2},{"question":"Sosyalizmde temel hedef nedir?","options":["Bireysel refahı maksimize etmek","Gelirin daha eşit dağıtılması ve sosyal güvence","Serbest piyasayı genişletmek","Özel girişimciliği teşvik etmek"],"correctIndex":1},{"question":"Kapitalizme yönelik temel eleştiri nedir?","options":["Bireyi çok özgür bırakması","Merkezi planlamaya dayanması","Servet eşitsizliğine ve sömürüye yol açması","İnovasyonu engellemesi"],"correctIndex":2},{"question":"Karma ekonomi modeli ne anlama gelir?","options":["Yalnızca devlet işletmelerinin bulunduğu sistem","Her iki sistemin unsurlarını barındıran model","Tarım odaklı ekonomik düzen","Yalnızca özel sektöre dayanan sistem"],"correctIndex":1}]'::jsonb),
  ('sosyal', 'İnsan Hakları Evrensel Beyannamesi (1948)', $$İkinci Dünya Savaşı'nın ardından yaşanan insanlık trajedileri, insan haklarının uluslararası güvence altına alınması gerekliliğini açıkça ortaya koydu. 10 Aralık 1948'de Birleşmiş Milletler Genel Kurulu, İnsan Hakları Evrensel Beyannamesi'ni kabul etti.

Beyanname, 30 maddeden oluşmaktadır. Her insanın ırk, dil, din, cinsiyet ya da ulusal köken farkı gözetilmeksizin eşit haklara sahip olduğunu ilan eder. Yaşam hakkı, özgürlük hakkı, adil yargılanma hakkı, eğitim hakkı ve çalışma hakkı bu temel haklar arasında yer almaktadır.

Beyanname, bağlayıcı bir hukuki belge olmaktan çok ahlaki bir çerçeve sunmaktadır. Ancak birçok uluslararası antlaşmanın ilham kaynağı olmuş ve pek çok ülkenin anayasasına yansımıştır.

Türkiye, Beyannamenin hazırlanmasına katılmış ve 1948'de kabul etmiştir.$$, 163, 5, '{lgs,tyt}', '[{"question":"İnsan Hakları Evrensel Beyannamesi kaç yılında kabul edilmiştir?","options":["1945","1948","1950","1956"],"correctIndex":1},{"question":"Beyanname kaç maddeden oluşmaktadır?","options":["20","25","30","40"],"correctIndex":2},{"question":"Beyannamenin temel ilkesi nedir?","options":["Güçlü devletlere öncelik tanımak","Her insanın herhangi bir ayrım gözetilmeksizin eşit haklara sahip olması","Ekonomik kalkınmayı temel hak olarak kabul etmek","Yalnızca savaş mağdurlarına hak tanımak"],"correctIndex":1},{"question":"Beyanname hukuki açıdan nasıl nitelendirilebilir?","options":["Bağlayıcı bir uluslararası sözleşmedir","Yalnızca BM üyelerini bağlar","Bağlayıcı olmayan ama ahlaki bir çerçeve sunan belgedir","Ceza hukuku niteliği taşır"],"correctIndex":2}]'::jsonb),
  ('sosyal', 'Küreselleşme: Avantajları ve Dezavantajları', $$Küreselleşme, ülkeler arasındaki ekonomik, siyasi, kültürel ve teknolojik bütünleşme sürecidir. 20. yüzyılın sonlarında iletişim ve ulaşım teknolojilerinin hızla gelişmesiyle birlikte dünya giderek "küçülmüş" ve toplumlar birbirine daha fazla bağımlı hale gelmiştir.

Küreselleşmenin avantajları arasında serbest ticaret sayesinde ekonomik büyüme, teknoloji ve bilginin daha hızlı yayılması ve uluslararası iş birliğinin güçlenmesi sayılabilir. Gelişmekte olan ülkeler küreselleşme aracılığıyla yabancı yatırım çekebilir ve ihracatlarını artırabilir.

Öte yandan dezavantajlar da göz ardı edilemez. Küreselleşme gelir eşitsizliğini artırabilir; küçük üreticiler rekabet baskısıyla zayıflayabilir. Kültürel homojenleşme ve yerel değerlerin erimesi de ciddi bir endişe kaynağıdır.

Ayrıca küresel salgınlar, finansal krizler ve iklim değişikliği gibi sorunlar da küreselleşmeyle birlikte daha hızlı yayılmaktadır.$$, 166, 5, '{lgs,tyt}', '[{"question":"Küreselleşme kavramını en iyi tanımlayan ifade hangisidir?","options":["Ülkelerin birbirinden izole olması","Ülkeler arasındaki ekonomik, siyasi, kültürel ve teknolojik bütünleşme","Yalnızca ticaretin serbestleşmesi","Tek bir küresel hükümetin kurulması"],"correctIndex":1},{"question":"Küreselleşmenin gelişmekte olan ülkelere sağlayabileceği avantaj nedir?","options":["Kültürel homojenleşme","Yabancı yatırım çekme ve ihracatı artırma","Yerel değerlerin korunması","Rekabet baskısından korunma"],"correctIndex":1},{"question":"Küreselleşmenin kültürel açıdan öne çıkan dezavantajı nedir?","options":["Teknolojinin yavaş yayılması","Ticaretin azalması","Kültürel homojenleşme ve yerel değerlerin erimesi","Uluslararası iş birliğinin zayıflaması"],"correctIndex":2},{"question":"Küreselleşmeyle birlikte hangi sorunlar daha hızlı yayılmaktadır?","options":["Ulusal kimlik sorunları","Küresel salgınlar, finansal krizler ve iklim değişikliği","Yerel dil yok oluşları","Tarımsal verim düşüşleri"],"correctIndex":1}]'::jsonb),
  ('sosyal', 'Antik Yunan Demokrasisi', $$Antik Yunan'da özellikle Atina'da gelişen demokrasi, tarihsel olarak "halkın yönetimi" anlamına gelen ilk siyasal sistemi temsil etmektedir. Yunanca "demos" (halk) ve "kratos" (güç) sözcüklerinden türeyen bu kavram, MÖ 5. yüzyılda Kleisthenes'in reformlarıyla sistemli bir biçim kazandı.

Atina demokrasisinin temel organı Halk Meclisi'ydi. Erkek vatandaşlar kararları doğrudan oylamaya katılarak alırdı. Bu nedenle Atina demokrasisi "doğrudan demokrasi" olarak nitelendirilir. Ancak kadınlar, köleler ve yabancılar bu haklardan yararlanamıyordu.

Perikles döneminde Atina demokrasisi altın çağına ulaştı. Perikles, halkın yönetimine daha geniş katılım sağlayacak düzenlemeler yaparak demokrasiyi pekiştirdi.

Antik Yunan demokrasisi, günümüz demokratik sistemlerinin temel ilham kaynaklarından biridir. Yasama, yürütme ve yargı ayrılığı ile halkın egemenliği gibi ilkeler bu geleneğe dayanmaktadır.$$, 164, 6, '{lgs,tyt}', '[{"question":"Atina demokrasisinin temel organı neydi?","options":["Senato","Meclis-i Mebusan","Halk Meclisi","Konsül"],"correctIndex":2},{"question":"Atina demokrasisi neden \"doğrudan demokrasi\" olarak nitelendirilir?","options":["Yalnızca bir kişinin karar vermesi","Erkek vatandaşların kararları doğrudan oylayarak alması","Kararların yazılı yasalara dayanması","Seçilmiş temsilcilerin karar alması"],"correctIndex":1},{"question":"Atina demokrasisinin en önemli sınırlılığı nedir?","options":["Seçimlerin çok sık yapılması","Kadınlar, köleler ve yabancıların haklardan yararlanamaması","Halk Meclisi''nin çok büyük olması","Perikles''in gücü tek elde toplaması"],"correctIndex":1},{"question":"Demokrasi kavramı Yunancada hangi iki sözcükten türemiştir?","options":["Polis ve logos","Demos ve kratos","Arche ve nomos","Telos ve ethos"],"correctIndex":1}]'::jsonb),
  ('sosyal', 'Rönesans Sanatı ve Hümanizm', $$Rönesans, 14. yüzyılda İtalya'da başlayarak 16. yüzyıla dek Avrupa'ya yayılan bir kültürel ve entelektüel yeniden doğuş hareketidir. Bu dönemde antik Yunan ve Roma uygarlıklarının değerleri yeniden keşfedildi.

Hümanizm, Rönesans'ın temel felsefi damarını oluşturur. İnsanı evrenin merkezine koyan bu düşünce akımı, Ortaçağ'ın Tanrı merkezli dünya anlayışından kopuşu simgelemektedir.

Sanat alanında Rönesans perspektif tekniğinin kullanımı, insan vücudunun gerçekçi tasviri ve doğadan ilham almayı beraberinde getirdi. Leonardo da Vinci, Michelangelo ve Raffaello bu dönemin sembolik isimleridir.

Matbaanın Gutenberg tarafından 1440'lı yıllarda icat edilmesi, Rönesans düşüncesinin Avrupa'ya yayılmasını hızlandırdı. Bu süreç, Reform hareketi ve Bilimsel Devrim'in zeminini de hazırladı.$$, 165, 5, '{lgs,tyt}', '[{"question":"Rönesans hareketi hangi ülkede başlamıştır?","options":["Fransa","Almanya","İngiltere","İtalya"],"correctIndex":3},{"question":"Hümanizmin temel özelliği nedir?","options":["Tanrı merkezli dünya görüşü","İnsanı evrenin merkezine koymak","Dini otoritenin güçlendirilmesi","Antik değerleri reddetmek"],"correctIndex":1},{"question":"Rönesans sanatında öne çıkan yenilikler nelerdir?","options":["Soyut kompozisyonlar ve din dışı temalar","Perspektif tekniği ve insan vücudunun gerçekçi tasviri","Mozaik sanatı ve altın yaldız kullanımı","Simgesel figürler ve gizem temaları"],"correctIndex":1},{"question":"Rönesans düşüncesinin Avrupa''ya yayılmasını hızlandıran icat nedir?","options":["Pusula","Barut","Matbaa","Teleskop"],"correctIndex":2}]'::jsonb),
  ('sosyal', 'Sanayi Devrimi ve Toplumsal Değişim', $$Sanayi Devrimi, 18. yüzyılın ortasında İngiltere'de başlayan ve üretim ile toplumsal yapıyı kökten dönüştüren tarihsel bir süreçtir. Buhar makinesinin geliştirilmesi ve fabrika sistemine geçiş bu devrimin temel dinamikleridir.

Tarım toplumundan sanayi toplumuna geçiş, kentleşmeyi hızlandırdı. Köylerden şehirlere göç eden işçiler, fabrika koşullarında uzun saatler boyunca ağır ve tehlikeli işlerde çalışmak zorunda kaldı. İşçi sınıfının (proletarya) ortaya çıkışı bu dönemin en önemli toplumsal sonuçlarından biridir.

Sanayi Devrimi aynı zamanda çevre kirliliğinin başlangıcını da simgeler. Kömür yakıtlı fabrikaların yaydığı dumanlar, hava kirliliğini ve sağlık sorunlarını beraberinde getirdi.

Ekonomik açıdan ise kapitalist sistemin güçlenmesine zemin hazırladı. Karl Marx ve Friedrich Engels bu dönemde işçi sınıfının sömürülmesini eleştiren "Komünist Manifesto"yu kaleme aldı. Sanayi Devrimi, günümüz dünya ekonomisinin şekillenmesinde belirleyici bir rol oynamıştır.$$, 163, 6, '{lgs,tyt}', '[{"question":"Sanayi Devrimi hangi ülkede başlamıştır?","options":["Fransa","Almanya","İngiltere","Amerika Birleşik Devletleri"],"correctIndex":2},{"question":"Sanayi Devrimi''nin toplumsal açıdan önemli sonuçlarından biri nedir?","options":["Tarım üretiminin artması","İşçi sınıfının ortaya çıkması","Feodal sistemin güçlenmesi","Nüfusun azalması"],"correctIndex":1},{"question":"Karl Marx ve Friedrich Engels bu dönemde hangi eseri kaleme aldı?","options":["Das Kapital","Komünist Manifesto","Ulusların Zenginliği","Toplumsal Sözleşme"],"correctIndex":1},{"question":"Sanayi Devrimi''nin çevresel etkisi nedir?","options":["Ormanların genişlemesi","Hava kirliliğinin başlaması","Su kaynaklarının artması","İklimin iyileşmesi"],"correctIndex":1}]'::jsonb),
  ('sosyal', 'Atatürk İlkeleri ve Cumhuriyet', $$Türkiye Cumhuriyeti, 29 Ekim 1923'te Mustafa Kemal Atatürk önderliğinde ilan edilmiştir. Cumhuriyetle birlikte gerçekleştirilen köklü reformlar, Türk toplumunun siyasi, hukuki, sosyal ve kültürel yapısını kökten dönüştürdü.

Atatürk'ün altı temel ilkesi Cumhuriyetçilik, Milliyetçilik, Halkçılık, Devletçilik, Laiklik ve Devrimcilik olarak sıralanır. Bu ilkeler 1937 yılında Anayasa'ya girerek anayasal güvence altına alınmıştır.

Laiklik ilkesi gereğince din ve devlet işleri birbirinden ayrıldı; halifelik kaldırıldı ve dini mahkemeler yerine laik mahkemeler kuruldu. Eğitim alanında ise Tevhid-i Tedrisat Kanunu ile öğretim birleştirildi.

Harf devrimi (1928) ile Arap alfabesinden Latin alfabesine geçildi; bu adım okuryazarlık oranını önemli ölçüde artırdı. Kadınlara seçme ve seçilme hakkı (1934), uluslararası alanda Türkiye'yi öncü konuma getirdi.

Atatürk ilkeleri, Türkiye Cumhuriyeti'nin temel taşları olmayı sürdürmektedir.$$, 167, 5, '{lgs,tyt}', '[{"question":"Türkiye Cumhuriyeti hangi yılda ilan edilmiştir?","options":["1920","1922","1923","1925"],"correctIndex":2},{"question":"Atatürk''ün altı ilkesi arasında hangisi yer almaz?","options":["Laiklik","Milliyetçilik","Monarşizm","Devrimcilik"],"correctIndex":2},{"question":"Harf devrimi hangi yılda gerçekleştirilmiştir?","options":["1924","1926","1928","1932"],"correctIndex":2},{"question":"Tevhid-i Tedrisat Kanunu ne anlama gelir?","options":["Dini eğitimin kaldırılması","Öğretimin birleştirilmesi","Yükseköğretimin yaygınlaştırılması","Zorunlu eğitimin başlaması"],"correctIndex":1}]'::jsonb),
  ('fen', 'Hücre Yapısı: Prokaryot ve Ökaryot', $$Hücre, tüm canlı organizmaların temel yapı ve işlev birimidir. Hücreler yapılarına göre iki ana gruba ayrılır: prokaryot hücreler ve ökaryot hücreler.

Prokaryot hücreler, gerçek bir zarla çevrilmiş çekirdeğe sahip değildir. DNA'ları sitoplazmada serbest halde bulunur. Bakteriler ve arkelerin prokaryot organizmalar olduğu bilinmektedir. Bu hücreler nispeten küçük olup mitokondri, kloroplast gibi zarlı organeller içermez.

Ökaryot hücreler ise çekirdeği bir zar ile çevrilmiş, gerçek bir çekirdeğe sahiptir. Bitkiler, hayvanlar, mantarlar ve protistler ökaryot organizmalardır.

Bitki hücreleri ile hayvan hücreleri arasında da önemli farklılıklar vardır. Bitki hücrelerinde hücre duvarı, kloroplast ve merkezi koful bulunur; hayvan hücrelerinde bu yapılar yer almaz. Bu ayrımlar LGS fen bilimleri sorularında sıkça test edilir.$$, 162, 5, '{lgs,tyt}', '[{"question":"Prokaryot hücrelerin temel özelliği nedir?","options":["Mitokondri içermeleri","Gerçek bir zarla çevrilmiş çekirdekten yoksun olmaları","Kloroplast bulundurmaları","Çok büyük olmaları"],"correctIndex":1},{"question":"Aşağıdakilerden hangisi prokaryot organizmalara örnektir?","options":["Mantarlar","Bitkiler","Bakteriler","Hayvanlar"],"correctIndex":2},{"question":"Bitki hücrelerinde bulunup hayvan hücrelerinde bulunmayan yapılar nelerdir?","options":["Ribozom ve mitokondri","Hücre duvarı, kloroplast ve merkezi koful","Çekirdek ve endoplazmik retikulum","Sitoplazma ve hücre zarı"],"correctIndex":1},{"question":"Ökaryot hücreler prokaryot hücrelerden nasıl ayrılır?","options":["Daha küçük olmalarıyla","Zarsız organeller içermeleriyle","Gerçek bir zarla çevrilmiş çekirdeğe sahip olmalarıyla","DNA içermemesiyle"],"correctIndex":2}]'::jsonb),
  ('fen', 'Newton''un Hareket Yasaları', $$Isaac Newton, 17. yüzyılda hareket ve kuvvet ilişkisini açıklayan üç temel yasa geliştirmiştir. Bu yasalar modern fiziğin ve mühendisliğin temelini oluşturur.

Birinci yasa (Eylemsizlik Yasası): Üzerine net bir kuvvet etki etmeyen bir cisim hareketsizse hareketsiz kalmaya, hareket halindeyse sabit hızla doğrusal harekete devam eder.

İkinci yasa: Bir cisme uygulanan net kuvvet, cismin kütlesiyle ivmesinin çarpımına eşittir. Formülü F = m × a şeklinde ifade edilir. Kuvvet büyüdükçe ya da kütle küçüldükçe ivme artar.

Üçüncü yasa (Etki-Tepki Yasası): Her etki kuvvetine eşit büyüklükte ve zıt yönde bir tepki kuvveti karşılık verir. Roketin itki kuvveti ve fırlayan tüfekteki geri tepme bu yasanın somut örnekleridir. Newton yasaları günlük yaşamda araçların frenlenmesinden uzay araçlarının yörünge hesaplamalarına kadar pek çok alanda uygulanmaktadır.$$, 165, 6, '{lgs,tyt}', '[{"question":"Newton''un birinci yasası neyi açıklar?","options":["Kuvvet ile ivme arasındaki ilişkiyi","Cisimlerin net kuvvet olmadığında mevcut hareket durumlarını korumalarını","Etki ve tepki kuvvetlerini","Yerçekimi ile kütle arasındaki ilişkiyi"],"correctIndex":1},{"question":"F = m × a formülünde \"a\" neyi temsil eder?","options":["Alanı","Ağırlığı","İvmeyi","Atalet momentini"],"correctIndex":2},{"question":"Newton''un üçüncü yasasına göre bir roketin fırlatılması nasıl açıklanır?","options":["Rokete uygulanan yer çekimi etkisiyle","Roketten çıkan gazların oluşturduğu etki kuvvetine karşı tepki kuvvetiyle","Rüzgar kuvvetinin etkisiyle","Manyetik kuvvetin itimiyle"],"correctIndex":1},{"question":"Eylemsizlik yasası hangi kavramı açıklar?","options":["Bir cismin kütlesinin değişmezliğini","Cisimlerin kuvvet olmadığında mevcut hareket durumlarını sürdürme eğilimini","Cisimlerin birbirine uyguladığı kuvvetleri","Sürtünme kuvvetinin nasıl oluştuğunu"],"correctIndex":1}]'::jsonb),
  ('fen', 'Kimyasal Bağlar: İyonik ve Kovalent', $$Kimyasal bağlar, atomları bir arada tutan elektrostatik kuvvetlerdir. Bileşiklerin oluşmasını sağlayan bu bağlar iki temel türe ayrılır: iyonik bağ ve kovalent bağ.

İyonik bağ, bir metalin elektronu bir ametaline verdiğinde oluşur. Elektron alan atom negatif iyon (anyon), elektron veren atom ise pozitif iyon (katyon) haline gelir. Zıt yüklü bu iyonlar birbirini çekerek bağ kurar. Sodyum klorür (sofra tuzu, NaCl) en bilinen iyonik bileşiktir.

Kovalent bağ ise iki ametal atomunun elektronlarını ortak kullanmasıyla oluşur. Su (H₂O), karbondioksit (CO₂) ve oksijen gazı (O₂) kovalent bağ içeren moleküllere örnektir.

İyonik bileşikler genellikle yüksek erime noktasına sahiptir, suda çözündüklerinde iletkenlik gösterir. Kovalent bileşikler ise daha düşük erime noktasına sahiptir. Bu iki bağ türü LGS ve TYT sorularında karşılaştırmalı olarak sıkça sorulmaktadır.$$, 163, 6, '{lgs,tyt}', '[{"question":"İyonik bağ nasıl oluşur?","options":["İki ametal atomunun elektron paylaşmasıyla","Bir metalin elektronu ametaline vermesiyle","İki metalin birleşmesiyle","Protonların paylaşılmasıyla"],"correctIndex":1},{"question":"NaCl (sofra tuzu) hangi tür kimyasal bağ içerir?","options":["Kovalent bağ","Metalik bağ","Hidrojen bağı","İyonik bağ"],"correctIndex":3},{"question":"Kovalent bağda atomlar ne yapar?","options":["Elektron aktarır","Proton alışverişi yapar","Elektronları ortak kullanır","Nötron paylaşır"],"correctIndex":2},{"question":"İyonik bileşiklerin suda çözünmesi durumunda ne gözlemlenir?","options":["Elektrik iletkenliği kaybolur","Bileşik ısı açığa çıkarır","Elektrik iletkenliği görülür","Renk değişimi gözlemlenir"],"correctIndex":2}]'::jsonb),
  ('fen', 'Periyodik Tablo ve Element Grupları', $$Periyodik tablo, elementlerin atom numaralarına göre sıralandığı ve kimyasal özelliklerine göre gruplandırıldığı evrensel bir düzendir. Dmitri Mendeleyev 1869 yılında elementleri sistematik biçimde düzenlemiş ve periyodik tablonun temellerini atmıştır.

Tabloda yatay sıralara "periyot", dikey sütunlara ise "grup" adı verilir. Aynı grupta yer alan elementler benzer kimyasal özellikler sergiler; çünkü son yörüngelerindeki elektron sayıları aynıdır.

Alkali metaller (1. grup), çok reaktif metaller olup suyla şiddetle tepkimeye girer. Halojenler (17. grup) ise reaktif ametal elementlerdir; klor ve flor bu grubun önemli üyeleridir. 18. grup soygaz olarak bilinir ve bu elementler son derece kararlı olup kimyasal tepkimelere girmezler.

Metallerin yarı iletkenlerle sınırı belirleyen elementlere "metaloit" denir. Silisyum en önemli metalloidlerden biridir ve elektronik sanayisinde kritik bir konuma sahiptir.$$, 164, 6, '{lgs,tyt}', '[{"question":"Periyodik tabloyu sistematik biçimde düzenleyen bilim insanı kimdir?","options":["Isaac Newton","Antoine Lavoisier","Dmitri Mendeleyev","John Dalton"],"correctIndex":2},{"question":"Periyodik tabloda aynı grupta yer alan elementlerin benzer özellik sergilemesinin nedeni nedir?","options":["Atom kütlelerinin aynı olması","Son yörüngelerindeki elektron sayılarının aynı olması","Aynı periyotta yer almaları","Aynı fiziksel halde bulunmaları"],"correctIndex":1},{"question":"Soygaz olarak bilinen 18. grubun temel özelliği nedir?","options":["Çok reaktif olmak","Suyla şiddetle tepkimeye girmek","Son derece kararlı olup kimyasal tepkimelere girmemek","Metal özelliği göstermek"],"correctIndex":2},{"question":"Silisyum hangi element grubuna girer ve neden önemlidir?","options":["Alkali metal; tarımda kullanılır","Metaloit; elektronik sanayisinde kritik öneme sahiptir","Halojen; tıpta antiseptik olarak kullanılır","Soygaz; ışık yayan tüplerde kullanılır"],"correctIndex":1}]'::jsonb),
  ('fen', 'Elektrik ve Manyetizma', $$Elektrik ve manyetizma, modern fiziğin birbirine sıkı sıkıya bağlı iki temel dalıdır. James Clerk Maxwell, 19. yüzyılda bu iki alanı birleştirerek elektromanyetizma teorisini oluşturdu.

Elektrik yükü, maddenin temel özelliklerinden biridir. Pozitif ve negatif olmak üzere iki tür yük bulunur; zıt yükler birbirini çeker, aynı yükler iter. Elektronların madde üzerinden hareketi elektrik akımını oluşturur. Ohm Yasası'na göre V = I × R formülü gerilim, akım ve direnci ilişkilendirir.

Manyetizma ise hareket eden yüklerin ya da mıknatısların çevresinde oluşan bir alan etkisidir. Her mıknatısın kuzey ve güney kutbu vardır. Zıt kutuplar birbirini çeker, aynı kutuplar iter. Elektrik akımı geçen bir tel çevresinde de manyetik alan oluşur; bu ilişki elektromotoru ve jeneratörü mümkün kılar.

LGS fen sorularında devre şemaları, Ohm Yasası hesaplamaları ve manyetik alan kavramları sıkça yer almaktadır.$$, 166, 6, '{lgs,tyt}', '[{"question":"Elektrik ve manyetizmayı tek bir teoride birleştiren bilim insanı kimdir?","options":["Michael Faraday","Nikola Tesla","James Clerk Maxwell","Thomas Edison"],"correctIndex":2},{"question":"Ohm Yasası hangi ilişkiyi tanımlar?","options":["Enerji ile kütle arasındaki ilişkiyi","Manyetik alan ile elektrik yükü arasındaki ilişkiyi","Gerilim, akım ve direnç arasındaki ilişkiyi","Güç ile zaman arasındaki ilişkiyi"],"correctIndex":2},{"question":"Mıknatıslarda zıt kutuplar ne yapar?","options":["Birbirini iter","Birbirini çeker","Birbirini nötrler","Hareket etmez"],"correctIndex":1},{"question":"Elektrik akımı geçen bir tel etrafında ne oluşur?","options":["Isı alanı","Manyetik alan","Gravitasyon alanı","Elektrik yükü birikimi"],"correctIndex":1}]'::jsonb),
  ('fen', 'Dalga Hareketi ve Ses', $$Dalga, enerjiyi bir noktadan diğerine madde taşımadan ileten titreşimli bir harekettir. Dalgalar iki temel türe ayrılır: mekanik dalgalar ve elektromanyetik dalgalar.

Mekanik dalgalar yayılmak için bir ortama ihtiyaç duyar. Ses dalgası en önemli mekanik dalga türüdür. Ses, havada yaklaşık 340 m/s hızla yayılır. Susuz bir ortamda ses yayılamaz; bu yüzden uzayda ses duyulmaz.

Sesin frekansı insan kulağının duyabileceği aralıkta (20 Hz - 20.000 Hz) ise işitilebilir ses, bu aralığın üstündeyse ultrason, altındaysa infrason olarak adlandırılır.

Elektromanyetik dalgalar ise boşlukta yayılabilir. Işık, radyo dalgaları ve X-ışınları elektromanyetik dalga türleridir. Işığın boşluktaki hızı yaklaşık 3×10⁸ m/s'dir. Dalga boyu, frekans ve hız arasındaki ilişki v = f × λ formülüyle ifade edilir.$$, 162, 6, '{lgs,tyt}', '[{"question":"Sesin uzayda duyulmamasının nedeni nedir?","options":["Uzaydaki sıcaklık çok düşük olduğu için","Ses yayılmak için ortam gerektirdiğinden ve uzayda boşluk olduğu için","Uzaydaki ışık sesi engellediği için","Uzayda ses kaynağı bulunmadığı için"],"correctIndex":1},{"question":"İnsan kulağının duyabildiği frekans aralığı nedir?","options":["0 Hz - 100 Hz","10 Hz - 10.000 Hz","20 Hz - 20.000 Hz","100 Hz - 100.000 Hz"],"correctIndex":2},{"question":"v = f × λ formülünde λ neyi temsil eder?","options":["Frekansı","Hızı","Dalga boyunu","Genliği"],"correctIndex":2},{"question":"Elektromanyetik dalgaların mekanik dalgalardan temel farkı nedir?","options":["Daha yavaş yayılmaları","Yalnızca sıvılarda yayılabilmeleri","Yayılmak için ortama ihtiyaç duymamaları","Enerji taşımamaları"],"correctIndex":2}]'::jsonb),
  ('fen', 'Asitler ve Bazlar: pH Skalası', $$Asitler ve bazlar, günlük hayatımızda sıkça karşılaştığımız kimyasal maddelerdir. Asitler, suya proton (H+) veren maddelerdir. Ekşi tat, turnusol kağıdını kırmızıya dönüştürme ve metalleri çözme özellikleri asitlerin temel nitelikleridir. Limon suyu, sirke ve mide asidi doğal asit örnekleridir.

Bazlar ise proton alan ya da hidroksil iyonu (OH-) serbest bırakan maddelerdir. Acı tat, kayganlık hissi ve turnusol kağıdını maviye dönüştürme bazların ayırt edici özelliklerindendir. Sabun, amonyak ve çamaşır sodası günlük hayatta kullanılan baz örnekleridir.

pH skalası, bir çözeltinin asitlik ya da bazlık derecesini 0'dan 14'e kadar ifade eder. pH 7 nötr kabul edilir. pH 7'nin altındaki değerler asitliği, üzerindekiler ise bazlığı gösterir.

Asit-baz tepkimelerinde her iki madde birbirini nötrler ve tuz ile su oluşur; bu tepkimeye nötralleşme denir.$$, 163, 6, '{lgs,tyt}', '[{"question":"pH skalasında 7''nin altındaki değerler neyi gösterir?","options":["Bazlığı","Nötrlüğü","Asitliği","Tuz konsantrasyonunu"],"correctIndex":2},{"question":"Aşağıdakilerden hangisi günlük hayatta kullanılan bir baz örneğidir?","options":["Limon suyu","Sirke","Mide asidi","Sabun"],"correctIndex":3},{"question":"Nötralleşme tepkimesinin ürünleri nelerdir?","options":["Asit ve baz","Tuz ve su","Oksijen ve hidrojen","Metal ve ametal"],"correctIndex":1},{"question":"Turnusol kağıdı asit ortamında hangi rengi alır?","options":["Mavi","Sarı","Yeşil","Kırmızı"],"correctIndex":3}]'::jsonb),
  ('fen', 'Evrim Teorisi: Darwin ve Doğal Seçilim', $$Evrim teorisi, canlı türlerinin zaman içinde değişim geçirerek birbirinden nasıl türediğini açıklayan bilimsel bir çerçevedir. Charles Darwin, 1859 yılında yayımladığı "Türlerin Kökeni" adlı kitabında doğal seçilim mekanizmasını ortaya koydu.

Doğal seçilim, belirli özelliklere sahip bireylerin kendi çevrelerine daha iyi uyum sağlayarak hayatta kalıp üremesi ve bu özellikleri sonraki nesillere aktarmasıdır. Böylece popülasyon zaman içinde değişir.

Darwin'in teorisine kanıt sağlayan birkaç önemli gözlem vardır: Galapagos adalarındaki ispinozların farklı gaga yapıları, fosil kayıtları ve anatomik yapılar arasındaki homoloji bunlara örnektir.

Kalıtım mekanizması Darwin döneminde tam olarak bilinmiyordu; ancak Mendel'in genetik yasaları ve sonraki dönemde DNA'nın keşfi evrim teorisini güçlendirdi. Günümüzde modern sentez, doğal seçilim ile genetik değişimi bir araya getirmektedir.$$, 164, 7, '{lgs,tyt}', '[{"question":"Charles Darwin evrim teorisini hangi kitapta yayımladı?","options":["Doğanın Tarihi","Canlıların Sınıflandırılması","Türlerin Kökeni","Kalıtım Yasaları"],"correctIndex":2},{"question":"Doğal seçilim kavramı ne anlama gelir?","options":["İnsanın doğayı kendi çıkarları için seçmesi","Çevreye daha iyi uyum sağlayan bireylerin hayatta kalarak genlerini aktarması","Canlıların bilerek evrimleşmesi","Güçlü canlıların zayıfları yemesi"],"correctIndex":1},{"question":"Darwin''in evrim teorisine kanıt sağlayan gözlemler arasında hangisi yer alır?","options":["Güneşin kimyasal bileşimi","Galapagos ispinozlarının farklı gaga yapıları","Yerkürenin manyetik alanı","Okyanus akıntıları"],"correctIndex":1},{"question":"Modern sentez hangi iki alanı bir araya getirir?","options":["Kimya ve fizik","Coğrafya ve jeoloji","Doğal seçilim ve genetik değişim","Anatomi ve fizyoloji"],"correctIndex":2}]'::jsonb),
  ('fen', 'Ekosistem ve Besin Zincirleri', $$Ekosistem, canlı (biyotik) ve cansız (abiyotik) ögelerin karşılıklı etkileşim içinde bulunduğu ekolojik bir birimdir. Canlı ögeler arasında bitkiler, hayvanlar ve mikroorganizmalar yer alırken cansız ögeler arasında su, toprak, ışık ve sıcaklık sayılabilir.

Besin zinciri, bir ekosistemde enerji ve besin maddelerinin üreticilerden tüketicilere doğru aktarıldığı sıralı ilişkidir. Üreticiler (otroflar), fotosentez aracılığıyla güneş enerjisini kimyasal enerjiye dönüştüren bitki ve alglerdir. Birinci derece tüketiciler (otçullar) bitkileri yer; ikinci derece tüketiciler ise otçulları yer.

Ayrıştırıcılar, ölü organik maddeleri parçalayarak besin maddelerini toprağa geri döndürür. Bu döngü ekosistem dengesini korur.

İnsan kaynaklı kirlilik, habitat yıkımı ve iklim değişikliği biyoçeşitlilik dengesini tehdit etmektedir. LGS fen sorularında besin zinciri şemaları ve enerji aktarımı sıkça test edilmektedir.$$, 166, 5, '{lgs,tyt}', '[{"question":"Besin zincirinde üreticiler kimlerdir?","options":["Otçullar ve etçiller","Ayrıştırıcılar","Fotosentez yapan bitkiler ve algler","İkinci derece tüketiciler"],"correctIndex":2},{"question":"Ayrıştırıcıların ekosistem içindeki görevi nedir?","options":["Fotosentez yapmak","Otçulları avlamak","Ölü organik maddeleri parçalayarak besin maddelerini toprağa geri döndürmek","Güneş enerjisini depolamak"],"correctIndex":2},{"question":"Ekosistemde abiyotik ögeler arasında ne yer alır?","options":["Bitkiler ve hayvanlar","Bakteriler ve mantarlar","Su, toprak, ışık ve sıcaklık","Üreticiler ve tüketiciler"],"correctIndex":2},{"question":"Biyoçeşitlilik dengesini tehdit eden etkenler arasında hangisi sayılabilir?","options":["Fotosentezin artması","Ayrıştırıcı sayısının artması","İnsan kaynaklı kirlilik, habitat yıkımı ve iklim değişikliği","Besin zincirinin uzaması"],"correctIndex":2}]'::jsonb),
  ('cografya', 'İklim ve Bitki Örtüsü', $$İklim, bir bölgenin uzun yıllar boyunca gözlemlenen hava koşullarının ortalamasıdır. Türkiye'nin coğrafi konumu ve yüzey şekilleri nedeniyle ülke içinde birden fazla iklim tipi yaşanmaktadır. Karadeniz kıyılarında ılıman ve yağışlı bir iklim hüküm sürerken, iç bölgelerde karasal iklim egemendir.

Bitki örtüsü ile iklim arasında çok sıkı bir ilişki vardır. Yağış miktarı arttıkça ormanlık alanlar genişler; kurak bölgelerde ise bozkır (step) hakimiyeti görülür. Akdeniz ikliminin etkisi altındaki bölgelerde maki adı verilen sert yapraklı bitkiler yetişir.

Türkiye'nin %27'si ormanlarla kaplıdır. Karadeniz'in nemli havasıyla beslenen Doğu Karadeniz bölgesi, ülkedeki en yüksek yağış miktarına ulaşır: yılda 2.000 milimetreden fazla. Bu nedenle söz konusu bölgede çay, fındık ve mısır tarımı başarıyla yapılır. Güneydoğu Anadolu'da ise yağışların azalmasıyla birlikte tarımda sulama kaçınılmaz hale gelir.$$, 210, 5, '{lgs,tyt}', '[{"question":"Türkiye''nin hangi bölgesi en yüksek yağış miktarına sahiptir?","options":["Güneydoğu Anadolu","İç Anadolu","Doğu Karadeniz","Ege kıyıları"],"correctIndex":2},{"question":"Maki bitkisi hangi iklim bölgesinde yetişir?","options":["Karasal iklim","Akdeniz iklimi","Karadeniz iklimi","Tundra iklimi"],"correctIndex":1},{"question":"İklim ne anlama gelir?","options":["Günlük hava durumu","Uzun yıllar ortalama hava koşulları","Mevsimsel yağış miktarı","Rüzgar yönü"],"correctIndex":1},{"question":"Türkiye''nin yüzeyinin yaklaşık kaçta biri ormanlarla kaplıdır?","options":["%10","%18","%27","%45"],"correctIndex":2}]'::jsonb),
  ('edebiyat', 'Tanzimat Edebiyatının Doğuşu', $$Tanzimat, 1839 yılında ilan edilen bir reform fermanıdır. Bu tarihten itibaren Osmanlı toplumunda köklü değişimler yaşandı; edebiyat da bu dönüşümden nasibini aldı. Batı edebiyatıyla kurulan temas, yeni türlerin Türk edebiyatına girmesini sağladı: roman, hikâye, tiyatro ve gazete.

İlk Türk romanı olarak kabul edilen "Taaşşuk-ı Talat ve Fitnat", Şemseddin Sami tarafından 1872'de kaleme alındı. Ardından Namık Kemal'in "İntibah"ı ve Recaizade Mahmut Ekrem'in eserleri, romanın Türk okuyucusuna yerleşmesini hızlandırdı.

Tanzimat edebiyatı iki dönemde incelenir. Birinci dönemde toplum için sanat anlayışı benimsendi; vatan, özgürlük ve hak temaları öne çıktı. İkinci dönemde ise sanat için sanat görüşü ağır bastı; bireysel duygular ve dil güzelliği ön plana geçti. Bu iki dönem arasındaki fark, yalnızca estetik değil aynı zamanda ideolojik bir ayrışmanın yansımasıdır.$$, 195, 5, '{lgs,tyt,ayt}', '[{"question":"Tanzimat fermanı hangi yılda ilan edilmiştir?","options":["1826","1839","1856","1876"],"correctIndex":1},{"question":"İlk Türk romanı olarak kabul edilen eser hangisidir?","options":["İntibah","Araba Sevdası","Taaşşuk-ı Talat ve Fitnat","Zehra"],"correctIndex":2},{"question":"Tanzimat''ın birinci döneminde benimsenen sanat anlayışı nedir?","options":["Sanat için sanat","Toplum için sanat","Bireysel duygular","Saf şiir"],"correctIndex":1},{"question":"\"Taaşşuk-ı Talat ve Fitnat\"ı kim yazmıştır?","options":["Namık Kemal","Recaizade Ekrem","Şemseddin Sami","Ahmet Mithat"],"correctIndex":2}]'::jsonb),
  ('sosyal', 'Sanayi Devrimi ve Toplumsal Dönüşüm', $$18. yüzyılın sonlarında İngiltere'de başlayan Sanayi Devrimi, insanlık tarihinin en köklü dönüşümlerinden birini temsil eder. Buhar makinesinin bulunması ve fabrika üretim sisteminin yaygınlaşmasıyla birlikte ekonomik ve sosyal yapılar hızla değişti.

Köylerden şehirlere göç hızlandı; fabrikalar etrafında büyük kentler oluştu. İşçi sınıfı tarihte ilk kez ekonomik ve siyasi bir güç olarak sahneye çıktı. Kadın ve çocuk emeğinin sömürülmesi, ağır çalışma koşulları toplumsal huzursuzluklara zemin hazırladı.

Bu dönemde sendikal hareketler güç kazandı; işçi hakları için verilen mücadeleler bugünkü iş hukuku sisteminin temellerini attı. Eğitime erişimin genişlemesiyle okuryazarlık oranı yükseldi. Buharlı lokomotifler sayesinde ulaşım kolaylaştı, ticaret hızlandı ve küresel piyasalar şekillenmeye başladı.$$, 200, 5, '{lgs,tyt}', '[{"question":"Sanayi Devrimi nerede başlamıştır?","options":["Fransa","Almanya","İngiltere","ABD"],"correctIndex":2},{"question":"Sanayi Devrimi''nin temel tetikleyicisi nedir?","options":["Elektriğin keşfi","Buhar makinesinin bulunması","Matbaanın icadı","Deniz ticaretinin artması"],"correctIndex":1},{"question":"Sanayi Devrimi sonucunda toplumda ortaya çıkan yeni sınıf hangisidir?","options":["Feodal beyler","Rahipler","İşçi sınıfı","Tüccarlar"],"correctIndex":2},{"question":"Sendikal hareketlerin güçlenmesi hangi alana katkı sağlamıştır?","options":["Tarım hukuku","İş hukuku","Uluslararası ticaret","Dini özgürlükler"],"correctIndex":1}]'::jsonb),
  ('fen', 'Fotosentez: Yaşamın Enerjisi', $$Fotosentez, yeşil bitkilerin güneş ışığını kullanarak karbondioksit ve suyu glikoza dönüştürdüğü biyokimyasal bir süreçtir. Bu tepkime kloroplastlarda, özellikle klorofil pigmenti aracılığıyla gerçekleşir.

Fotosentezin genel denklemi şu şekilde özetlenir: 6 CO₂ + 6 H₂O + ışık enerjisi → C₆H₁₂O₆ + 6 O₂. Yani bitkiler karbondioksitten organik madde (şeker) üretirken oksijen gazı açığa çıkar. Bu oksijen, atmosferdeki oksijen dengesinin korunmasında kritik bir rol oynar.

Fotosentez iki aşamada gerçekleşir: ışığa bağımlı tepkimeler ve Calvin döngüsü. Işığa bağımlı tepkimelerde güneş enerjisi kimyasal enerjiye (ATP ve NADPH) dönüştürülür. Calvin döngüsünde ise bu enerji, karbondioksitten glikoz sentezlemek için kullanılır.

İklim değişikliği bağlamında fotosentez büyük önem taşır. Ormanlar, her yıl milyonlarca ton karbondioksiti bağlayarak küresel ısınmayı yavaşlatır.$$, 190, 5, '{lgs,tyt}', '[{"question":"Fotosentez bitkide nerede gerçekleşir?","options":["Mitokondri","Ribozom","Kloroplast","Çekirdek"],"correctIndex":2},{"question":"Fotosentez sonucunda hangi gaz açığa çıkar?","options":["Karbondioksit","Azot","Oksijen","Hidrojen"],"correctIndex":2},{"question":"Fotosentezde ışık enerjisi hangi kimyasal bileşiklere dönüşür?","options":["ADP ve NADP","ATP ve NADPH","Glikoz ve su","CO₂ ve O₂"],"correctIndex":1},{"question":"Calvin döngüsünde ne üretilir?","options":["Oksijen","ATP","Glikoz","Su"],"correctIndex":2}]'::jsonb),
  ('saglik', 'Bağışıklık Sistemi ve Savunma Mekanizmaları', $$Bağışıklık sistemi, vücudu hastalık yapıcı mikroorganizmalara karşı koruyan karmaşık bir savunma ağıdır. İki temel koldan oluşur: doğal bağışıklık ve edinsel bağışıklık.

Doğal bağışıklık, deri, mukoza ve fagositler gibi yapılardan oluşur. Bu mekanizmalar, tehditlere hızla yanıt verir ancak özgün değildir. Bir yabancı madde (antijen) vücuda girdiğinde nötrofiller ve makrofajlar devreye girerek onu yok etmeye çalışır.

Edinsel bağışıklık ise daha özgün ve kalıcıdır. B lenfositler, antijene özgü antikorlar üretir. T lenfositler ise enfekte hücreleri doğrudan ortadan kaldırır. Bu süreçte oluşan hafıza hücreleri, aynı antijene karşı ileri tarihte daha hızlı ve güçlü bir yanıt verilmesini sağlar. Aşılar tam olarak bu hafıza mekanizmasından yararlanır.

Bağışıklık sistemi düzenli egzersiz, yeterli uyku, dengeli beslenme ve düşük stres düzeyiyle desteklenebilir. Sigara ve aşırı alkol ise bağışıklık yanıtını zayıflatır.$$, 205, 5, '{lgs,tyt}', '[{"question":"Bağışıklık sisteminin kaç temel kolu vardır?","options":["1","2","3","4"],"correctIndex":1},{"question":"Antijene özgü antikorları hangi hücreler üretir?","options":["T lenfositler","Makrofajlar","B lenfositler","Nötrofiller"],"correctIndex":2},{"question":"Aşılar hangi mekanizmayı kullanır?","options":["Doğal bağışıklık","Fagositoz","Hafıza hücreleri","Mukoza engeli"],"correctIndex":2},{"question":"Bağışıklığı zayıflatan faktörler arasında ne yer alır?","options":["Düzenli egzersiz","Yeterli uyku","Sigara","Dengeli beslenme"],"correctIndex":2}]'::jsonb);

